/// Snapshot of every Model resource and its clip names. Built
/// before the mutable borrow on a Resource so the Character Profile
/// inspector can populate model + clip dropdowns without
/// fighting the live `&mut CharacterResource`.
struct CharacterEditorContext {
    /// `(model id, model display name, clip names in order)`.
    models: Vec<(ResourceId, String, Vec<String>)>,
    /// `(model id, skeleton id)`.
    model_skeletons: Vec<(ResourceId, Option<ResourceId>)>,
    animation_sets: Vec<AnimationSetOption>,
    animation_clips: Vec<(ResourceId, String)>,
}

fn build_character_editor_context(project: &ProjectDocument) -> CharacterEditorContext {
    CharacterEditorContext {
        models: collect_model_options(project),
        model_skeletons: project
            .resources
            .iter()
            .filter_map(|resource| match &resource.data {
                ResourceData::Model(model) => Some((resource.id, model.skeleton)),
                _ => None,
            })
            .collect(),
        animation_sets: collect_animation_set_options(project),
        animation_clips: project
            .resources
            .iter()
            .filter_map(|resource| match &resource.data {
                ResourceData::AnimationClip(_) => Some((resource.id, resource.name.clone())),
                _ => None,
            })
            .collect(),
    }
}

impl CharacterEditorContext {
    fn model_skeleton(&self, model: Option<ResourceId>) -> Option<ResourceId> {
        let model = model?;
        self.model_skeletons
            .iter()
            .find_map(|(id, skeleton)| (*id == model).then_some(*skeleton))
            .flatten()
    }

    fn animation_set(&self, set: Option<ResourceId>) -> Option<&AnimationSetOption> {
        let set = set?;
        self.animation_sets.iter().find(|option| option.id == set)
    }

    fn animation_clip_name(&self, clip: ResourceId) -> &str {
        self.animation_clips
            .iter()
            .find_map(|(id, name)| (*id == clip).then_some(name.as_str()))
            .unwrap_or("(missing)")
    }
}

#[derive(Clone, Debug)]
struct AnimationSetOption {
    id: ResourceId,
    name: String,
    skeleton: Option<ResourceId>,
    action_clips: [Option<ResourceId>; psxed_project::CHARACTER_ANIMATION_ACTION_COUNT],
}

/// Inspector body for `ResourceData::Character` profiles. Combines a
/// model picker, role-clip pickers, capsule sizes, controller speed,
/// and camera params.
/// `Auto Assign Clips By Name` walks the bound model's clip
/// list and matches gameplay role substrings
/// -- case-insensitive -- into role slots.
fn draw_character_resource_editor(
    ui: &mut egui::Ui,
    character: &mut psxed_project::CharacterResource,
    ctx: &CharacterEditorContext,
) -> bool {
    let mut changed = false;

    // Resolve the bound model + clip list (if any). Used
    // throughout the inspector to surface clip names instead of
    // raw indices.
    let bound = character
        .model
        .and_then(|id| ctx.models.iter().find(|(mid, _, _)| *mid == id));
    let bound_skeleton = ctx.model_skeleton(character.model);
    let selected_set = ctx.animation_set(character.animation_set);

    egui::CollapsingHeader::new(icons::label(icons::BOX, "Model"))
        .default_open(true)
        .show(ui, |ui| {
            ui.horizontal(|ui| {
                ui.label("Model");
                let preview = bound.map(|(_, name, _)| name.as_str()).unwrap_or("(none)");
                egui::ComboBox::from_id_salt("character-model-picker")
                    .selected_text(preview)
                    .show_ui(ui, |ui| {
                        if ui
                            .selectable_label(character.model.is_none(), "(none)")
                            .clicked()
                        {
                            character.model = None;
                            changed = true;
                        }
                        for (id, name, _) in &ctx.models {
                            if ui
                                .selectable_label(character.model == Some(*id), name)
                                .clicked()
                            {
                                character.model = Some(*id);
                                changed = true;
                            }
                        }
                    });
            });
            if character.model.is_some() && bound.is_none() {
                ui.colored_label(
                    Color32::from_rgb(220, 120, 100),
                    "Bound model resource is missing.",
                );
            }
            changed |= resource_id_picker(
                ui,
                "Action Map",
                "character-animation-set-picker",
                &mut character.animation_set,
                &ctx.animation_sets
                    .iter()
                    .filter(|set| {
                        bound_skeleton.is_none()
                            || set.skeleton.is_none()
                            || set.skeleton == bound_skeleton
                    })
                    .map(|set| (set.id, set.name.clone()))
                    .collect::<Vec<_>>(),
            );
            if character.animation_set.is_some() && selected_set.is_none() {
                ui.colored_label(
                    Color32::from_rgb(220, 120, 100),
                    "Action Map resource is missing.",
                );
            }
            if let Some(set) = selected_set {
                if bound_skeleton.is_some()
                    && set.skeleton.is_some()
                    && set.skeleton != bound_skeleton
                {
                    ui.colored_label(
                        Color32::from_rgb(220, 120, 100),
                        "Action Map targets a different skeleton than the selected Model.",
                    );
                }
            }
        });

    egui::CollapsingHeader::new(icons::label(icons::PALETTE, "Animation Actions"))
        .default_open(true)
        .show(ui, |ui| {
            let clips: &[String] = bound.map(|(_, _, c)| c.as_slice()).unwrap_or(&[]);
            if character.animation_set.is_some() {
                ui.label(
                    RichText::new(
                        "Preset clips below are fallback defaults. Animator components can override action clips per entity.",
                    )
                    .color(STUDIO_TEXT_WEAK)
                    .small(),
                );
            }
            if bound.is_none() {
                ui.colored_label(
                    STUDIO_TEXT_WEAK,
                    "Pick a Model to surface its clip list.",
                );
            }
            for action in psxed_project::CharacterAnimationAction::ALL {
                let mut current = character.action_clip(action);
                changed |= clip_role_picker(
                    ui,
                    action.label(),
                    &format!("character-action-clip-{}", action.to_index()),
                    &mut current,
                    clips,
                );
                if current != character.action_clip(action) {
                    character.set_action_clip(action, current);
                    changed = true;
                }
            }

            draw_character_effective_roles(ui, character, selected_set, clips, ctx);

            ui.add_space(4.0);
            ui.horizontal(|ui| {
                let auto_enabled = !clips.is_empty();
                if ui
                    .add_enabled(
                        auto_enabled,
                        egui::Button::new(icons::label(icons::SCAN, "Auto Assign Clips By Name")),
                    )
                    .on_hover_text(
                        "Match clip names against gameplay action names (case-insensitive).",
                    )
                    .clicked()
                {
                    let before = character.action_clips.clone();
                    auto_assign_character_clips(character, clips);
                    if character.action_clips != before {
                        changed = true;
                    }
                }
            });

            // Inline warnings: required roles missing, or slot
            // points past end of the model's clip list.
            let warn_idx = |label: &str, slot: Option<u16>| -> Option<String> {
                let idx = slot?;
                if (idx as usize) >= clips.len() {
                    Some(format!(
                        "{label} clip index {idx} exceeds model's clip list ({} clips).",
                        clips.len()
                    ))
                } else {
                    None
                }
            };
            for action in psxed_project::CharacterAnimationAction::ALL {
                if let Some(warning) = warn_idx(action.label(), character.action_clip(action)) {
                    ui.colored_label(Color32::from_rgb(220, 160, 80), warning);
                }
            }
            let has_set_idle = selected_set
                .and_then(|set| set.action_clips[psxed_project::CharacterAnimationAction::Idle.to_index()])
                .is_some();
            let has_set_walk = selected_set
                .and_then(|set| set.action_clips[psxed_project::CharacterAnimationAction::Walk.to_index()])
                .is_some();
            if character.model.is_some()
                && character
                    .action_clip(psxed_project::CharacterAnimationAction::Idle)
                    .is_none()
                && !has_set_idle
            {
                ui.colored_label(
                    Color32::from_rgb(220, 120, 100),
                    "Idle clip is required for the player character.",
                );
            }
            if character.model.is_some()
                && character
                    .action_clip(psxed_project::CharacterAnimationAction::Walk)
                    .is_none()
                && !has_set_walk
            {
                ui.colored_label(
                    Color32::from_rgb(220, 120, 100),
                    "Walk clip is required for the player character.",
                );
            }
        });

    egui::CollapsingHeader::new(icons::label(icons::GRID, "Camera"))
        .default_open(false)
        .show(ui, |ui| {
            changed |= drag_i32(ui, "Distance", &mut character.camera_distance, 1, 16384);
            changed |= drag_i32(ui, "Height", &mut character.camera_height, 0, 16384);
            changed |= drag_i32(
                ui,
                "Target height",
                &mut character.camera_target_height,
                0,
                16384,
            );
        });

    changed
}

