#[derive(Debug, Clone, PartialEq, Eq)]
struct WeaponAttachmentSummary {
    hitbox_count: usize,
    active_window_label: String,
    max_reach: i32,
    warnings: Vec<String>,
}

fn weapon_attachment_summary(
    weapon: &psxed_project::WeaponResource,
    known_socket_names: &[String],
) -> WeaponAttachmentSummary {
    let mut warnings = Vec::new();
    let socket_name = weapon.default_character_socket.trim();
    if socket_name.is_empty() {
        warnings.push("Default character socket is empty.".to_string());
    } else if !known_socket_names.is_empty()
        && !known_socket_names.iter().any(|name| name == socket_name)
    {
        warnings.push(format!(
            "No current model resource defines socket \"{socket_name}\"."
        ));
    }
    if weapon.grip.name.trim().is_empty() {
        warnings.push("Weapon grip name is empty.".to_string());
    }
    if weapon.model.is_none() {
        warnings.push("Weapon has no visual model assigned.".to_string());
    }
    if weapon.hitboxes.is_empty() {
        warnings.push("Weapon has no hitboxes.".to_string());
    }

    let active_start = weapon
        .hitboxes
        .iter()
        .map(|hitbox| hitbox.active_start_frame)
        .min();
    let active_end = weapon
        .hitboxes
        .iter()
        .map(|hitbox| hitbox.active_end_frame)
        .max();
    let active_window_label = match (active_start, active_end) {
        (Some(start), Some(end)) => format!("{start}..{end}"),
        _ => "none".to_string(),
    };
    let max_reach = weapon
        .hitboxes
        .iter()
        .map(|hitbox| weapon_hitbox_max_reach(&hitbox.shape))
        .max()
        .unwrap_or(0);

    WeaponAttachmentSummary {
        hitbox_count: weapon.hitboxes.len(),
        active_window_label,
        max_reach,
        warnings,
    }
}

fn weapon_hitbox_max_reach(shape: &psxed_project::WeaponHitShape) -> i32 {
    match shape {
        psxed_project::WeaponHitShape::Box {
            center,
            half_extents,
        } => center
            .iter()
            .zip(half_extents.iter())
            .map(|(c, h)| c.abs().saturating_add(*h as i32))
            .max()
            .unwrap_or(0),
        psxed_project::WeaponHitShape::Capsule { start, end, radius } => start
            .iter()
            .chain(end.iter())
            .map(|v| v.abs().saturating_add(*radius as i32))
            .max()
            .unwrap_or(0),
    }
}

fn model_resource_picker(
    ui: &mut egui::Ui,
    label: &str,
    current: &mut Option<ResourceId>,
    options: &[(ResourceId, String, Vec<String>)],
) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(label);
        let preview = current
            .and_then(|id| {
                options
                    .iter()
                    .find(|(rid, _, _)| *rid == id)
                    .map(|(_, name, _)| name.as_str())
            })
            .unwrap_or("(none)");
        egui::ComboBox::from_id_salt(label)
            .selected_text(preview)
            .show_ui(ui, |ui| {
                if ui.selectable_label(current.is_none(), "(none)").clicked() {
                    *current = None;
                    changed = true;
                }
                for (id, name, _) in options {
                    if ui.selectable_label(*current == Some(*id), name).clicked() {
                        *current = Some(*id);
                        changed = true;
                    }
                }
            });
    });
    if let Some(id) = *current {
        if !options.iter().any(|(rid, _, _)| *rid == id) {
            ui.colored_label(
                Color32::from_rgb(220, 120, 100),
                "Model resource is missing.",
            );
        }
    }
    changed
}

fn weapon_hitbox_list_editor(
    ui: &mut egui::Ui,
    hitboxes: &mut Vec<psxed_project::WeaponHitbox>,
) -> bool {
    let mut changed = false;
    let mut remove: Option<usize> = None;
    for (index, hitbox) in hitboxes.iter_mut().enumerate() {
        egui::Frame::group(ui.style()).show(ui, |ui| {
            ui.horizontal(|ui| {
                ui.label(RichText::new(format!("#{index}")).color(STUDIO_TEXT_WEAK));
                changed |= ui.text_edit_singleline(&mut hitbox.name).changed();
                if ui
                    .small_button(icons::label(icons::TRASH, ""))
                    .on_hover_text("Remove hitbox")
                    .clicked()
                {
                    remove = Some(index);
                }
            });
            changed |= drag_u16(
                ui,
                "Start frame",
                &mut hitbox.active_start_frame,
                0,
                u16::MAX,
            );
            changed |= drag_u16(ui, "End frame", &mut hitbox.active_end_frame, 0, u16::MAX);
            if hitbox.active_end_frame < hitbox.active_start_frame {
                hitbox.active_end_frame = hitbox.active_start_frame;
                changed = true;
            }
            changed |= weapon_hit_shape_editor(ui, &mut hitbox.shape);
        });
        ui.add_space(4.0);
    }
    if let Some(index) = remove {
        hitboxes.remove(index);
        changed = true;
    }
    if ui.button(icons::label(icons::PLUS, "Hitbox")).clicked() {
        hitboxes.push(psxed_project::WeaponHitbox::default());
        changed = true;
    }
    changed
}

fn weapon_hit_shape_editor(ui: &mut egui::Ui, shape: &mut psxed_project::WeaponHitShape) -> bool {
    let mut changed = false;
    let mut shape_kind = match shape {
        psxed_project::WeaponHitShape::Box { .. } => 0,
        psxed_project::WeaponHitShape::Capsule { .. } => 1,
    };
    ui.horizontal(|ui| {
        ui.label("Shape");
        egui::ComboBox::from_id_salt(ui.id().with("weapon-hit-shape"))
            .selected_text(if shape_kind == 0 { "Box" } else { "Capsule" })
            .show_ui(ui, |ui| {
                if ui.selectable_label(shape_kind == 0, "Box").clicked() {
                    shape_kind = 0;
                }
                if ui.selectable_label(shape_kind == 1, "Capsule").clicked() {
                    shape_kind = 1;
                }
            });
    });
    match (shape_kind, &mut *shape) {
        (0, psxed_project::WeaponHitShape::Capsule { .. }) => {
            *shape = psxed_project::WeaponHitShape::Box {
                center: [0, 256, 0],
                half_extents: [64, 256, 64],
            };
            changed = true;
        }
        (1, psxed_project::WeaponHitShape::Box { .. }) => {
            *shape = psxed_project::WeaponHitShape::Capsule {
                start: [0, 0, 0],
                end: [0, 512, 0],
                radius: 48,
            };
            changed = true;
        }
        _ => {}
    }

    match shape {
        psxed_project::WeaponHitShape::Box {
            center,
            half_extents,
        } => {
            changed |= int_vec3_editor(ui, "Center", center, -32768, 32767, 8.0);
            changed |= u16_vec3_editor(ui, "Half Extents", half_extents, 1, 8192);
        }
        psxed_project::WeaponHitShape::Capsule { start, end, radius } => {
            changed |= int_vec3_editor(ui, "Start", start, -32768, 32767, 8.0);
            changed |= int_vec3_editor(ui, "End", end, -32768, 32767, 8.0);
            changed |= drag_u16(ui, "Radius", radius, 1, 8192);
        }
    }
    changed
}

fn int_vec3_editor(
    ui: &mut egui::Ui,
    label: &str,
    values: &mut [i32; 3],
    min: i32,
    max: i32,
    speed: f64,
) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(label);
        for axis in 0..3 {
            let prefix = ["X ", "Y ", "Z "][axis];
            let response = ui.add(
                egui::DragValue::new(&mut values[axis])
                    .prefix(prefix)
                    .range(min..=max)
                    .speed(speed),
            );
            if response.changed() {
                values[axis] = values[axis].clamp(min, max);
                changed = true;
            }
        }
    });
    changed
}

fn u16_vec3_editor(
    ui: &mut egui::Ui,
    label: &str,
    values: &mut [u16; 3],
    min: u16,
    max: u16,
) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(label);
        for axis in 0..3 {
            let prefix = ["X ", "Y ", "Z "][axis];
            let mut value = values[axis] as i32;
            let response = ui.add(
                egui::DragValue::new(&mut value)
                    .prefix(prefix)
                    .range(min as i32..=max as i32),
            );
            if response.changed() {
                values[axis] = value.clamp(min as i32, max as i32) as u16;
                changed = true;
            }
        }
    });
    changed
}

fn q12_rotation_editor(ui: &mut egui::Ui, label: &str, values: &mut [i16; 3]) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(label);
        for axis in 0..3 {
            let prefix = ["X ", "Y ", "Z "][axis];
            let mut value = values[axis] as i32;
            let response = ui.add(
                egui::DragValue::new(&mut value)
                    .prefix(prefix)
                    .range(-4096..=4096)
                    .speed(16.0),
            );
            if response.changed() {
                values[axis] = value.clamp(i16::MIN as i32, i16::MAX as i32) as i16;
                changed = true;
            }
        }
    });
    changed
}

fn human_bytes(n: u32) -> String {
    human_bytes_u64(n as u64)
}

fn human_bytes_u64(n: u64) -> String {
    if n < 1024 {
        format!("{} B", n)
    } else if n < 1024 * 1024 {
        format!("{:.1} KB", (n as f64) / 1024.0)
    } else {
        format!("{:.1} MB", (n as f64) / (1024.0 * 1024.0))
    }
}

fn draw_play_overlay_icon_button(
    ui: &mut egui::Ui,
    rect: Rect,
    id_source: &'static str,
    icon: char,
    tooltip: &'static str,
    active: bool,
    enabled: bool,
    active_fill: Option<Color32>,
) -> bool {
    let response = ui
        .interact(
            rect,
            ui.id().with(("play_overlay_icon_button", id_source)),
            if enabled {
                Sense::click()
            } else {
                Sense::hover()
            },
        )
        .on_hover_text(tooltip);
    let hovered = response.hovered();
    let fill = if active {
        active_fill.unwrap_or(STUDIO_ACCENT_DIM)
    } else if hovered && enabled {
        Color32::from_rgba_unmultiplied(34, 48, 58, 232)
    } else if enabled {
        Color32::from_black_alpha(176)
    } else {
        Color32::from_rgba_unmultiplied(0, 0, 0, 112)
    };
    let stroke = if active {
        Stroke::new(1.0, STUDIO_ACCENT)
    } else if hovered && enabled {
        Stroke::new(1.0, Color32::from_rgba_unmultiplied(210, 220, 235, 128))
    } else {
        Stroke::new(1.0, Color32::from_rgba_unmultiplied(210, 220, 235, 84))
    };
    let icon_color = if !enabled {
        Color32::from_rgba_unmultiplied(142, 154, 168, 108)
    } else if hovered || active {
        Color32::WHITE
    } else {
        STUDIO_TEXT
    };
    let painter = ui.painter();
    painter.rect_filled(rect, 4.0, fill);
    painter.rect_stroke(rect, 4.0, stroke, StrokeKind::Inside);
    painter.text(
        rect.center(),
        Align2::CENTER_CENTER,
        icon.to_string(),
        icons::font(14.0),
        icon_color,
    );
    enabled && response.clicked()
}

#[derive(Clone, Copy)]
struct PlayChunkDebugMapCell {
    runtime_room_index: usize,
    center: [f32; 2],
    half: [f32; 2],
    room_origin: [f32; 2],
    sector_size: f32,
}

#[derive(Clone)]
struct PlayChunkDebugMapPortal {
    portal_index: usize,
    source_room_index: usize,
    destination_room_index: usize,
    a: [f32; 2],
    b: [f32; 2],
}

struct PlayChunkDebugMap {
    cells: Vec<PlayChunkDebugMapCell>,
    portals: Vec<PlayChunkDebugMapPortal>,
}

fn draw_play_chunk_debug_map(
    painter: &egui::Painter,
    viewport_rect: Rect,
    project: &ProjectDocument,
    metrics: EditorPlaytestMetrics,
) {
    let map = collect_play_chunk_debug_map(project);
    if map.cells.is_empty() {
        return;
    }

    let map_size = Vec2::new(300.0, 224.0);
    let mut map_rect = Rect::from_min_size(
        Pos2::new(
            viewport_rect.right() - map_size.x - 8.0,
            viewport_rect.top() + 44.0,
        ),
        map_size,
    );
    if map_rect.left() < viewport_rect.left() + 270.0 {
        map_rect = Rect::from_min_size(
            Pos2::new(
                viewport_rect.right() - map_size.x - 8.0,
                viewport_rect.bottom() - map_size.y - 8.0,
            ),
            map_size,
        );
    }

    let mut min_x = f32::INFINITY;
    let mut max_x = f32::NEG_INFINITY;
    let mut min_z = f32::INFINITY;
    let mut max_z = f32::NEG_INFINITY;
    for cell in &map.cells {
        min_x = min_x.min(cell.center[0] - cell.half[0]);
        max_x = max_x.max(cell.center[0] + cell.half[0]);
        min_z = min_z.min(cell.center[1] - cell.half[1]);
        max_z = max_z.max(cell.center[1] + cell.half[1]);
    }
    if !min_x.is_finite() || !min_z.is_finite() {
        return;
    }

    painter.rect_filled(map_rect, 4.0, Color32::from_black_alpha(176));
    painter.rect_stroke(
        map_rect,
        4.0,
        Stroke::new(1.0, Color32::from_rgba_unmultiplied(210, 220, 235, 68)),
        StrokeKind::Inside,
    );
    painter.text(
        map_rect.left_top() + Vec2::new(8.0, 7.0),
        Align2::LEFT_TOP,
        "Portal map",
        FontId::monospace(11.0),
        STUDIO_TEXT,
    );

    let plot = Rect::from_min_max(
        map_rect.left_top() + Vec2::new(8.0, 24.0),
        map_rect.right_bottom() - Vec2::new(8.0, 60.0),
    );
    let world_w = (max_x - min_x).max(1.0);
    let world_h = (max_z - min_z).max(1.0);
    let scale = (plot.width() / world_w).min(plot.height() / world_h);
    let content_w = world_w * scale;
    let content_h = world_h * scale;
    let origin = Pos2::new(
        plot.left() + (plot.width() - content_w) * 0.5,
        plot.top() + (plot.height() - content_h) * 0.5,
    );
    let map_x = |x: f32| origin.x + (x - min_x) * scale;
    let map_z = |z: f32| origin.y + (z - min_z) * scale;

    for cell in &map.cells {
        let bit = debug_chunk_bit(cell.runtime_room_index);
        let loaded = bit != 0 && metrics.chunk_loaded_mask & bit != 0;
        let loading = bit != 0 && metrics.chunk_loading_mask & bit != 0;
        let visible = bit != 0 && metrics.portal_visible_mask & bit != 0;
        let frontier = bit != 0 && metrics.portal_frontier_mask & bit != 0;
        let missing = bit != 0 && metrics.portal_missing_mask & bit != 0;
        let build_failed = bit != 0 && metrics.portal_build_failed_mask & bit != 0;
        let drawn = bit != 0 && metrics.chunk_drawn_mask & bit != 0;
        let rect = Rect::from_min_max(
            Pos2::new(
                map_x(cell.center[0] - cell.half[0]),
                map_z(cell.center[1] - cell.half[1]),
            ),
            Pos2::new(
                map_x(cell.center[0] + cell.half[0]),
                map_z(cell.center[1] + cell.half[1]),
            ),
        )
        .shrink(0.75);
        let fill = if drawn {
            Color32::from_rgba_unmultiplied(42, 214, 124, 156)
        } else if build_failed {
            Color32::from_rgba_unmultiplied(232, 76, 196, 112)
        } else if missing {
            Color32::from_rgba_unmultiplied(226, 54, 74, 112)
        } else if loading {
            Color32::from_rgba_unmultiplied(72, 150, 255, 96)
        } else if visible {
            Color32::from_rgba_unmultiplied(244, 170, 48, 96)
        } else if loaded {
            Color32::from_rgba_unmultiplied(132, 148, 164, 48)
        } else {
            Color32::from_rgba_unmultiplied(0, 0, 0, 0)
        };
        if fill.a() > 0 {
            painter.rect_filled(rect, 0.0, fill);
        }
        let stroke = if drawn {
            Stroke::new(1.6, Color32::from_rgb(72, 255, 152))
        } else if build_failed {
            Stroke::new(1.8, Color32::from_rgb(255, 92, 214))
        } else if missing {
            Stroke::new(1.8, Color32::from_rgb(255, 82, 104))
        } else if loading {
            Stroke::new(1.8, Color32::from_rgb(96, 178, 255))
        } else if visible {
            Stroke::new(1.7, Color32::from_rgb(255, 184, 58))
        } else if frontier {
            Stroke::new(1.6, Color32::from_rgb(172, 128, 255))
        } else if loaded {
            Stroke::new(1.2, Color32::from_rgb(154, 170, 188))
        } else {
            Stroke::new(1.0, Color32::from_rgba_unmultiplied(210, 220, 235, 120))
        };
        painter.rect_stroke(rect, 0.0, stroke, StrokeKind::Inside);
    }

    let clipped = painter.with_clip_rect(plot);
    for portal in &map.portals {
        let source_bit = debug_chunk_bit(portal.source_room_index);
        let dest_bit = debug_chunk_bit(portal.destination_room_index);
        let portal_bit = debug_chunk_bit(portal.portal_index);
        let source_visible = source_bit != 0 && metrics.portal_visible_mask & source_bit != 0;
        let dest_frontier = dest_bit != 0 && metrics.portal_frontier_mask & dest_bit != 0;
        let dest_loading = dest_bit != 0 && metrics.chunk_loading_mask & dest_bit != 0;
        let dest_build_failed = dest_bit != 0 && metrics.portal_build_failed_mask & dest_bit != 0;
        let portal_accepted =
            portal_bit != 0 && metrics.portal_accepted_portal_mask & portal_bit != 0;
        let portal_rejected =
            portal_bit != 0 && metrics.portal_reject_frustum_portal_mask & portal_bit != 0;
        let color = if source_visible && portal_accepted {
            Color32::from_rgb(255, 190, 72)
        } else if source_visible && dest_build_failed {
            Color32::from_rgb(255, 92, 214)
        } else if source_visible && dest_loading {
            Color32::from_rgb(96, 178, 255)
        } else if source_visible && portal_rejected {
            Color32::from_rgb(255, 142, 48)
        } else if source_visible && dest_frontier {
            Color32::from_rgb(172, 128, 255)
        } else {
            Color32::from_rgba_unmultiplied(210, 220, 235, 112)
        };
        let (a, b) = directed_portal_map_segment(
            Pos2::new(map_x(portal.a[0]), map_z(portal.a[1])),
            Pos2::new(map_x(portal.b[0]), map_z(portal.b[1])),
            portal.source_room_index,
            portal.destination_room_index,
        );
        clipped.line_segment([a, b], Stroke::new(2.0, color));
        if source_visible && portal_rejected && !portal_accepted {
            draw_rejected_portal_marker(&clipped, a, b);
        }
    }

    if metrics.player_map_valid {
        if let Some(cell) = map
            .cells
            .iter()
            .find(|cell| cell.runtime_room_index == metrics.player_room_index as usize)
        {
            let sector_size = cell.sector_size.max(1.0);
            let local_to_map_pos = |local_x: i32, local_z: i32| {
                let x = cell.room_origin[0] + local_x as f32 / sector_size;
                let z = cell.room_origin[1] + local_z as f32 / sector_size;
                Pos2::new(map_x(x), map_z(z))
            };
            let player_pos = local_to_map_pos(metrics.player_local_x, metrics.player_local_z);
            let camera_pos = if metrics.camera_map_valid {
                local_to_map_pos(metrics.camera_local_x, metrics.camera_local_z)
            } else {
                player_pos
            };
            if player_pos.x.is_finite()
                && player_pos.y.is_finite()
                && camera_pos.x.is_finite()
                && camera_pos.y.is_finite()
            {
                let yaw = metrics.player_view_yaw_q12 as f32 * std::f32::consts::TAU / 4096.0;
                let forward = if metrics.camera_view_basis_valid {
                    let basis = Vec2::new(
                        -(metrics.camera_view_sin_yaw_q12 as f32) / 4096.0,
                        -(metrics.camera_view_cos_yaw_q12 as f32) / 4096.0,
                    );
                    let len = basis.length();
                    if len > 0.001 {
                        basis / len
                    } else {
                        Vec2::new(-yaw.sin(), -yaw.cos())
                    }
                } else {
                    Vec2::new(-yaw.sin(), -yaw.cos())
                };
                let cone_len = (content_w * content_w + content_h * content_h)
                    .sqrt()
                    .max(42.0);
                let cone_half_angle = (160.0_f32 / 320.0_f32).atan();
                let left = rotate_vec2(forward, -cone_half_angle) * cone_len;
                let right = rotate_vec2(forward, cone_half_angle) * cone_len;
                let clipped = painter.with_clip_rect(plot);
                if metrics.camera_map_valid && player_pos.distance(camera_pos) > 2.0 {
                    clipped.line_segment(
                        [player_pos, camera_pos],
                        Stroke::new(1.0, Color32::from_rgba_unmultiplied(232, 240, 252, 160)),
                    );
                }
                clipped.add(egui::Shape::convex_polygon(
                    vec![camera_pos, camera_pos + left, camera_pos + right],
                    Color32::from_rgba_unmultiplied(235, 240, 248, 44),
                    Stroke::new(1.2, Color32::from_rgb(232, 240, 252)),
                ));
                clipped.line_segment(
                    [camera_pos, camera_pos + forward * (cone_len * 0.82)],
                    Stroke::new(1.2, Color32::from_rgb(218, 244, 255)),
                );
                clipped.circle_filled(player_pos, 2.6, Color32::from_rgb(72, 255, 152));
                clipped.circle_stroke(player_pos, 2.6, Stroke::new(1.0, Color32::BLACK));
                clipped.circle_filled(camera_pos, 3.5, Color32::from_rgb(245, 250, 255));
                clipped.circle_stroke(camera_pos, 3.5, Stroke::new(1.0, Color32::BLACK));
            }
        }
    }

    let legend_row0 = map_rect.left_bottom() + Vec2::new(8.0, -51.0);
    let legend_row1 = map_rect.left_bottom() + Vec2::new(8.0, -34.0);
    let legend_row2 = map_rect.left_bottom() + Vec2::new(8.0, -17.0);
    draw_chunk_map_legend_item(
        painter,
        legend_row0,
        Color32::from_rgba_unmultiplied(42, 214, 124, 156),
        Color32::from_rgb(72, 255, 152),
        "drawn",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row0 + Vec2::new(70.0, 0.0),
        Color32::from_rgba_unmultiplied(244, 170, 48, 96),
        Color32::from_rgb(255, 184, 58),
        "accepted",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row0 + Vec2::new(158.0, 0.0),
        Color32::from_rgba_unmultiplied(0, 0, 0, 0),
        Color32::from_rgb(172, 128, 255),
        "depth/cap",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row1,
        Color32::from_rgba_unmultiplied(132, 148, 164, 48),
        Color32::from_rgb(154, 170, 188),
        "resident",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row1 + Vec2::new(94.0, 0.0),
        Color32::from_rgba_unmultiplied(72, 150, 255, 96),
        Color32::from_rgb(96, 178, 255),
        "loading",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row1 + Vec2::new(188.0, 0.0),
        Color32::from_rgba_unmultiplied(226, 54, 74, 112),
        Color32::from_rgb(255, 82, 104),
        "not loaded",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row2,
        Color32::from_rgba_unmultiplied(232, 76, 196, 112),
        Color32::from_rgb(255, 92, 214),
        "build fail",
    );
    draw_chunk_map_legend_item(
        painter,
        legend_row2 + Vec2::new(94.0, 0.0),
        Color32::from_rgba_unmultiplied(255, 124, 36, 84),
        Color32::from_rgb(255, 142, 48),
        "rejected",
    );
    draw_rejected_map_marker(
        painter,
        Rect::from_min_size(legend_row2 + Vec2::new(94.0, 0.0), Vec2::new(9.0, 9.0)),
    );
}

fn collect_play_chunk_debug_map(project: &ProjectDocument) -> PlayChunkDebugMap {
    let scene = project.active_scene();
    let mut cells = Vec::new();
    let mut portals = Vec::new();
    let mut runtime_room_index = 0usize;
    let mut room_nodes: Vec<_> = scene
        .nodes()
        .iter()
        .filter(|node| matches!(node.kind, NodeKind::Room { .. }))
        .collect();
    room_nodes.sort_by_key(|node| node.id.raw());
    for node in room_nodes {
        let NodeKind::Room { grid } = &node.kind else {
            continue;
        };
        if grid.populated_sector_count() == 0 {
            continue;
        }
        let plan = plan_portal_rooms(scene, node.id, grid, PortalRoomConfig::default());
        let node_center = node_world(node);
        let room_base_index = runtime_room_index;
        for portal_room in &plan.rooms {
            let room_origin = [
                node_center[0] + portal_room.array_origin[0] as f32 - grid.width as f32 * 0.5,
                node_center[1] + portal_room.array_origin[1] as f32 - grid.depth as f32 * 0.5,
            ];
            for [cell_x, cell_z] in &portal_room.cells {
                let local_center = grid_cell_editor_center(grid, *cell_x, *cell_z);
                cells.push(PlayChunkDebugMapCell {
                    runtime_room_index,
                    center: [
                        node_center[0] + local_center[0],
                        node_center[1] + local_center[1],
                    ],
                    half: [0.5, 0.5],
                    room_origin,
                    sector_size: grid.sector_size.max(1) as f32,
                });
            }
            runtime_room_index += 1;
        }
        let sector_size = grid.sector_size.max(1) as f32;
        let room_portal_base = portals.len();
        for portal in plan.portals {
            let a =
                portal_debug_map_point(grid, node_center, sector_size, portal.vertices_world[0]);
            let b =
                portal_debug_map_point(grid, node_center, sector_size, portal.vertices_world[1]);
            portals.push(PlayChunkDebugMapPortal {
                portal_index: room_portal_base + portal.index,
                source_room_index: room_base_index + portal.source_room,
                destination_room_index: room_base_index + portal.destination_room,
                a,
                b,
            });
        }
    }
    PlayChunkDebugMap { cells, portals }
}

fn portal_debug_map_point(
    grid: &WorldGrid,
    node_center: [f32; 2],
    sector_size: f32,
    vertex: [i32; 3],
) -> [f32; 2] {
    [
        node_center[0] + vertex[0] as f32 / sector_size
            - grid.origin[0] as f32
            - grid.width as f32 * 0.5,
        node_center[1] + vertex[2] as f32 / sector_size
            - grid.origin[1] as f32
            - grid.depth as f32 * 0.5,
    ]
}

fn debug_chunk_bit(index: usize) -> u64 {
    if index < u64::BITS as usize {
        1u64 << index
    } else {
        0
    }
}

fn rotate_vec2(v: Vec2, radians: f32) -> Vec2 {
    let (sin, cos) = radians.sin_cos();
    Vec2::new(v.x * cos - v.y * sin, v.x * sin + v.y * cos)
}

fn directed_portal_map_segment(
    a: Pos2,
    b: Pos2,
    source_room_index: usize,
    destination_room_index: usize,
) -> (Pos2, Pos2) {
    let edge = b - a;
    let len = (edge.x * edge.x + edge.y * edge.y).sqrt();
    if len <= 0.001 {
        return (a, b);
    }
    let side = if source_room_index <= destination_room_index {
        1.0
    } else {
        -1.0
    };
    let offset = Vec2::new(-edge.y / len, edge.x / len) * (1.6 * side);
    (a + offset, b + offset)
}

fn draw_rejected_map_marker(painter: &egui::Painter, rect: Rect) {
    let inset = (rect.width().min(rect.height()) * 0.22).clamp(1.0, 4.0);
    let a = rect.left_top() + Vec2::splat(inset);
    let b = rect.right_bottom() - Vec2::splat(inset);
    painter.line_segment(
        [a, b],
        Stroke::new(2.4, Color32::from_rgba_unmultiplied(20, 14, 10, 160)),
    );
    painter.line_segment([a, b], Stroke::new(1.2, Color32::from_rgb(255, 238, 204)));
}

fn draw_rejected_portal_marker(painter: &egui::Painter, a: Pos2, b: Pos2) {
    let edge = b - a;
    let len = (edge.x * edge.x + edge.y * edge.y).sqrt();
    if len <= 0.001 {
        return;
    }
    let tangent = edge / len;
    let normal = Vec2::new(-tangent.y, tangent.x);
    let center = a + edge * 0.5;
    let half_a = tangent * 4.5 + normal * 4.5;
    let half_b = tangent * 4.5 - normal * 4.5;
    painter.line_segment(
        [center - half_a, center + half_a],
        Stroke::new(2.4, Color32::from_rgba_unmultiplied(20, 14, 10, 170)),
    );
    painter.line_segment(
        [center - half_a, center + half_a],
        Stroke::new(1.2, Color32::from_rgb(255, 238, 204)),
    );
    painter.line_segment(
        [center - half_b, center + half_b],
        Stroke::new(2.4, Color32::from_rgba_unmultiplied(20, 14, 10, 170)),
    );
    painter.line_segment(
        [center - half_b, center + half_b],
        Stroke::new(1.2, Color32::from_rgb(255, 238, 204)),
    );
}

fn draw_chunk_map_legend_item(
    painter: &egui::Painter,
    pos: Pos2,
    fill: Color32,
    stroke: Color32,
    label: &str,
) {
    let swatch = Rect::from_min_size(pos, Vec2::new(9.0, 9.0));
    if fill.a() > 0 {
        painter.rect_filled(swatch, 0.0, fill);
    }
    painter.rect_stroke(swatch, 0.0, Stroke::new(1.0, stroke), StrokeKind::Inside);
    painter.text(
        pos + Vec2::new(13.0, -1.0),
        Align2::LEFT_TOP,
        label,
        FontId::monospace(10.0),
        STUDIO_TEXT_WEAK,
    );
}

fn draw_play_metric_line(painter: &egui::Painter, x: f32, y: &mut f32, text: &str, color: Color32) {
    painter.text(
        Pos2::new(x, *y),
        Align2::LEFT_TOP,
        text,
        FontId::monospace(11.0),
        color,
    );
    *y += 13.0;
}

fn dock_label_limit(depth: usize) -> usize {
    LEFT_DOCK_LABEL_CHARS
        .saturating_sub(depth.saturating_mul(2))
        .max(18)
}

fn compact_middle(text: &str, max_chars: usize) -> String {
    let char_count = text.chars().count();
    if char_count <= max_chars || max_chars < 8 {
        return text.to_string();
    }

    let marker = "...";
    let room = max_chars.saturating_sub(marker.len());
    let head = room.saturating_mul(2) / 3;
    let tail = room.saturating_sub(head);
    let mut out = String::with_capacity(text.len().min(max_chars + marker.len()));
    out.extend(text.chars().take(head));
    out.push_str(marker);
    let mut suffix = text.chars().rev().take(tail).collect::<Vec<_>>();
    suffix.reverse();
    out.extend(suffix);
    out
}

fn draw_scene_node_row(
    ui: &mut egui::Ui,
    row: &NodeRow,
    selected: bool,
    collapsed: bool,
    directly_hidden: bool,
    effectively_hidden: bool,
    renaming: &mut Option<(NodeId, String)>,
    pending_focus: &mut bool,
    actions: &mut Vec<TreeAction>,
) {
    let row_height = 24.0;
    let dnd_active = egui::DragAndDrop::has_any_payload(ui.ctx());

    // Insertion bar above the row: dropping here reorders before the
    // current row inside its parent's child list. Hidden when no drag
    // is in flight so we don't steal mouse hovers.
    if dnd_active && row.id != NodeId::ROOT {
        let (insert_rect, insert_response) =
            ui.allocate_exact_size(Vec2::new(ui.available_width(), 4.0), Sense::hover());
        if let Some(payload) = insert_response.dnd_release_payload::<NodeId>() {
            actions.push(TreeAction::Reparent {
                source: *payload,
                target_parent: row.parent.unwrap_or(NodeId::ROOT),
                position: row.sibling_index,
            });
        }
        if insert_response.contains_pointer() {
            ui.painter().line_segment(
                [
                    Pos2::new(insert_rect.left() + 4.0, insert_rect.center().y),
                    Pos2::new(insert_rect.right() - 4.0, insert_rect.center().y),
                ],
                Stroke::new(EDITOR_OUTLINE_STROKE_WIDTH, EDITOR_OUTLINE_ACCENT),
            );
        }
    }

    let (rect, response) = ui.allocate_exact_size(
        Vec2::new(ui.available_width(), row_height),
        Sense::click_and_drag(),
    );
    let painter = ui.painter_at(rect);
    let hovered = response.hovered();
    let display_kind = scene_tree_kind_label(row.kind);

    if selected {
        painter.rect_filled(rect.shrink2(Vec2::new(0.0, 1.0)), 3.0, STUDIO_ACCENT_DIM);
    } else if hovered {
        painter.rect_filled(
            rect.shrink2(Vec2::new(0.0, 1.0)),
            3.0,
            Color32::from_rgba_unmultiplied(42, 58, 70, 120),
        );
    }

    let indent = row.depth as f32 * 16.0;
    let content_left = rect.left() + 4.0 + indent;
    if row.depth > 0 {
        let line_x = rect.left() + 10.0 + (row.depth.saturating_sub(1) as f32 * 16.0);
        painter.line_segment(
            [
                Pos2::new(line_x, rect.top()),
                Pos2::new(line_x, rect.bottom()),
            ],
            Stroke::new(1.0, Color32::from_rgba_unmultiplied(70, 86, 102, 92)),
        );
    }

    let chevron_rect = Rect::from_min_size(
        Pos2::new(content_left, rect.center().y - 5.0),
        Vec2::splat(10.0),
    );
    let chevron_response = if row.child_count > 0 {
        ui.interact(
            chevron_rect.expand(4.0),
            ui.id().with(("scene_tree_expand", row.id)),
            Sense::click(),
        )
        .on_hover_text(if collapsed { "Expand" } else { "Collapse" })
    } else {
        response.clone()
    };
    if row.child_count > 0 {
        painter.text(
            chevron_rect.center(),
            Align2::CENTER_CENTER,
            if collapsed {
                icons::CHEVRON_RIGHT
            } else {
                icons::CHEVRON_DOWN
            }
            .to_string(),
            icons::font(12.0),
            if chevron_response.hovered() {
                Color32::WHITE
            } else {
                Color32::from_rgb(160, 174, 188)
            },
        );
    }

    let icon_rect = Rect::from_min_size(
        Pos2::new(content_left + 14.0, rect.center().y - 8.0),
        Vec2::splat(16.0),
    );
    painter.text(
        icon_rect.center(),
        Align2::CENTER_CENTER,
        node_lucide_icon(display_kind, row.id == NodeId::ROOT).to_string(),
        icons::font(15.0),
        node_lucide_color(display_kind, row.id == NodeId::ROOT, selected),
    );

    let text_color = if effectively_hidden {
        Color32::from_rgb(96, 110, 124)
    } else if selected {
        Color32::WHITE
    } else {
        STUDIO_TEXT
    };
    let in_rename = matches!(renaming, Some((id, _)) if *id == row.id);
    let label = if row.id == NodeId::ROOT {
        format!("Root: {display_kind}")
    } else {
        row.name.clone()
    };
    let display_label = compact_middle(&label, dock_label_limit(row.depth));
    let response = if !in_rename && display_label != label {
        response.on_hover_text(label.clone())
    } else {
        response
    };
    let text_left = icon_rect.right() + 7.0;
    let text_pos = Pos2::new(text_left, rect.center().y);

    if in_rename {
        let edit_rect = Rect::from_min_size(
            Pos2::new(text_left, rect.center().y - 10.0),
            Vec2::new(rect.right() - text_left - 56.0, 20.0),
        );
        if let Some((_, buffer)) = renaming.as_mut() {
            let edit_response = ui.put(
                edit_rect,
                egui::TextEdit::singleline(buffer)
                    .desired_width(edit_rect.width())
                    .margin(egui::Vec2::new(2.0, 1.0)),
            );
            if *pending_focus {
                edit_response.request_focus();
                *pending_focus = false;
            }
            let lost_focus = edit_response.lost_focus();
            let pressed_enter = lost_focus && ui.input(|i| i.key_pressed(egui::Key::Enter));
            let pressed_esc = ui.input(|i| i.key_pressed(egui::Key::Escape));
            if pressed_esc {
                actions.push(TreeAction::CancelRename);
            } else if pressed_enter || lost_focus {
                actions.push(TreeAction::CommitRename(row.id, buffer.clone()));
            }
        }
    } else {
        let name_clip_right = if row.id != NodeId::ROOT {
            (rect.right() - 142.0).max(text_left + 72.0)
        } else {
            rect.right() - 28.0
        };
        painter
            .with_clip_rect(Rect::from_min_max(
                Pos2::new(text_left, rect.top()),
                Pos2::new(name_clip_right, rect.bottom()),
            ))
            .text(
                text_pos,
                Align2::LEFT_CENTER,
                display_label,
                FontId::proportional(13.0),
                text_color,
            );
    }

    if !in_rename && row.id != NodeId::ROOT {
        painter.text(
            Pos2::new(
                (rect.right() - 136.0).max(text_pos.x + 78.0),
                rect.center().y,
            ),
            Align2::LEFT_CENTER,
            display_kind,
            FontId::proportional(11.0),
            if effectively_hidden {
                Color32::from_rgb(84, 96, 108)
            } else if selected {
                Color32::from_rgb(204, 229, 236)
            } else {
                STUDIO_TEXT_WEAK
            },
        );
    }

    if row.child_count > 0 && row.id != NodeId::ROOT {
        let pill = Rect::from_min_size(
            Pos2::new(rect.right() - 50.0, rect.center().y - 8.0),
            Vec2::new(24.0, 16.0),
        );
        painter.rect_filled(pill, 8.0, Color32::from_rgba_unmultiplied(9, 14, 18, 138));
        painter.text(
            pill.center(),
            Align2::CENTER_CENTER,
            row.child_count.to_string(),
            FontId::monospace(10.0),
            STUDIO_TEXT_WEAK,
        );
    }

    let eye_rect = Rect::from_min_size(
        Pos2::new(rect.right() - 22.0, rect.center().y - 6.0),
        Vec2::new(14.0, 12.0),
    );
    let eye_response = ui
        .interact(
            eye_rect.expand2(Vec2::new(5.0, 4.0)),
            ui.id().with(("scene_tree_visibility", row.id)),
            Sense::click(),
        )
        .on_hover_text(if directly_hidden {
            "Show node"
        } else {
            "Hide node"
        });
    painter.text(
        eye_rect.center(),
        Align2::CENTER_CENTER,
        if effectively_hidden {
            icons::EYE_OFF
        } else {
            icons::EYE
        }
        .to_string(),
        icons::font(12.0),
        if eye_response.hovered() {
            Color32::WHITE
        } else if effectively_hidden {
            Color32::from_rgb(82, 92, 102)
        } else if selected || hovered {
            Color32::from_rgb(184, 205, 218)
        } else {
            Color32::from_rgb(88, 102, 116)
        },
    );

    if in_rename {
        return;
    }

    if chevron_response.clicked() && row.child_count > 0 {
        actions.push(TreeAction::ToggleExpanded(row.id));
    }
    if eye_response.clicked() {
        actions.push(TreeAction::ToggleVisibility(row.id));
    }
    let icon_clicked =
        (row.child_count > 0 && chevron_response.clicked()) || eye_response.clicked();

    // Drag source: only descendants of root can be dragged.
    if row.id != NodeId::ROOT && response.dragged() {
        response.dnd_set_drag_payload::<NodeId>(row.id);
        let label_text = label_for_drag(row);
        let pointer_pos = ui
            .ctx()
            .input(|i| i.pointer.interact_pos())
            .unwrap_or_else(|| rect.center());
        ui.painter().text(
            pointer_pos + Vec2::new(12.0, 0.0),
            Align2::LEFT_CENTER,
            label_text,
            FontId::proportional(12.0),
            STUDIO_ACCENT,
        );
    }

    // Drop on row body → reparent as last child. Highlight while
    // hovered so the user knows where the drop will land.
    if let Some(payload) = response.dnd_hover_payload::<NodeId>() {
        if *payload != row.id {
            ui.painter().rect_stroke(
                rect.shrink2(Vec2::new(2.0, 1.0)),
                3.0,
                Stroke::new(EDITOR_OUTLINE_STROKE_WIDTH, EDITOR_OUTLINE_ACCENT),
                StrokeKind::Inside,
            );
        }
    }
    if let Some(payload) = response.dnd_release_payload::<NodeId>() {
        actions.push(TreeAction::Reparent {
            source: *payload,
            target_parent: row.id,
            position: row.child_count,
        });
    }

    if response.clicked() && !icon_clicked {
        let modifiers = ui.input(|input| input.modifiers);
        actions.push(TreeAction::Select {
            id: row.id,
            modifiers,
        });
    }
    if response.double_clicked() && !icon_clicked && row.id != NodeId::ROOT {
        actions.push(TreeAction::BeginRename(row.id));
    }

    if row.id != NodeId::ROOT {
        response.context_menu(|ui| {
            ui.menu_button(icons::label(icons::PLUS, "Add Child"), |ui| {
                for (label, kind) in default_addable_kinds() {
                    if ui.button(label).clicked() {
                        actions.push(TreeAction::AddChild {
                            parent: row.id,
                            kind,
                            name: label,
                        });
                        ui.close_menu();
                    }
                }
            });
            if ui.button(icons::label(icons::PALETTE, "Rename")).clicked() {
                actions.push(TreeAction::BeginRename(row.id));
                ui.close_menu();
            }
            if ui.button(icons::label(icons::COPY, "Duplicate")).clicked() {
                actions.push(TreeAction::Duplicate(row.id));
                ui.close_menu();
            }
            ui.separator();
            if ui.button(icons::label(icons::TRASH, "Delete")).clicked() {
                actions.push(TreeAction::Delete(row.id));
                ui.close_menu();
            }
        });
    } else {
        // Even root accepts "Add Child" for top-level Worlds.
        response.context_menu(|ui| {
            ui.menu_button(icons::label(icons::PLUS, "Add Child"), |ui| {
                for (label, kind) in default_addable_kinds() {
                    if ui.button(label).clicked() {
                        actions.push(TreeAction::AddChild {
                            parent: row.id,
                            kind,
                            name: label,
                        });
                        ui.close_menu();
                    }
                }
            });
        });
    }
}

fn reserve_remaining_panel_space(ui: &mut egui::Ui) {
    let remaining = ui.available_size();
    if remaining.x > 0.0 || remaining.y > 0.0 {
        ui.allocate_space(remaining);
    }
}

fn fixed_panel_content<R>(
    ui: &mut egui::Ui,
    id_salt: &'static str,
    add_contents: impl FnOnce(&mut egui::Ui) -> R,
) -> R {
    let size = ui.available_size_before_wrap();
    let (rect, _) = ui.allocate_exact_size(size, Sense::hover());
    let mut child = ui.new_child(
        egui::UiBuilder::new()
            .id_salt(id_salt)
            .max_rect(rect)
            .layout(egui::Layout::top_down(egui::Align::Min)),
    );
    child.expand_to_include_rect(rect);
    child.set_clip_rect(rect);
    add_contents(&mut child)
}

fn range_between<T: Copy + Eq>(order: &[T], a: T, b: T) -> Option<Vec<T>> {
    let ai = order.iter().position(|id| *id == a)?;
    let bi = order.iter().position(|id| *id == b)?;
    let (start, end) = if ai <= bi { (ai, bi) } else { (bi, ai) };
    Some(order[start..=end].to_vec())
}

fn scene_node_hidden(
    scene: &psxed_project::Scene,
    hidden_scene_nodes: &HashSet<NodeId>,
    id: NodeId,
) -> bool {
    let mut current = Some(id);
    while let Some(node_id) = current {
        if hidden_scene_nodes.contains(&node_id) {
            return true;
        }
        current = scene.node(node_id).and_then(|node| node.parent);
    }
    false
}

fn scene_tree_row_matches_filter(row: &NodeRow, filter: &str) -> bool {
    let display_kind = scene_tree_kind_label(row.kind);
    filter.is_empty()
        || row.name.to_ascii_lowercase().contains(filter)
        || row.kind.to_ascii_lowercase().contains(filter)
        || display_kind.to_ascii_lowercase().contains(filter)
}

fn scene_tree_display_rows<'a>(
    rows: &'a [NodeRow],
    filter: &str,
    collapsed_scene_nodes: &HashSet<NodeId>,
) -> Vec<&'a NodeRow> {
    if !filter.is_empty() {
        return rows
            .iter()
            .filter(|row| scene_tree_row_matches_filter(row, filter))
            .collect();
    }

    let mut collapsed_depth = None;
    let mut display_rows = Vec::with_capacity(rows.len());
    for row in rows {
        if let Some(depth) = collapsed_depth {
            if row.depth > depth {
                continue;
            }
            collapsed_depth = None;
        }

        display_rows.push(row);
        if row.child_count > 0 && collapsed_scene_nodes.contains(&row.id) {
            collapsed_depth = Some(row.depth);
        }
    }
    display_rows
}

fn first_in_order<T: Copy + Eq + std::hash::Hash>(order: &[T], selected: &HashSet<T>) -> Option<T> {
    order.iter().copied().find(|id| selected.contains(id))
}

fn constrain_resizable_dock_content(ui: &mut egui::Ui, width: f32) {
    ui.set_width(width);
    ui.set_max_width(width);
    ui.style_mut().wrap_mode = Some(egui::TextWrapMode::Wrap);
    ui.spacing_mut().text_edit_width = (width - 72.0).clamp(24.0, 280.0);
}

fn max_resizable_side_dock_width(ctx: &egui::Context, reserve_opposite_dock: bool) -> f32 {
    let opposite = if reserve_opposite_dock {
        RESIZABLE_DOCK_MIN_WIDTH
    } else {
        0.0
    };
    (ctx.available_rect().width() - CENTRAL_WORKSPACE_MIN_WIDTH - opposite)
        .max(RESIZABLE_DOCK_MIN_WIDTH)
}

fn max_resizable_bottom_dock_height(ctx: &egui::Context) -> f32 {
    (ctx.available_rect().height() - CENTRAL_WORKSPACE_MIN_HEIGHT).max(CONTENT_BROWSER_MIN_HEIGHT)
}

/// Friendly label for the drag-tooltip preview.
fn label_for_drag(row: &NodeRow) -> String {
    if row.name.is_empty() {
        scene_tree_kind_label(row.kind).to_string()
    } else {
        row.name.clone()
    }
}

fn scene_tree_kind_label(kind: &'static str) -> &'static str {
    match kind {
        "Room" => "Map",
        other => other,
    }
}

/// Default `(menu label, kind template)` pairs for "Add Child" menus.
/// Each menu entry uses the label as the new node's display name.
