fn starter_room_grid(sector_size: i32, material: Option<ResourceId>) -> WorldGrid {
    let mut grid = WorldGrid::empty(3, 3, sector_size);
    for x in 0..3 {
        for z in 0..3 {
            grid.set_floor(x, z, 0, material);
        }
    }
    grid
}

fn addable_component_templates(
    host_kind: &NodeKind,
    existing: &[&NodeKind],
) -> Vec<(&'static str, NodeKind)> {
    component_templates_for_host(host_kind)
        .into_iter()
        .filter(|(_, candidate)| {
            component_can_be_added(candidate, existing)
                && component_is_valid_for_host(host_kind, candidate)
        })
        .collect()
}

fn component_templates_for_host(host_kind: &NodeKind) -> Vec<(&'static str, NodeKind)> {
    if !matches!(host_kind, NodeKind::Entity) {
        return Vec::new();
    }
    vec![
        (
            "Model Renderer",
            NodeKind::ModelRenderer {
                model: None,
                material: None,
                visual_offset: [0; 3],
                visual_scale_q8: psxed_project::MODEL_SCALE_ONE_Q8,
            },
        ),
        (
            "Animator",
            NodeKind::Animator {
                clip: None,
                action_clips: Vec::new(),
                autoplay: true,
            },
        ),
        (
            "Collider",
            NodeKind::Collider {
                shape: ColliderShape::default(),
                solid: true,
            },
        ),
        (
            "Interactable",
            NodeKind::Interactable {
                prompt: String::new(),
                action: String::new(),
            },
        ),
        (
            "Character Controller",
            NodeKind::CharacterController {
                character: None,
                settings: CharacterControllerSettings::default(),
                player: false,
            },
        ),
        (
            "AI Controller",
            NodeKind::AiController {
                behavior: String::new(),
            },
        ),
        (
            "Combat",
            NodeKind::Combat {
                faction: String::new(),
                health: 1,
            },
        ),
        (
            "Equipment",
            NodeKind::Equipment {
                weapon: None,
                character_socket: "right_hand_grip".to_string(),
                weapon_grip: "grip".to_string(),
            },
        ),
    ]
}

fn component_can_be_added_to_host(
    host_kind: &NodeKind,
    candidate: &NodeKind,
    scene: &psxed_project::Scene,
    host: NodeId,
) -> bool {
    let existing: Vec<&NodeKind> = scene
        .node(host)
        .into_iter()
        .flat_map(|host| host.children.iter())
        .filter_map(|id| scene.node(*id))
        .filter(|child| child.kind.is_component())
        .map(|child| &child.kind)
        .collect();
    component_is_valid_for_host(host_kind, candidate)
        && component_can_be_added(candidate, &existing)
}

const fn component_is_valid_for_host(host_kind: &NodeKind, component: &NodeKind) -> bool {
    if !component.is_component() {
        return false;
    }
    match component {
        _ => matches!(host_kind, NodeKind::Entity),
    }
}

fn component_can_be_added(candidate: &NodeKind, existing: &[&NodeKind]) -> bool {
    if component_allows_multiple(candidate) {
        return true;
    }
    let Some(candidate_slot) = component_slot(candidate) else {
        return true;
    };
    !existing
        .iter()
        .filter_map(|component| component_slot(component))
        .any(|slot| slot == candidate_slot)
}

const fn component_allows_multiple(kind: &NodeKind) -> bool {
    matches!(kind, NodeKind::Collider { .. })
}

const fn component_slot(kind: &NodeKind) -> Option<&'static str> {
    match kind {
        NodeKind::ModelRenderer { .. } => Some("ModelRenderer"),
        NodeKind::Animator { .. } => Some("Animator"),
        NodeKind::Collider { .. } => Some("Collider"),
        NodeKind::Interactable { .. } => Some("Interactable"),
        NodeKind::CharacterController { .. } => Some("CharacterController"),
        NodeKind::AiController { .. } => Some("AiController"),
        NodeKind::Combat { .. } => Some("Combat"),
        NodeKind::Equipment { .. } => Some("Equipment"),
        _ => None,
    }
}

fn node_draw_mode(kind: &NodeKind) -> &'static str {
    match kind {
        NodeKind::MeshInstance { .. } => "Textured Triangles",
        NodeKind::ImageProp { .. } => "Flat Image",
        NodeKind::ModelRenderer { .. } => "Render Component",
        NodeKind::Animator { .. } => "Animation Component",
        NodeKind::Collider { .. } => "Collision Component",
        NodeKind::Interactable { .. } => "Interaction Component",
        NodeKind::CharacterController { .. } => "Controller Component",
        NodeKind::AiController { .. } => "AI Component",
        NodeKind::Combat { .. } => "Combat Component",
        NodeKind::Equipment { .. } => "Equipment Component",
        NodeKind::World { .. } => "Portal Region",
        NodeKind::Entity => "Entity Host",
        NodeKind::Room { .. } => "Editable Map Grid",
        NodeKind::PointLight { .. } => "Static Light",
        NodeKind::SpawnPoint { .. } => "Spawn Marker",
        NodeKind::Trigger { .. } => "Trigger Volume",
        NodeKind::AudioSource { .. } => "Audio Marker",
        NodeKind::Portal { .. } => "Portal Seam",
        NodeKind::Node | NodeKind::Node3D => "None",
    }
}

#[derive(Debug, Clone)]
struct ProjectFileRow {
    depth: usize,
    name: String,
    folder: bool,
    key: String,
    ancestors: Vec<String>,
    icon: char,
    resource: Option<ResourceId>,
}

fn project_filesystem_rows(project: &ProjectDocument) -> Vec<ProjectFileRow> {
    let mut rows = Vec::new();
    rows.push(ProjectFileRow {
        depth: 0,
        name: "res://".to_string(),
        folder: true,
        key: "res://".to_string(),
        ancestors: Vec::new(),
        icon: icons::FOLDER,
        resource: None,
    });
    rows.push(ProjectFileRow {
        depth: 1,
        name: "maps".to_string(),
        folder: true,
        key: "res://maps".to_string(),
        ancestors: vec!["res://".to_string()],
        icon: icons::FOLDER,
        resource: None,
    });
    rows.push(ProjectFileRow {
        depth: 2,
        name: format!("{}.map", snake_name(&project.active_scene().name)),
        folder: false,
        key: "res://maps/main.map".to_string(),
        ancestors: vec!["res://".to_string(), "res://maps".to_string()],
        icon: icons::GRID,
        resource: None,
    });

    push_resource_folder(project, &mut rows, "materials", ResourceFilter::Material);
    push_resource_folder(project, &mut rows, "textures", ResourceFilter::Texture);
    push_resource_folder(project, &mut rows, "models", ResourceFilter::Model);
    push_resource_folder(project, &mut rows, "animations", ResourceFilter::Animation);
    push_resource_folder(project, &mut rows, "characters", ResourceFilter::Character);
    push_resource_folder(project, &mut rows, "weapons", ResourceFilter::Weapon);
    push_resource_folder(project, &mut rows, "meshes", ResourceFilter::Mesh);
    push_resource_folder(project, &mut rows, "spawns", ResourceFilter::Other);
    rows
}

fn push_resource_folder(
    project: &ProjectDocument,
    rows: &mut Vec<ProjectFileRow>,
    folder: &str,
    filter: ResourceFilter,
) {
    let key = format!("res://{folder}");
    rows.push(ProjectFileRow {
        depth: 1,
        name: folder.to_string(),
        folder: true,
        key: key.clone(),
        ancestors: vec!["res://".to_string()],
        icon: icons::FOLDER,
        resource: None,
    });
    for resource in project
        .resources
        .iter()
        .filter(|resource| filter.matches(&resource.data))
    {
        rows.push(ProjectFileRow {
            depth: 2,
            name: resource_file_name(resource),
            folder: false,
            key: format!("{key}/{}", resource.id.raw()),
            ancestors: vec!["res://".to_string(), key.clone()],
            icon: resource_lucide_icon(&resource.data),
            resource: Some(resource.id),
        });
    }
}

fn project_filesystem_display_rows<'a>(
    rows: &'a [ProjectFileRow],
    filter: &str,
    collapsed_folders: &HashSet<String>,
) -> Vec<&'a ProjectFileRow> {
    rows.iter()
        .filter(|row| {
            if row
                .ancestors
                .iter()
                .any(|ancestor| collapsed_folders.contains(ancestor))
            {
                return false;
            }
            row.folder || filter.is_empty() || row.name.to_ascii_lowercase().contains(filter)
        })
        .collect()
}

fn draw_project_file_row(
    ui: &mut egui::Ui,
    row: &ProjectFileRow,
    selected_resource: Option<ResourceId>,
    selected_resources: &HashSet<ResourceId>,
    filter: &str,
    collapsed_folders: &HashSet<String>,
) -> Option<ProjectFileRowAction> {
    if !row.folder && !filter.is_empty() && !row.name.to_ascii_lowercase().contains(filter) {
        return None;
    }

    let mut action = None;
    ui.horizontal(|ui| {
        ui.add_space(row.depth as f32 * 14.0);
        let display_name = compact_middle(&row.name, dock_label_limit(row.depth));
        let label_was_compacted = display_name != row.name;
        if row.folder {
            let chevron = if collapsed_folders.contains(&row.key) {
                icons::CHEVRON_RIGHT
            } else {
                icons::CHEVRON_DOWN
            };
            let label = format!("{chevron}  {}", icons::label(row.icon, &display_name));
            let response = ui.add(egui::SelectableLabel::new(
                false,
                RichText::new(label).color(STUDIO_TEXT_WEAK),
            ));
            if response.clicked() {
                action = Some(ProjectFileRowAction::ToggleFolder(row.key.clone()));
            }
            if label_was_compacted {
                response.on_hover_text(row.name.clone());
            }
        } else {
            ui.add_space(18.0);
            let label = icons::label(row.icon, &display_name);
            let selected = row
                .resource
                .is_some_and(|id| selected_resources.contains(&id))
                || (selected_resources.is_empty() && row.resource == selected_resource);
            let response = ui.selectable_label(selected, label);
            if response.clicked() {
                if let Some(id) = row.resource {
                    action = Some(ProjectFileRowAction::Select(ResourceClick {
                        id,
                        modifiers: ui.input(|input| input.modifiers),
                    }));
                }
            }
            if label_was_compacted {
                response.on_hover_text(row.name.clone());
            }
        }
    });
    action
}

fn resource_file_name(resource: &Resource) -> String {
    match &resource.data {
        ResourceData::Texture { psxt_path } => cooked_name(&resource.name, psxt_path, "psxt"),
        ResourceData::Material(_) => cooked_name(&resource.name, "", "mat"),
        ResourceData::Model(model) => cooked_name(&resource.name, &model.model_path, "psxmdl"),
        ResourceData::Skeleton(_) => cooked_name(&resource.name, "", "skeleton"),
        ResourceData::AnimationSource(source) => {
            cooked_name(&resource.name, &source.source_path, "animsrc")
        }
        ResourceData::AnimationClip(clip) => {
            cooked_name(&resource.name, &clip.psxanim_path, "psxanim")
        }
        ResourceData::AnimationSet(_) => cooked_name(&resource.name, "", "animset"),
        ResourceData::Character(_) => cooked_name(&resource.name, "", "profile"),
        ResourceData::Weapon(_) => cooked_name(&resource.name, "", "weapon"),
        ResourceData::Mesh { source_path } => cooked_name(&resource.name, source_path, "psxmesh"),
        ResourceData::Scene { source_path } => cooked_name(&resource.name, source_path, "room"),
        ResourceData::Script { source_path } => cooked_name(&resource.name, source_path, "script"),
        ResourceData::Audio { source_path } => cooked_name(&resource.name, source_path, "vag"),
    }
}

fn cooked_name(name: &str, source_path: &str, ext: &str) -> String {
    let stem = Path::new(source_path)
        .file_stem()
        .and_then(|stem| stem.to_str())
        .filter(|stem| !stem.is_empty())
        .unwrap_or(name);
    format!("{}.{}", snake_name(stem), ext)
}

fn snake_name(name: &str) -> String {
    let mut out = String::new();
    let mut previous_was_sep = false;
    for ch in name.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
            previous_was_sep = false;
        } else if !previous_was_sep {
            out.push('_');
            previous_was_sep = true;
        }
    }
    out.trim_matches('_').to_string()
}

fn resource_filter_counts(project: &ProjectDocument) -> [(ResourceFilter, usize); 9] {
    let mut texture = 0;
    let mut material = 0;
    let mut model = 0;
    let mut animation = 0;
    let mut character = 0;
    let mut weapon = 0;
    let mut mesh = 0;
    let mut room = 0;
    let mut other = 0;
    for resource in &project.resources {
        match &resource.data {
            ResourceData::Texture { .. } => texture += 1,
            ResourceData::Material(_) => material += 1,
            ResourceData::Model(_) => model += 1,
            ResourceData::Skeleton(_)
            | ResourceData::AnimationSource(_)
            | ResourceData::AnimationClip(_)
            | ResourceData::AnimationSet(_) => animation += 1,
            ResourceData::Character(_) => character += 1,
            ResourceData::Weapon(_) => weapon += 1,
            ResourceData::Mesh { .. } => mesh += 1,
            ResourceData::Scene { .. } => room += 1,
            ResourceData::Script { .. } | ResourceData::Audio { .. } => other += 1,
        }
    }
    [
        (ResourceFilter::Texture, texture),
        (ResourceFilter::Material, material),
        (ResourceFilter::Model, model),
        (ResourceFilter::Animation, animation),
        (ResourceFilter::Character, character),
        (ResourceFilter::Weapon, weapon),
        (ResourceFilter::Mesh, mesh),
        (ResourceFilter::Room, room),
        (ResourceFilter::Other, other),
    ]
}

fn resource_matches_filter(resource: &Resource, filter: ResourceFilter, search: &str) -> bool {
    if !filter.matches(&resource.data) {
        return false;
    }
    if search.is_empty() {
        return true;
    }
    resource.name.to_ascii_lowercase().contains(search)
        || resource.data.label().to_ascii_lowercase().contains(search)
        || resource_source_path(resource)
            .is_some_and(|path| path.to_ascii_lowercase().contains(search))
}

fn resource_source_path(resource: &Resource) -> Option<&str> {
    match &resource.data {
        ResourceData::Texture { psxt_path } => Some(psxt_path.as_str()),
        ResourceData::Model(model) => Some(model.model_path.as_str()),
        ResourceData::AnimationSource(source) => Some(source.source_path.as_str()),
        ResourceData::AnimationClip(clip) => Some(clip.psxanim_path.as_str()),
        ResourceData::Mesh { source_path }
        | ResourceData::Scene { source_path }
        | ResourceData::Script { source_path }
        | ResourceData::Audio { source_path } => Some(source_path.as_str()),
        ResourceData::Material(_)
        | ResourceData::Skeleton(_)
        | ResourceData::AnimationSet(_)
        | ResourceData::Character(_)
        | ResourceData::Weapon(_) => None,
    }
}

fn resource_lucide_icon(data: &ResourceData) -> char {
    match data {
        ResourceData::Texture { .. } => icons::PALETTE,
        ResourceData::Material(_) => icons::BLEND,
        ResourceData::Model(_) => icons::BOX,
        ResourceData::Skeleton(_) => icons::WAYPOINT,
        ResourceData::AnimationSource(_) => icons::PLAY,
        ResourceData::AnimationClip(_) => icons::PLAY,
        ResourceData::AnimationSet(_) => icons::LAYERS,
        ResourceData::Character(_) => icons::MAP_PIN,
        ResourceData::Weapon(_) => icons::WAYPOINT,
        ResourceData::Mesh { .. } => icons::BOX,
        ResourceData::Scene { .. } => icons::GRID,
        ResourceData::Script { .. } => icons::FILE,
        ResourceData::Audio { .. } => icons::AUDIO_LINES,
    }
}

fn resource_lucide_color(data: &ResourceData, selected: bool) -> Color32 {
    if selected {
        return Color32::WHITE;
    }

    match data {
        ResourceData::Texture { .. } => Color32::from_rgb(163, 182, 198),
        ResourceData::Material(_) => Color32::from_rgb(208, 112, 162),
        ResourceData::Model(_) => Color32::from_rgb(186, 178, 124),
        ResourceData::Skeleton(_) => Color32::from_rgb(144, 180, 216),
        ResourceData::AnimationSource(_) => Color32::from_rgb(170, 140, 220),
        ResourceData::AnimationClip(_) => Color32::from_rgb(126, 164, 220),
        ResourceData::AnimationSet(_) => Color32::from_rgb(142, 190, 154),
        ResourceData::Character(_) => Color32::from_rgb(120, 220, 148),
        ResourceData::Weapon(_) => Color32::from_rgb(222, 196, 112),
        ResourceData::Mesh { .. } => Color32::from_rgb(156, 174, 190),
        ResourceData::Scene { .. } => Color32::from_rgb(209, 118, 71),
        ResourceData::Script { .. } => Color32::from_rgb(188, 176, 104),
        ResourceData::Audio { .. } => Color32::from_rgb(104, 202, 188),
    }
}

fn resource_can_open_in_animation_viewer(data: &ResourceData) -> bool {
    matches!(
        data,
        ResourceData::Model(_)
            | ResourceData::AnimationClip(_)
            | ResourceData::AnimationSet(_)
            | ResourceData::Character(_)
    )
}

fn draw_resource_card(
    ui: &mut egui::Ui,
    project: &ProjectDocument,
    resource: &Resource,
    selected: bool,
    thumb: Option<egui::TextureId>,
) -> egui::Response {
    let size = Vec2::new(RESOURCE_CARD_WIDTH, RESOURCE_CARD_HEIGHT);
    let (rect, response) = ui.allocate_exact_size(size, Sense::click_and_drag());
    let painter = ui.painter_at(rect);
    let fill = if selected {
        Color32::from_rgb(21, 50, 62)
    } else {
        STUDIO_PANEL
    };
    painter.rect_filled(rect, 4.0, fill);
    painter.rect_stroke(
        rect,
        4.0,
        Stroke::new(
            if selected { 2.0 } else { 1.0 },
            if selected {
                STUDIO_ACCENT
            } else {
                STUDIO_BORDER
            },
        ),
        StrokeKind::Inside,
    );

    let preview = Rect::from_min_size(rect.min + Vec2::new(8.0, 8.0), Vec2::new(104.0, 72.0));
    draw_resource_preview(&painter, preview, project, resource, thumb);
    painter.rect_stroke(
        preview,
        2.0,
        Stroke::new(1.0, Color32::from_rgb(54, 64, 76)),
        StrokeKind::Inside,
    );
    let badge = Rect::from_min_size(preview.left_top() + Vec2::new(4.0, 4.0), Vec2::splat(22.0));
    painter.rect_filled(badge, 4.0, Color32::from_rgba_unmultiplied(8, 12, 16, 192));
    painter.text(
        badge.center(),
        Align2::CENTER_CENTER,
        resource_lucide_icon(&resource.data).to_string(),
        icons::font(14.0),
        resource_lucide_color(&resource.data, selected),
    );
    painter.text(
        rect.center_top() + Vec2::new(0.0, 88.0),
        Align2::CENTER_TOP,
        compact_middle(&resource.name, 16),
        FontId::monospace(12.0),
        Color32::from_rgb(225, 231, 240),
    );
    painter.text(
        rect.center_top() + Vec2::new(0.0, 110.0),
        Align2::CENTER_TOP,
        resource_detail(resource),
        FontId::monospace(10.0),
        STUDIO_TEXT_WEAK,
    );
    if response.dragged() {
        response.dnd_set_drag_payload::<ResourceId>(resource.id);
        let pointer_pos = ui
            .ctx()
            .input(|input| input.pointer.interact_pos())
            .unwrap_or_else(|| rect.center());
        ui.painter().text(
            pointer_pos + Vec2::new(12.0, 0.0),
            Align2::LEFT_CENTER,
            format!("{} {}", resource_lucide_icon(&resource.data), resource.name),
            FontId::proportional(12.0),
            STUDIO_ACCENT,
        );
    }
    response
}

fn draw_resource_preview(
    painter: &egui::Painter,
    preview: Rect,
    project: &ProjectDocument,
    resource: &Resource,
    thumb: Option<egui::TextureId>,
) {
    match &resource.data {
        ResourceData::Material(material) => {
            // Material: blit the linked Texture's decoded thumbnail
            // when available, fall back to the linked texture's
            // procedural pattern, then to the material's own name.
            if let Some(id) = thumb {
                blit_thumb(painter, preview, id);
            } else if let Some(texture) = material.texture.and_then(|id| project.resource(id)) {
                draw_texture_like_preview(painter, preview, texture);
            } else {
                draw_texture_like_preview(painter, preview, resource);
            }
            if material.tint != [0x80, 0x80, 0x80] {
                let tint = Color32::from_rgba_unmultiplied(
                    material.tint[0].saturating_mul(2),
                    material.tint[1].saturating_mul(2),
                    material.tint[2].saturating_mul(2),
                    48,
                );
                painter.rect_filled(preview, 2.0, tint);
            }
        }
        ResourceData::Texture { .. } => {
            if let Some(id) = thumb {
                blit_thumb(painter, preview, id);
            } else {
                draw_texture_like_preview(painter, preview, resource);
            }
        }
        _ => {
            painter.rect_filled(preview, 2.0, resource_preview_color(resource));
        }
    }
    draw_palette_strip(painter, preview, palette_for_resource(resource));
}

/// Paint a registered egui texture into the preview rect, full-image
/// UV (no atlasing) and untinted. Used for real `.psxt`-decoded
/// thumbnails so the resource card mirrors the actual texels the
/// runtime would sample.
fn blit_thumb(painter: &egui::Painter, preview: Rect, id: egui::TextureId) {
    painter.image(
        id,
        preview,
        Rect::from_min_max(Pos2::new(0.0, 0.0), Pos2::new(1.0, 1.0)),
        Color32::WHITE,
    );
}

fn draw_texture_like_preview(painter: &egui::Painter, preview: Rect, resource: &Resource) {
    let name = resource.name.to_ascii_lowercase();
    if name.contains("brick") {
        draw_brick_preview(painter, preview, resource_preview_color(resource));
    } else if name.contains("floor") || name.contains("stone") {
        draw_stone_preview(painter, preview, resource_preview_color(resource));
    } else {
        draw_checker_preview(painter, preview, resource_preview_color(resource));
    }
}

fn draw_brick_preview(painter: &egui::Painter, preview: Rect, base: Color32) {
    painter.rect_filled(preview, 2.0, darken(base, 8));
    let row_h = 14.0;
    let rows = (preview.height() / row_h).ceil() as i32;
    for row in 0..rows {
        let top = preview.top() + row as f32 * row_h;
        let y = top.min(preview.bottom());
        painter.line_segment(
            [Pos2::new(preview.left(), y), Pos2::new(preview.right(), y)],
            Stroke::new(1.0, darken(base, 48)),
        );
        let offset = if row % 2 == 0 { 0.0 } else { 18.0 };
        let mut x = preview.left() + offset;
        while x < preview.right() {
            painter.line_segment(
                [
                    Pos2::new(x, top + 2.0),
                    Pos2::new(x, (top + row_h - 2.0).min(preview.bottom())),
                ],
                Stroke::new(1.0, darken(base, 45)),
            );
            x += 36.0;
        }
        let stripe = Rect::from_min_max(
            Pos2::new(preview.left(), top + 2.0),
            Pos2::new(preview.right(), (top + 5.0).min(preview.bottom())),
        );
        painter.rect_filled(
            stripe,
            0.0,
            Color32::from_rgba_unmultiplied(188, 110, 60, 35),
        );
    }
}

fn draw_stone_preview(painter: &egui::Painter, preview: Rect, base: Color32) {
    painter.rect_filled(preview, 2.0, darken(base, 18));
    let cols = 3;
    let rows = 3;
    let cell = Vec2::new(
        preview.width() / cols as f32,
        preview.height() / rows as f32,
    );
    for y in 0..rows {
        for x in 0..cols {
            let min = preview.min + Vec2::new(x as f32 * cell.x, y as f32 * cell.y);
            let rect = Rect::from_min_size(min, cell).shrink(1.0);
            let shade = if (x + y) % 2 == 0 {
                lighten(base, 12)
            } else {
                darken(base, 6)
            };
            painter.rect_filled(rect, 1.0, shade);
            painter.rect_stroke(
                rect,
                1.0,
                Stroke::new(1.0, darken(base, 38)),
                StrokeKind::Inside,
            );
        }
    }
}

fn draw_checker_preview(painter: &egui::Painter, preview: Rect, base: Color32) {
    let alt = Color32::from_rgb(
        base.r().saturating_add(28),
        base.g().saturating_add(24),
        base.b().saturating_add(20),
    );
    let cell = 16.0;
    let cols = (preview.width() / cell).ceil() as i32;
    let rows = (preview.height() / cell).ceil() as i32;
    for y in 0..rows {
        for x in 0..cols {
            let min = preview.min + Vec2::new(x as f32 * cell, y as f32 * cell);
            let rect = Rect::from_min_size(min, Vec2::splat(cell)).intersect(preview);
            painter.rect_filled(rect, 0.0, if (x + y) % 2 == 0 { base } else { alt });
        }
    }
}

/// Decode the bytes of a cooked `.psxt` blob into an egui
/// [`ColorImage`] suitable for [`Context::load_texture`], plus the
/// declared `(width, height)` in texels so the cache can pick a
/// reasonable sample rate.
///
/// Supports 4bpp + 8bpp indexed and 15bpp direct. The CLUT/direct
/// colour STP bit (bit 15, set by the runtime so semi-transparent
/// draws can mask fully transparent black) is masked out before
/// producing display RGB.
fn decode_psxt_thumbnail(bytes: &[u8]) -> Option<(ColorImage, PsxtStats)> {
    let texture = psx_asset::Texture::from_bytes(bytes).ok()?;
    let width = texture.width() as usize;
    let height = texture.height() as usize;
    let clut_entries = texture.clut_entries() as usize;
    let depth_bits = match clut_entries {
        16 => 4,
        256 => 8,
        0 => 15,
        _ => return None,
    };
    if width == 0 || height == 0 {
        return None;
    }
    let pixel_count = width.checked_mul(height)?;
    let clut_bytes = texture.clut_bytes();
    if clut_entries > 0 && clut_bytes.len() < clut_entries * 2 {
        return None;
    }
    let stats = PsxtStats {
        width: texture.width(),
        height: texture.height(),
        depth_bits,
        clut_entries: clut_entries as u16,
        index_zero_transparent: texture.index_zero_transparent(),
        pixel_bytes: texture.pixel_bytes().len() as u32,
        clut_bytes: clut_bytes.len() as u32,
        file_bytes: bytes.len() as u32,
    };
    let palette: Vec<Color32> = (0..clut_entries)
        .map(|i| {
            let raw_full = u16::from_le_bytes([clut_bytes[i * 2], clut_bytes[i * 2 + 1]]);
            if i == 0 && texture.index_zero_transparent() && raw_full == 0 {
                return Color32::TRANSPARENT;
            }
            let raw = raw_full & 0x7FFF;
            let r5 = (raw & 0x1F) as u8;
            let g5 = ((raw >> 5) & 0x1F) as u8;
            let b5 = ((raw >> 10) & 0x1F) as u8;
            Color32::from_rgb(
                (r5 << 3) | (r5 >> 2),
                (g5 << 3) | (g5 >> 2),
                (b5 << 3) | (b5 >> 2),
            )
        })
        .collect();

    let pixel_bytes = texture.pixel_bytes();
    let mut pixels = Vec::with_capacity(pixel_count);
    if clut_entries == 0 {
        for i in 0..pixel_count {
            let off = i * 2;
            if off + 1 >= pixel_bytes.len() {
                return None;
            }
            let raw = u16::from_le_bytes([pixel_bytes[off], pixel_bytes[off + 1]]) & 0x7FFF;
            let r5 = (raw & 0x1F) as u8;
            let g5 = ((raw >> 5) & 0x1F) as u8;
            let b5 = ((raw >> 10) & 0x1F) as u8;
            pixels.push(Color32::from_rgb(
                (r5 << 3) | (r5 >> 2),
                (g5 << 3) | (g5 >> 2),
                (b5 << 3) | (b5 >> 2),
            ));
        }
    } else if clut_entries == 16 {
        // 4bpp: 4 texels per halfword, low nibble first.
        let halfwords_per_row = width.div_ceil(4);
        for row in 0..height {
            for hw in 0..halfwords_per_row {
                let off = (row * halfwords_per_row + hw) * 2;
                if off + 1 >= pixel_bytes.len() {
                    break;
                }
                let word = u16::from_le_bytes([pixel_bytes[off], pixel_bytes[off + 1]]);
                for nibble in 0..4 {
                    let texel = (word >> (nibble * 4)) & 0xF;
                    if hw * 4 + nibble < width {
                        pixels.push(palette[texel as usize]);
                    }
                }
            }
        }
    } else {
        // 8bpp: 2 texels per halfword, low byte first.
        let halfwords_per_row = width.div_ceil(2);
        for row in 0..height {
            for hw in 0..halfwords_per_row {
                let off = (row * halfwords_per_row + hw) * 2;
                if off + 1 >= pixel_bytes.len() {
                    break;
                }
                let lo = pixel_bytes[off] as usize;
                let hi = pixel_bytes[off + 1] as usize;
                if hw * 2 < width {
                    pixels.push(palette[lo]);
                }
                if hw * 2 + 1 < width {
                    pixels.push(palette[hi]);
                }
            }
        }
    }
    if pixels.len() != pixel_count {
        return None;
    }
    Some((
        ColorImage {
            size: [width, height],
            pixels,
        },
        stats,
    ))
}

fn draw_palette_strip(painter: &egui::Painter, preview: Rect, swatches: [Color32; 5]) {
    let width = preview.width() / swatches.len() as f32;
    for (idx, color) in swatches.iter().enumerate() {
        let min = Pos2::new(preview.left() + idx as f32 * width, preview.bottom() - 10.0);
        let rect = Rect::from_min_size(min, Vec2::new(width, 10.0));
        painter.rect_filled(rect, 0.0, *color);
    }
}

fn palette_for_resource(resource: &Resource) -> [Color32; 5] {
    let base = resource_preview_color(resource);
    [
        Color32::from_rgb(28, 30, 34),
        darken(base, 70),
        darken(base, 35),
        base,
        lighten(base, 44),
    ]
}

fn darken(color: Color32, amount: u8) -> Color32 {
    Color32::from_rgb(
        color.r().saturating_sub(amount),
        color.g().saturating_sub(amount),
        color.b().saturating_sub(amount),
    )
}

fn lighten(color: Color32, amount: u8) -> Color32 {
    Color32::from_rgb(
        color.r().saturating_add(amount),
        color.g().saturating_add(amount),
        color.b().saturating_add(amount),
    )
}

fn resource_preview_color(resource: &Resource) -> Color32 {
    let name = resource.name.to_ascii_lowercase();
    if name.contains("brick") {
        Color32::from_rgb(130, 70, 42)
    } else if name.contains("floor") {
        Color32::from_rgb(106, 112, 120)
    } else if name.contains("glass") {
        Color32::from_rgb(80, 150, 165)
    } else {
        match &resource.data {
            ResourceData::Texture { .. } => Color32::from_rgb(92, 116, 140),
            ResourceData::Material(_) => Color32::from_rgb(120, 92, 135),
            ResourceData::Model(_) => Color32::from_rgb(140, 124, 96),
            ResourceData::Skeleton(_) => Color32::from_rgb(82, 112, 145),
            ResourceData::AnimationSource(_) => Color32::from_rgb(104, 82, 145),
            ResourceData::AnimationClip(_) => Color32::from_rgb(76, 108, 170),
            ResourceData::AnimationSet(_) => Color32::from_rgb(82, 136, 100),
            ResourceData::Character(_) => Color32::from_rgb(96, 144, 110),
            ResourceData::Weapon(_) => Color32::from_rgb(150, 132, 76),
            ResourceData::Mesh { .. } => Color32::from_rgb(110, 120, 130),
            ResourceData::Scene { .. } => Color32::from_rgb(92, 130, 106),
            ResourceData::Script { .. } => Color32::from_rgb(128, 126, 80),
            ResourceData::Audio { .. } => Color32::from_rgb(80, 128, 128),
        }
    }
}

fn resource_detail(resource: &Resource) -> &'static str {
    match &resource.data {
        ResourceData::Texture { .. } => "Texture - 4bpp",
        ResourceData::Material(_) => "Material - 4bpp",
        ResourceData::Model(_) => "Model",
        ResourceData::Skeleton(_) => "Skeleton",
        ResourceData::AnimationSource(_) => "Animation Source",
        ResourceData::AnimationClip(_) => "Animation Clip",
        ResourceData::AnimationSet(_) => "Clip Role Map",
        ResourceData::Character(_) => "Character Profile",
        ResourceData::Weapon(_) => "Weapon",
        ResourceData::Mesh { .. } => "Mesh",
        ResourceData::Scene { .. } => "Map",
        ResourceData::Script { .. } => "Script",
        ResourceData::Audio { .. } => "Audio",
    }
}

fn draw_viewport_overlay(
    painter: &egui::Painter,
    rect: Rect,
    project: &ProjectDocument,
    zoom: f32,
    snap_units: u16,
) {
    let overlay = Rect::from_min_size(
        rect.left_top() + Vec2::new(12.0, 12.0),
        Vec2::new(132.0, 94.0),
    );
    painter.rect_filled(
        overlay,
        2.0,
        Color32::from_rgba_unmultiplied(14, 20, 26, 224),
    );
    painter.rect_stroke(
        overlay,
        2.0,
        Stroke::new(1.0, STUDIO_BORDER),
        StrokeKind::Inside,
    );
    let lines = [
        "Top Orthographic".to_string(),
        format!("Grid: {snap_units} units"),
        format!("{} nodes", project.active_scene().nodes().len()),
        format!("{} resources", project.resources.len()),
        format!("{:.0} px/unit", zoom),
    ];
    for (idx, line) in lines.iter().enumerate() {
        painter.text(
            overlay.left_top() + Vec2::new(10.0, 10.0 + idx as f32 * 15.0),
            Align2::LEFT_TOP,
            line,
            FontId::monospace(11.0),
            STUDIO_TEXT,
        );
    }
}

fn draw_viewport_box_select_marquee(painter: &egui::Painter, rect: Option<Rect>) {
    let Some(rect) = rect else {
        return;
    };
    painter.rect_filled(
        rect,
        0.0,
        Color32::from_rgba_unmultiplied(255, 238, 150, 24),
    );
    painter.rect_stroke(
        rect,
        0.0,
        Stroke::new(2.0, EDITOR_OUTLINE_GOLD),
        StrokeKind::Outside,
    );
}

fn draw_axes_gizmo(painter: &egui::Painter, rect: Rect) {
    let origin = Pos2::new(rect.left() + 34.0, rect.bottom() - 38.0);
    let x_end = origin + Vec2::new(42.0, 0.0);
    let y_end = origin + Vec2::new(0.0, -42.0);
    let x_stroke = Stroke::new(2.0, Color32::from_rgb(220, 52, 46));
    let y_stroke = Stroke::new(2.0, Color32::from_rgb(108, 220, 92));

    painter.circle_filled(origin, 3.0, STUDIO_ACCENT);
    painter.line_segment([origin, x_end], x_stroke);
    painter.line_segment([origin, y_end], y_stroke);
    painter.line_segment([x_end, x_end + Vec2::new(-7.0, -4.0)], x_stroke);
    painter.line_segment([x_end, x_end + Vec2::new(-7.0, 4.0)], x_stroke);
    painter.line_segment([y_end, y_end + Vec2::new(-4.0, 7.0)], y_stroke);
    painter.line_segment([y_end, y_end + Vec2::new(4.0, 7.0)], y_stroke);
    painter.text(
        x_end + Vec2::new(8.0, 0.0),
        Align2::LEFT_CENTER,
        "X",
        FontId::monospace(12.0),
        Color32::from_rgb(255, 95, 88),
    );
    painter.text(
        y_end + Vec2::new(0.0, -8.0),
        Align2::CENTER_BOTTOM,
        "Y",
        FontId::monospace(12.0),
        Color32::from_rgb(140, 255, 128),
    );
}

#[derive(Debug, Clone, Copy)]
struct ViewportTransform {
    rect: Rect,
    pan: Vec2,
    zoom: f32,
}

impl ViewportTransform {
    fn new(rect: Rect, pan: Vec2, zoom: f32) -> Self {
        Self { rect, pan, zoom }
    }

    fn world_to_screen(self, world: [f32; 2]) -> Pos2 {
        self.rect.center() + self.pan + Vec2::new(world[0] * self.zoom, -world[1] * self.zoom)
    }

    fn screen_to_world(self, screen: Pos2) -> [f32; 2] {
        let delta = screen - self.rect.center() - self.pan;
        [delta.x / self.zoom, -delta.y / self.zoom]
    }

    fn world_rect_to_screen(self, center: [f32; 2], half: [f32; 2]) -> Rect {
        let min = [center[0] - half[0], center[1] - half[1]];
        let max = [center[0] + half[0], center[1] + half[1]];
        let a = self.world_to_screen(min);
        let b = self.world_to_screen(max);
        Rect::from_min_max(
            Pos2::new(a.x.min(b.x), a.y.min(b.y)),
            Pos2::new(a.x.max(b.x), a.y.max(b.y)),
        )
    }

    fn screen_radius(self, radius: f32) -> f32 {
        radius * self.zoom
    }
}

#[derive(Debug, Clone)]
struct ViewportHit {
    id: NodeId,
    shape: HitShape,
}

impl ViewportHit {
    fn rect(id: NodeId, _name: impl Into<String>, center: [f32; 2], half: [f32; 2]) -> Self {
        Self {
            id,
            shape: HitShape::Rect { center, half },
        }
    }

    fn circle(id: NodeId, _name: impl Into<String>, center: [f32; 2], radius: f32) -> Self {
        Self {
            id,
            shape: HitShape::Circle { center, radius },
        }
    }

    fn contains(&self, world: [f32; 2]) -> bool {
        match self.shape {
            HitShape::Rect { center, half } => {
                world[0] >= center[0] - half[0]
                    && world[0] <= center[0] + half[0]
                    && world[1] >= center[1] - half[1]
                    && world[1] <= center[1] + half[1]
            }
            HitShape::Circle { center, radius } => {
                let dx = world[0] - center[0];
                let dz = world[1] - center[1];
                dx * dx + dz * dz <= radius * radius
            }
        }
    }
}

#[derive(Debug, Clone, Copy)]
enum HitShape {
    Rect { center: [f32; 2], half: [f32; 2] },
    Circle { center: [f32; 2], radius: f32 },
}

fn draw_world_grid(painter: &egui::Painter, transform: ViewportTransform) {
    let rect = transform.rect;
    let top_left = transform.screen_to_world(rect.left_top());
    let bottom_right = transform.screen_to_world(rect.right_bottom());
    let min_x = top_left[0].min(bottom_right[0]).floor() as i32 - 1;
    let max_x = top_left[0].max(bottom_right[0]).ceil() as i32 + 1;
    let min_z = top_left[1].min(bottom_right[1]).floor() as i32 - 1;
    let max_z = top_left[1].max(bottom_right[1]).ceil() as i32 + 1;

    let minor = Stroke::new(1.0, Color32::from_rgb(20, 43, 52));
    let major = Stroke::new(1.0, Color32::from_rgb(31, 63, 75));
    let axis = Stroke::new(1.0, Color32::from_rgb(58, 91, 103));

    for x in min_x..=max_x {
        let stroke = if x == 0 {
            axis
        } else if x % 4 == 0 {
            major
        } else {
            minor
        };
        let a = transform.world_to_screen([x as f32, min_z as f32]);
        let b = transform.world_to_screen([x as f32, max_z as f32]);
        painter.line_segment([a, b], stroke);
    }

    for z in min_z..=max_z {
        let stroke = if z == 0 {
            axis
        } else if z % 4 == 0 {
            major
        } else {
            minor
        };
        let a = transform.world_to_screen([min_x as f32, z as f32]);
        let b = transform.world_to_screen([max_x as f32, z as f32]);
        painter.line_segment([a, b], stroke);
    }
}

fn draw_scene_viewport(
    painter: &egui::Painter,
    transform: ViewportTransform,
    project: &ProjectDocument,
    hidden_scene_nodes: &HashSet<NodeId>,
    selected: NodeId,
    selected_nodes: &HashSet<NodeId>,
    selected_sectors: &HashSet<SectorSelection>,
    validation_issue_primitives: &[Selection],
    validation_issue_rooms: &HashSet<NodeId>,
    show_portals: bool,
) -> Vec<ViewportHit> {
    let scene = project.active_scene();
    let mut hits = Vec::new();

    for node in scene.nodes() {
        if scene_node_hidden(scene, hidden_scene_nodes, node.id) {
            continue;
        }
        if matches!(node.kind, NodeKind::Room { .. }) {
            draw_room(
                painter,
                transform,
                project,
                node,
                selected_nodes.contains(&node.id)
                    || (selected_nodes.is_empty() && selected == node.id),
                selected_sectors,
                validation_issue_primitives,
                validation_issue_rooms,
                show_portals,
                &mut hits,
            );
        }
    }

    for node in scene.nodes() {
        if scene_node_hidden(scene, hidden_scene_nodes, node.id) {
            continue;
        }
        match &node.kind {
            NodeKind::MeshInstance { .. } => {
                draw_mesh_marker(
                    painter,
                    transform,
                    project,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    &mut hits,
                );
            }
            NodeKind::ImageProp { .. } => {
                draw_simple_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    "I",
                    Color32::from_rgb(210, 170, 120),
                    &mut hits,
                );
            }
            NodeKind::SpawnPoint { .. } => {
                draw_spawn_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    &mut hits,
                );
            }
            NodeKind::PointLight {
                color,
                intensity,
                radius,
            } => {
                draw_light_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    *color,
                    *intensity,
                    *radius,
                    &mut hits,
                );
            }
            NodeKind::Trigger { .. } => {
                draw_simple_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    "T",
                    Color32::from_rgb(180, 116, 230),
                    &mut hits,
                );
            }
            NodeKind::AudioSource { .. } => {
                draw_simple_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    "A",
                    Color32::from_rgb(70, 190, 165),
                    &mut hits,
                );
            }
            NodeKind::Portal { .. } if show_portals => {
                draw_portal_seam_2d(
                    painter,
                    transform,
                    scene,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                );
                draw_portal_marker(
                    painter,
                    transform,
                    scene,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    &mut hits,
                );
            }
            NodeKind::Node | NodeKind::Node3D if node.id != scene.root => {
                draw_simple_marker(
                    painter,
                    transform,
                    node,
                    selected_nodes.contains(&node.id)
                        || (selected_nodes.is_empty() && selected == node.id),
                    "N",
                    Color32::from_rgb(110, 124, 150),
                    &mut hits,
                );
            }
            _ => {}
        }
    }

    hits
}

fn draw_room(
    painter: &egui::Painter,
    transform: ViewportTransform,
    project: &ProjectDocument,
    node: &psxed_project::SceneNode,
    selected: bool,
    selected_sectors: &HashSet<SectorSelection>,
    validation_issue_primitives: &[Selection],
    validation_issue_rooms: &HashSet<NodeId>,
    show_portals: bool,
    hits: &mut Vec<ViewportHit>,
) {
    let NodeKind::Room { grid } = &node.kind else {
        return;
    };

    let node_center = node_world(node);
    let Some((local_center, half)) = grid_authored_editor_center_half(grid) else {
        return;
    };
    let center = [
        node_center[0] + local_center[0],
        node_center[1] + local_center[1],
    ];
    let outline = transform.world_rect_to_screen(center, half);
    hits.push(ViewportHit::rect(node.id, node.name.clone(), center, half));
    painter.rect_filled(outline, 0.0, darken(STUDIO_ROOM_FLOOR, 28));

    for x in 0..grid.width {
        for z in 0..grid.depth {
            let Some(sector) = grid.sector(x, z) else {
                continue;
            };
            if !sector.has_geometry() {
                continue;
            }
            let local_tile_center = grid_cell_editor_center(grid, x, z);
            let tile_center = [
                node_center[0] + local_tile_center[0],
                node_center[1] + local_tile_center[1],
            ];
            let screen_rect = transform.world_rect_to_screen(tile_center, [0.5, 0.5]);
            if !screen_rect.intersects(transform.rect) {
                continue;
            }
            if let Some(floor) = &sector.floor {
                let floor_color = material_color(project, floor.material, SurfaceRole::Floor);
                draw_floor_tile(
                    painter,
                    screen_rect,
                    floor_color,
                    x as i32,
                    z as i32,
                    floor.split,
                    floor.dropped_corner,
                );
            }
            if selected_sectors.contains(&(node.id, x, z)) {
                painter.rect_filled(
                    screen_rect.shrink(2.0),
                    0.0,
                    Color32::from_rgba_unmultiplied(255, 238, 150, 58),
                );
                painter.rect_stroke(
                    screen_rect.shrink(2.0),
                    0.0,
                    Stroke::new(EDITOR_SELECTED_OUTLINE_STROKE_WIDTH, EDITOR_OUTLINE_GOLD),
                    StrokeKind::Inside,
                );
            }
            hits.push(ViewportHit::rect(
                node.id,
                format!("{} sector {},{}", node.name, x, z),
                tile_center,
                [0.5, 0.5],
            ));
            draw_grid_sector_walls(painter, transform, project, tile_center, sector);
        }
    }

    if show_portals {
        draw_portal_room_boundaries_2d(painter, transform, project, node.id, grid, node_center);
    }
    draw_validation_issue_primitives_2d(
        painter,
        transform,
        grid,
        node.id,
        node_center,
        validation_issue_primitives,
    );
    painter.rect_stroke(outline, 0.0, selected_stroke(selected), StrokeKind::Outside);
    if validation_issue_rooms.contains(&node.id) {
        painter.rect_stroke(
            outline.expand(2.0),
            0.0,
            Stroke::new(4.0, Color32::from_rgb(255, 64, 64)),
            StrokeKind::Outside,
        );
    }
    painter.text(
        transform.world_to_screen([center[0] - half[0], center[1] + half[1]])
            + Vec2::new(8.0, -8.0),
        Align2::LEFT_BOTTOM,
        &node.name,
        FontId::monospace(12.0),
        Color32::from_rgb(230, 235, 245),
    );
}

fn draw_portal_room_boundaries_2d(
    painter: &egui::Painter,
    transform: ViewportTransform,
    project: &ProjectDocument,
    room_id: NodeId,
    grid: &WorldGrid,
    node_center: [f32; 2],
) {
    let plan = plan_portal_rooms(
        project.active_scene(),
        room_id,
        grid,
        PortalRoomConfig::default(),
    );
    if plan.room_count() <= 1 {
        return;
    }
    let stroke = Stroke::new(2.0, Color32::from_rgb(96, 255, 196));
    for portal_room in plan.rooms {
        let (local_center, chunk_half) =
            grid_rect_editor_center_half(grid, portal_room.array_origin, portal_room.size);
        let chunk_center = [
            node_center[0] + local_center[0],
            node_center[1] + local_center[1],
        ];
        let rect = transform.world_rect_to_screen(chunk_center, chunk_half);
        if rect.intersects(transform.rect) {
            painter.rect_stroke(rect, 0.0, stroke, StrokeKind::Inside);
        }
    }
}

fn draw_validation_issue_primitives_2d(
    painter: &egui::Painter,
    transform: ViewportTransform,
    grid: &WorldGrid,
    room: NodeId,
    node_center: [f32; 2],
    validation_issue_primitives: &[Selection],
) {
    for selection in validation_issue_primitives {
        let Selection::Face(face) = *selection else {
            continue;
        };
        if face.room != room || face.sx >= grid.width || face.sz >= grid.depth {
            continue;
        }

        let local_tile_center = grid_cell_editor_center(grid, face.sx, face.sz);
        let tile_center = [
            node_center[0] + local_tile_center[0],
            node_center[1] + local_tile_center[1],
        ];
        match face.kind {
            FaceKind::Floor | FaceKind::Ceiling => {
                let rect = transform.world_rect_to_screen(tile_center, [0.5, 0.5]);
                if rect.intersects(transform.rect) {
                    draw_validation_issue_rect(painter, rect);
                }
            }
            FaceKind::Wall { dir, .. } if dir.is_cardinal() => {
                if let Some((wall_center, wall_half)) = wall_band_center_half(tile_center, dir) {
                    let rect = transform.world_rect_to_screen(wall_center, wall_half);
                    if rect.intersects(transform.rect) {
                        draw_validation_issue_rect(painter, rect);
                    }
                }
            }
            FaceKind::Wall { dir, .. } => {
                draw_validation_issue_diagonal(painter, transform, tile_center, dir);
            }
        }
    }
}

fn draw_validation_issue_rect(painter: &egui::Painter, rect: Rect) {
    let fill = Color32::from_rgba_unmultiplied(255, 32, 32, 70);
    let stroke = Stroke::new(4.0, Color32::from_rgb(255, 64, 64));
    painter.rect_filled(rect, 0.0, fill);
    painter.rect_stroke(rect, 0.0, stroke, StrokeKind::Outside);
}

fn draw_validation_issue_diagonal(
    painter: &egui::Painter,
    transform: ViewportTransform,
    tile_center: [f32; 2],
    dir: GridDirection,
) {
    let min_x = tile_center[0] - 0.5;
    let min_z = tile_center[1] - 0.5;
    let (a, b) = match dir {
        GridDirection::NorthWestSouthEast => ([min_x, min_z + 1.0], [min_x + 1.0, min_z]),
        GridDirection::NorthEastSouthWest => ([min_x + 1.0, min_z + 1.0], [min_x, min_z]),
        _ => return,
    };
    let a = transform.world_to_screen(a);
    let b = transform.world_to_screen(b);
    painter.line_segment(
        [a, b],
        Stroke::new(7.0, Color32::from_rgba_unmultiplied(255, 32, 32, 92)),
    );
    painter.line_segment([a, b], Stroke::new(4.0, Color32::from_rgb(255, 64, 64)));
}

#[allow(clippy::too_many_arguments)]
fn draw_grid_sector_walls(
    painter: &egui::Painter,
    transform: ViewportTransform,
    project: &ProjectDocument,
    tile_center: [f32; 2],
    sector: &psxed_project::GridSector,
) {
    let min_x = tile_center[0] - 0.5;
    let min_z = tile_center[1] - 0.5;
    for direction in GridDirection::CARDINAL {
        let walls = sector.walls.get(direction);
        if walls.is_empty() {
            continue;
        }
        let material = walls.first().and_then(|wall| wall.material);
        let wall_color = material_color(project, material, SurfaceRole::Wall);
        let Some((wall_center, wall_half)) = wall_band_center_half(tile_center, direction) else {
            continue;
        };
        let screen_rect = transform.world_rect_to_screen(wall_center, wall_half);
        if screen_rect.intersects(transform.rect) {
            draw_wall_band(painter, screen_rect, wall_color);
            painter.rect_stroke(
                screen_rect,
                0.0,
                Stroke::new(1.0, Color32::from_rgb(84, 58, 44)),
                StrokeKind::Inside,
            );
        }
    }

    for (direction, nw_to_se) in [
        (GridDirection::NorthWestSouthEast, true),
        (GridDirection::NorthEastSouthWest, false),
    ] {
        if sector.walls.get(direction).is_empty() {
            continue;
        }
        let a = if nw_to_se {
            transform.world_to_screen([min_x, min_z + 1.0])
        } else {
            transform.world_to_screen([min_x + 1.0, min_z + 1.0])
        };
        let b = if nw_to_se {
            transform.world_to_screen([min_x + 1.0, min_z])
        } else {
            transform.world_to_screen([min_x, min_z])
        };
        painter.line_segment([a, b], Stroke::new(4.0, STUDIO_ROOM_WALL));
        painter.line_segment([a, b], Stroke::new(1.0, Color32::from_rgb(84, 58, 44)));
    }
}

fn wall_band_center_half(
    tile_center: [f32; 2],
    direction: GridDirection,
) -> Option<([f32; 2], [f32; 2])> {
    let wall_thickness = 0.18;
    let min_x = tile_center[0] - 0.5;
    let min_z = tile_center[1] - 0.5;
    match direction {
        GridDirection::North => Some((
            [min_x + 0.5, min_z + 1.0 + wall_thickness * 0.5],
            [0.5, wall_thickness * 0.5],
        )),
        GridDirection::East => Some((
            [min_x + 1.0 + wall_thickness * 0.5, min_z + 0.5],
            [wall_thickness * 0.5, 0.5],
        )),
        GridDirection::South => Some((
            [min_x + 0.5, min_z - wall_thickness * 0.5],
            [0.5, wall_thickness * 0.5],
        )),
        GridDirection::West => Some((
            [min_x - wall_thickness * 0.5, min_z + 0.5],
            [wall_thickness * 0.5, 0.5],
        )),
        _ => None,
    }
}

fn draw_floor_tile(
    painter: &egui::Painter,
    rect: Rect,
    base: Color32,
    ix: i32,
    iz: i32,
    split: GridSplit,
    dropped_corner: Option<Corner>,
) {
    let tint = if (ix + iz) % 2 == 0 {
        lighten(base, 8)
    } else {
        darken(base, 5)
    };
    painter.rect_filled(rect, 0.0, tint);
    painter.rect_stroke(
        rect,
        0.0,
        Stroke::new(1.0, Color32::from_rgba_unmultiplied(44, 56, 65, 168)),
        StrokeKind::Inside,
    );

    if rect.width() < 28.0 || rect.height() < 28.0 {
        return;
    }

    let mid_x = rect.center().x
        + if ix % 2 == 0 {
            -rect.width() * 0.12
        } else {
            rect.width() * 0.10
        };
    let mid_y = rect.center().y
        + if iz % 2 == 0 {
            rect.height() * 0.08
        } else {
            -rect.height() * 0.10
        };
    let crack = Stroke::new(1.0, Color32::from_rgba_unmultiplied(70, 80, 88, 150));
    painter.line_segment(
        [
            Pos2::new(mid_x, rect.top() + 5.0),
            Pos2::new(mid_x, rect.bottom() - 5.0),
        ],
        crack,
    );
    painter.line_segment(
        [
            Pos2::new(rect.left() + 5.0, mid_y),
            Pos2::new(rect.right() - 5.0, mid_y),
        ],
        crack,
    );
    draw_horizontal_split_line(painter, rect, split, dropped_corner);
}

fn draw_horizontal_split_line(
    painter: &egui::Painter,
    rect: Rect,
    split: GridSplit,
    dropped_corner: Option<Corner>,
) {
    if rect.width() < 20.0 || rect.height() < 20.0 {
        return;
    }
    let inset = 4.0;
    let nw = Pos2::new(rect.left() + inset, rect.top() + inset);
    let ne = Pos2::new(rect.right() - inset, rect.top() + inset);
    let se = Pos2::new(rect.right() - inset, rect.bottom() - inset);
    let sw = Pos2::new(rect.left() + inset, rect.bottom() - inset);
    let (a, b) = match split {
        GridSplit::NorthWestSouthEast => (nw, se),
        GridSplit::NorthEastSouthWest => (ne, sw),
    };
    let alpha = if dropped_corner.is_some() { 160 } else { 96 };
    painter.line_segment(
        [a, b],
        Stroke::new(1.5, Color32::from_rgba_unmultiplied(255, 238, 150, alpha)),
    );
}

fn draw_wall_band(painter: &egui::Painter, rect: Rect, base: Color32) {
    painter.rect_filled(rect, 0.0, darken(base, 4));
    let highlight = Stroke::new(1.0, Color32::from_rgba_unmultiplied(166, 92, 50, 160));
    let shadow = Stroke::new(1.0, Color32::from_rgba_unmultiplied(72, 42, 30, 180));

    if rect.width() >= rect.height() {
        let rows = (rect.height() / 7.0).max(2.0) as i32;
        for row in 1..rows {
            let y = rect.top() + row as f32 * rect.height() / rows as f32;
            painter.line_segment(
                [Pos2::new(rect.left(), y), Pos2::new(rect.right(), y)],
                if row % 2 == 0 { highlight } else { shadow },
            );
        }
        let cols = (rect.width() / 42.0).max(3.0) as i32;
        for col in 1..cols {
            let x = rect.left() + col as f32 * rect.width() / cols as f32;
            painter.line_segment(
                [
                    Pos2::new(x, rect.top() + 3.0),
                    Pos2::new(x, rect.bottom() - 3.0),
                ],
                shadow,
            );
        }
    } else {
        let cols = (rect.width() / 7.0).max(2.0) as i32;
        for col in 1..cols {
            let x = rect.left() + col as f32 * rect.width() / cols as f32;
            painter.line_segment(
                [Pos2::new(x, rect.top()), Pos2::new(x, rect.bottom())],
                if col % 2 == 0 { highlight } else { shadow },
            );
        }
        let rows = (rect.height() / 42.0).max(3.0) as i32;
        for row in 1..rows {
            let y = rect.top() + row as f32 * rect.height() / rows as f32;
            painter.line_segment(
                [
                    Pos2::new(rect.left() + 3.0, y),
                    Pos2::new(rect.right() - 3.0, y),
                ],
                shadow,
            );
        }
    }
}

fn draw_mesh_marker(
    painter: &egui::Painter,
    transform: ViewportTransform,
    project: &ProjectDocument,
    node: &psxed_project::SceneNode,
    selected: bool,
    hits: &mut Vec<ViewportHit>,
) {
    let NodeKind::MeshInstance { material, .. } = node.kind else {
        return;
    };
    let center = node_world(node);
    let half = [
        node.transform.scale[0].abs().max(0.35) * 0.5,
        node.transform.scale[2].abs().max(0.18) * 0.5,
    ];
    let rect = transform.world_rect_to_screen(center, half);
    let color = material_color(project, material, SurfaceRole::Object);
    let translucent = material_is_translucent(project, material);
    painter.rect_filled(rect, 0.0, color);
    if translucent {
        draw_glass_marker(painter, rect);
    }
    painter.rect_stroke(rect, 0.0, selected_stroke(selected), StrokeKind::Outside);
    painter.text(
        rect.center_top() + Vec2::new(0.0, -6.0),
        Align2::CENTER_BOTTOM,
        &node.name,
        FontId::monospace(11.0),
        Color32::from_rgb(232, 238, 246),
    );
    hits.push(ViewportHit::rect(node.id, node.name.clone(), center, half));
}

fn draw_glass_marker(painter: &egui::Painter, rect: Rect) {
    painter.rect_filled(
        rect.shrink(1.0),
        0.0,
        Color32::from_rgba_unmultiplied(190, 230, 232, 34),
    );
    let sheen = Stroke::new(1.0, Color32::from_rgba_unmultiplied(222, 252, 255, 120));
    let step = 18.0;
    let mut x = rect.left() - rect.height();
    while x < rect.right() {
        painter.line_segment(
            [
                Pos2::new(x, rect.bottom()),
                Pos2::new((x + rect.height()).min(rect.right()), rect.top()),
            ],
            sheen,
        );
        x += step;
    }
}

fn draw_spawn_marker(
    painter: &egui::Painter,
    transform: ViewportTransform,
    node: &psxed_project::SceneNode,
    selected: bool,
    hits: &mut Vec<ViewportHit>,
) {
    draw_simple_marker(
        painter,
        transform,
        node,
        selected,
        "P",
        Color32::from_rgb(82, 184, 118),
        hits,
    );
}

#[allow(clippy::too_many_arguments)]
fn draw_light_marker(
    painter: &egui::Painter,
    transform: ViewportTransform,
    node: &psxed_project::SceneNode,
    selected: bool,
    color: [u8; 3],
    intensity: f32,
    radius: f32,
    hits: &mut Vec<ViewportHit>,
) {
    let center = node_world(node);
    let world_radius = (radius / 4096.0).clamp(0.45, 2.5) * intensity.max(0.25);
    let screen_center = transform.world_to_screen(center);
    painter.circle_filled(
        screen_center,
        transform.screen_radius(world_radius),
        Color32::from_rgba_unmultiplied(color[0], color[1], color[2], 28),
    );
    let fill = Color32::from_rgb(color[0], color[1], color[2]);
    let icon_radius = transform.screen_radius(0.18).max(8.0);
    draw_light_bulb_marker(painter, screen_center, icon_radius, fill, selected);
    painter.text(
        screen_center + Vec2::new(0.0, 16.0),
        Align2::CENTER_TOP,
        &node.name,
        FontId::monospace(10.0),
        Color32::from_rgb(220, 228, 238),
    );
    hits.push(ViewportHit::circle(
        node.id,
        node.name.clone(),
        center,
        0.18_f32.max(8.0 / transform.zoom),
    ));
}

fn draw_light_bulb_marker(
    painter: &egui::Painter,
    center: Pos2,
    radius: f32,
    fill: Color32,
    selected: bool,
) {
    let glass_center = center + Vec2::new(0.0, -radius * 0.25);
    let glass_radius = radius * 0.72;
    let glass_fill = Color32::from_rgba_unmultiplied(fill.r(), fill.g(), fill.b(), 224);
    let stroke = selected_stroke(selected);
    painter.circle_filled(glass_center, glass_radius, glass_fill);
    painter.circle_stroke(glass_center, glass_radius, stroke);

    let base = Rect::from_center_size(
        center + Vec2::new(0.0, radius * 0.52),
        Vec2::new(radius * 0.86, radius * 0.52),
    );
    painter.rect_filled(base, 2.0, darken(fill, 46));
    painter.rect_stroke(base, 2.0, stroke, StrokeKind::Outside);

    let filament = Stroke::new(1.0, Color32::from_rgba_unmultiplied(18, 20, 24, 190));
    let y = glass_center.y + glass_radius * 0.18;
    let left = glass_center.x - glass_radius * 0.38;
    let right = glass_center.x + glass_radius * 0.38;
    let mid = glass_center.x;
    painter.line_segment(
        [Pos2::new(left, y), Pos2::new(mid, y + glass_radius * 0.18)],
        filament,
    );
    painter.line_segment(
        [Pos2::new(mid, y + glass_radius * 0.18), Pos2::new(right, y)],
        filament,
    );
}

fn draw_portal_seam_2d(
    painter: &egui::Painter,
    transform: ViewportTransform,
    scene: &psxed_project::Scene,
    node: &psxed_project::SceneNode,
    selected: bool,
) {
    let Some(room_id) = enclosing_room_id(scene, node.id) else {
        return;
    };
    let Some(room) = scene.node(room_id) else {
        return;
    };
    let NodeKind::Room { grid } = &room.kind else {
        return;
    };
    let seam = portal_seam_edges_for_node(grid, node);
    if seam.is_empty() {
        return;
    }
    let room_center = node_world(room);
    let halo = Stroke::new(
        if selected { 9.0 } else { 7.0 },
        Color32::from_rgba_unmultiplied(PORTAL_PINK.r(), PORTAL_PINK.g(), PORTAL_PINK.b(), 54),
    );
    let stroke = Stroke::new(if selected { 4.0 } else { 3.0 }, PORTAL_PINK);
    for edge in seam {
        draw_portal_edge_segment_2d(painter, transform, grid, room_center, edge, halo, stroke);
    }
    if let Some(edge) = portal_edge_for_node(grid, node) {
        if let Some((a, b)) = portal_edge_screen_segment(transform, grid, room_center, edge) {
            let mid = Pos2::new((a.x + b.x) * 0.5, (a.y + b.y) * 0.5);
            painter.circle_filled(mid, 4.5, PORTAL_PINK);
            painter.circle_stroke(mid, 5.5, Stroke::new(1.0, Color32::from_rgb(28, 8, 24)));
        }
    }
}

fn portal_edge_editor_segment(grid: &WorldGrid, edge: PortalEdge) -> Option<([f32; 2], [f32; 2])> {
    portal_edge_editor_segment_for_array(grid, edge.x, edge.z, edge.direction)
}

fn draw_portal_edge_segment_2d(
    painter: &egui::Painter,
    transform: ViewportTransform,
    grid: &WorldGrid,
    room_center: [f32; 2],
    edge: PortalEdge,
    halo: Stroke,
    stroke: Stroke,
) {
    let Some((a, b)) = portal_edge_screen_segment(transform, grid, room_center, edge) else {
        return;
    };
    painter.line_segment([a, b], halo);
    painter.line_segment([a, b], stroke);
}

fn portal_edge_screen_segment(
    transform: ViewportTransform,
    grid: &WorldGrid,
    room_center: [f32; 2],
    edge: PortalEdge,
) -> Option<(Pos2, Pos2)> {
    let (local_a, local_b) = portal_edge_editor_segment(grid, edge)?;
    Some((
        transform.world_to_screen([room_center[0] + local_a[0], room_center[1] + local_a[1]]),
        transform.world_to_screen([room_center[0] + local_b[0], room_center[1] + local_b[1]]),
    ))
}

fn portal_edge_editor_segment_for_array(
    grid: &WorldGrid,
    sx: u16,
    sz: u16,
    dir: GridDirection,
) -> Option<([f32; 2], [f32; 2])> {
    let wcx = grid.origin[0] + sx as i32;
    let wcz = grid.origin[1] + sz as i32;
    portal_edge_editor_segment_for_world_cell(grid, wcx, wcz, dir)
}

fn portal_edge_editor_segment_for_world_cell(
    grid: &WorldGrid,
    wcx: i32,
    wcz: i32,
    dir: GridDirection,
) -> Option<([f32; 2], [f32; 2])> {
    let world = match dir {
        GridDirection::North => (
            [wcx as f32, wcz as f32 + 1.0],
            [wcx as f32 + 1.0, wcz as f32 + 1.0],
        ),
        GridDirection::East => (
            [wcx as f32 + 1.0, wcz as f32],
            [wcx as f32 + 1.0, wcz as f32 + 1.0],
        ),
        GridDirection::South => ([wcx as f32, wcz as f32], [wcx as f32 + 1.0, wcz as f32]),
        GridDirection::West => ([wcx as f32, wcz as f32], [wcx as f32, wcz as f32 + 1.0]),
        GridDirection::NorthWestSouthEast | GridDirection::NorthEastSouthWest => return None,
    };
    Some((
        grid.world_cells_to_editor(world.0),
        grid.world_cells_to_editor(world.1),
    ))
}

fn draw_portal_marker(
    painter: &egui::Painter,
    transform: ViewportTransform,
    scene: &psxed_project::Scene,
    node: &psxed_project::SceneNode,
    selected: bool,
    hits: &mut Vec<ViewportHit>,
) {
    let center = portal_marker_world_2d(scene, node);
    let screen = transform.world_to_screen(center);
    let radius = transform.screen_radius(0.2).max(9.0);
    let points = vec![
        screen + Vec2::new(0.0, -radius),
        screen + Vec2::new(radius, 0.0),
        screen + Vec2::new(0.0, radius),
        screen + Vec2::new(-radius, 0.0),
    ];
    let fill =
        Color32::from_rgba_unmultiplied(PORTAL_PINK.r(), PORTAL_PINK.g(), PORTAL_PINK.b(), 64);
    painter.add(egui::Shape::convex_polygon(
        points,
        fill,
        Stroke::new(if selected { 3.0 } else { 1.5 }, PORTAL_PINK),
    ));
    painter.text(
        screen,
        Align2::CENTER_CENTER,
        "P",
        FontId::monospace(12.0),
        Color32::WHITE,
    );
    painter.text(
        screen + Vec2::new(0.0, radius + 5.0),
        Align2::CENTER_TOP,
        &node.name,
        FontId::monospace(10.0),
        PORTAL_PINK,
    );
    hits.push(ViewportHit::circle(
        node.id,
        node.name.clone(),
        center,
        0.2_f32.max(radius / transform.zoom),
    ));
}

fn portal_marker_world_2d(
    scene: &psxed_project::Scene,
    node: &psxed_project::SceneNode,
) -> [f32; 2] {
    let local = node_world(node);
    let Some(room_id) = enclosing_room_id(scene, node.id) else {
        return local;
    };
    let Some(room) = scene.node(room_id) else {
        return local;
    };
    let room_center = node_world(room);
    [room_center[0] + local[0], room_center[1] + local[1]]
}

fn draw_simple_marker(
    painter: &egui::Painter,
    transform: ViewportTransform,
    node: &psxed_project::SceneNode,
    selected: bool,
    label: &str,
    fill: Color32,
    hits: &mut Vec<ViewportHit>,
) {
    let center = node_world(node);
    let screen = transform.world_to_screen(center);
    let radius = 0.18;
    painter.circle_filled(screen, transform.screen_radius(radius).max(8.0), fill);
    painter.circle_stroke(
        screen,
        transform.screen_radius(radius).max(8.0),
        selected_stroke(selected),
    );
    painter.text(
        screen,
        Align2::CENTER_CENTER,
        label,
        FontId::monospace(12.0),
        Color32::from_rgb(8, 10, 13),
    );
    painter.text(
        screen + Vec2::new(0.0, 16.0),
        Align2::CENTER_TOP,
        &node.name,
        FontId::monospace(10.0),
        Color32::from_rgb(220, 228, 238),
    );
    hits.push(ViewportHit::circle(
        node.id,
        node.name.clone(),
        center,
        radius.max(8.0 / transform.zoom),
    ));
}

#[derive(Debug, Clone, Copy)]
enum SurfaceRole {
    Floor,
    Wall,
    Object,
}

fn material_color(
    project: &ProjectDocument,
    material: Option<ResourceId>,
    role: SurfaceRole,
) -> Color32 {
    let Some(id) = material else {
        return match role {
            SurfaceRole::Floor => STUDIO_ROOM_FLOOR,
            SurfaceRole::Wall => STUDIO_ROOM_WALL,
            SurfaceRole::Object => Color32::from_rgb(125, 155, 190),
        };
    };
    let Some(resource) = project.resource(id) else {
        return Color32::from_rgb(150, 80, 120);
    };

    let name = resource.name.to_ascii_lowercase();
    let mut color = if name.contains("brick") {
        Color32::from_rgb(126, 72, 43)
    } else if name.contains("floor") || name.contains("stone") {
        STUDIO_ROOM_FLOOR
    } else if name.contains("glass") {
        Color32::from_rgba_unmultiplied(122, 176, 198, 118)
    } else {
        match role {
            SurfaceRole::Floor => STUDIO_ROOM_FLOOR,
            SurfaceRole::Wall => STUDIO_ROOM_WALL,
            SurfaceRole::Object => Color32::from_rgb(125, 155, 190),
        }
    };

    if let ResourceData::Material(material) = &resource.data {
        if material.blend_mode != PsxBlendMode::Opaque {
            color = Color32::from_rgba_unmultiplied(color.r(), color.g(), color.b(), 132);
        }
    }

    color
}

fn material_is_translucent(project: &ProjectDocument, material: Option<ResourceId>) -> bool {
    material
        .and_then(|id| project.resource(id))
        .is_some_and(|resource| match &resource.data {
            ResourceData::Material(material) => material.blend_mode != PsxBlendMode::Opaque,
            _ => false,
        })
}

fn selected_stroke(selected: bool) -> Stroke {
    if selected {
        Stroke::new(EDITOR_SELECTED_OUTLINE_STROKE_WIDTH, EDITOR_OUTLINE_GOLD)
    } else {
        Stroke::new(1.0, Color32::from_rgb(70, 84, 108))
    }
}

fn node_world(node: &psxed_project::SceneNode) -> [f32; 2] {
    [node.transform.translation[0], node.transform.translation[2]]
}

fn room_grid_center_cells(scene: &psxed_project::Scene, room: NodeId) -> Option<[f32; 2]> {
    let node = scene.node(room)?;
    let NodeKind::Room { grid } = &node.kind else {
        return None;
    };
    Some(grid.grid_center_cells())
}

fn node_kind_uses_room_editor_position(kind: &NodeKind) -> bool {
    matches!(
        kind,
        NodeKind::Entity
            | NodeKind::MeshInstance { .. }
            | NodeKind::ImageProp { .. }
            | NodeKind::SpawnPoint { .. }
            | NodeKind::PointLight { .. }
            | NodeKind::Trigger { .. }
            | NodeKind::Portal { .. }
            | NodeKind::AudioSource { .. }
    )
}

fn recenter_room_spatial_descendants(
    scene: &mut psxed_project::Scene,
    room: NodeId,
    old_center: [f32; 2],
) {
    let Some(new_center) = room_grid_center_cells(scene, room) else {
        return;
    };
    let delta = [old_center[0] - new_center[0], old_center[1] - new_center[1]];
    if delta[0] == 0.0 && delta[1] == 0.0 {
        return;
    }
    let ids: Vec<NodeId> = scene
        .nodes()
        .iter()
        .filter(|node| node.id != room)
        .filter(|node| scene.is_descendant_of(node.id, room))
        .filter(|node| node_kind_uses_room_editor_position(&node.kind))
        .map(|node| node.id)
        .collect();
    for id in ids {
        if let Some(node) = scene.node_mut(id) {
            node.transform.translation[0] += delta[0];
            node.transform.translation[2] += delta[1];
        }
    }
}

fn extend_room_grid_to_include_preserving_child_positions(
    scene: &mut psxed_project::Scene,
    room: NodeId,
    wcx: i32,
    wcz: i32,
) -> Option<(u16, u16)> {
    let old_center = room_grid_center_cells(scene, room)?;
    let cell = {
        let node = scene.node_mut(room)?;
        let NodeKind::Room { grid } = &mut node.kind else {
            return None;
        };
        grid.extend_to_include(wcx, wcz)
    };
    recenter_room_spatial_descendants(scene, room, old_center);
    Some(cell)
}

fn resize_room_grid_preserving_child_positions(
    scene: &mut psxed_project::Scene,
    room: NodeId,
    width: u16,
    depth: u16,
) -> bool {
    let Some(old_center) = room_grid_center_cells(scene, room) else {
        return false;
    };
    let resized = {
        let Some(node) = scene.node_mut(room) else {
            return false;
        };
        let NodeKind::Room { grid } = &mut node.kind else {
            return false;
        };
        if grid.width == width && grid.depth == depth {
            return false;
        }
        grid.resize(width, depth);
        true
    };
    if resized {
        recenter_room_spatial_descendants(scene, room, old_center);
    }
    resized
}

fn grid_cell_editor_center(grid: &WorldGrid, sx: u16, sz: u16) -> [f32; 2] {
    [
        sx as f32 + 0.5 - grid.width as f32 * 0.5,
        sz as f32 + 0.5 - grid.depth as f32 * 0.5,
    ]
}

fn grid_rect_editor_center_half(
    grid: &WorldGrid,
    array_origin: [u16; 2],
    size: [u16; 2],
) -> ([f32; 2], [f32; 2]) {
    let half = [size[0] as f32 * 0.5, size[1] as f32 * 0.5];
    (
        [
            array_origin[0] as f32 + half[0] - grid.width as f32 * 0.5,
            array_origin[1] as f32 + half[1] - grid.depth as f32 * 0.5,
        ],
        half,
    )
}

fn grid_authored_editor_center_half(grid: &WorldGrid) -> Option<([f32; 2], [f32; 2])> {
    let footprint = grid.authored_footprint()?;
    Some(grid_rect_editor_center_half(
        grid,
        [footprint.x, footprint.z],
        [footprint.width, footprint.depth],
    ))
}

fn merge_bounds(bounds: &mut Option<(f32, f32, f32, f32)>, center: [f32; 2], half: [f32; 2]) {
    let next = (
        center[0] - half[0],
        center[1] - half[1],
        center[0] + half[0],
        center[1] + half[1],
    );
    *bounds = Some(match *bounds {
        Some((min_x, min_z, max_x, max_z)) => (
            min_x.min(next.0),
            min_z.min(next.1),
            max_x.max(next.2),
            max_z.max(next.3),
        ),
        None => next,
    });
}

fn bounds_to_center_half(bounds: (f32, f32, f32, f32)) -> ([f32; 2], [f32; 2]) {
    let (min_x, min_z, max_x, max_z) = bounds;
    (
        [(min_x + max_x) * 0.5, (min_z + max_z) * 0.5],
        [(max_x - min_x) * 0.5, (max_z - min_z) * 0.5],
    )
}

fn merge_bounds_3d(
    bounds: &mut Option<(f32, f32, f32, f32, f32, f32)>,
    center: [f32; 3],
    half: [f32; 3],
) {
    let next = (
        center[0] - half[0],
        center[1] - half[1],
        center[2] - half[2],
        center[0] + half[0],
        center[1] + half[1],
        center[2] + half[2],
    );
    *bounds = Some(match *bounds {
        Some((min_x, min_y, min_z, max_x, max_y, max_z)) => (
            min_x.min(next.0),
            min_y.min(next.1),
            min_z.min(next.2),
            max_x.max(next.3),
            max_y.max(next.4),
            max_z.max(next.5),
        ),
        None => next,
    });
}

fn bounds_3d_to_center_half(bounds: (f32, f32, f32, f32, f32, f32)) -> ([f32; 3], [f32; 3]) {
    let (min_x, min_y, min_z, max_x, max_y, max_z) = bounds;
    (
        [
            (min_x + max_x) * 0.5,
            (min_y + max_y) * 0.5,
            (min_z + max_z) * 0.5,
        ],
        [
            (max_x - min_x) * 0.5,
            (max_y - min_y) * 0.5,
            (max_z - min_z) * 0.5,
        ],
    )
}

fn command_shortcut(key: egui::Key) -> egui::KeyboardShortcut {
    egui::KeyboardShortcut::new(egui::Modifiers::COMMAND, key)
}

fn command_shift_shortcut(key: egui::Key) -> egui::KeyboardShortcut {
    egui::KeyboardShortcut::new(egui::Modifiers::COMMAND.plus(egui::Modifiers::SHIFT), key)
}

fn consume_command_shortcut(ctx: &egui::Context, key: egui::Key) -> bool {
    let shortcut = command_shortcut(key);
    ctx.input_mut(|input| input.consume_shortcut(&shortcut))
}

fn consume_command_shift_shortcut(ctx: &egui::Context, key: egui::Key) -> bool {
    let shortcut = command_shift_shortcut(key);
    ctx.input_mut(|input| input.consume_shortcut(&shortcut))
}

fn consume_command_cycle_shortcut(ctx: &egui::Context, key: egui::Key) -> Option<bool> {
    if consume_command_shift_shortcut(ctx, key) {
        Some(true)
    } else if consume_command_shortcut(ctx, key) {
        Some(false)
    } else {
        None
    }
}

fn command_shortcut_text(key: &str) -> String {
    if cfg!(target_os = "macos") {
        format!("Cmd+{key}")
    } else {
        format!("Ctrl+{key}")
    }
}

fn command_shift_shortcut_text(key: &str) -> String {
    if cfg!(target_os = "macos") {
        format!("Shift+Cmd+{key}")
    } else {
        format!("Shift+Ctrl+{key}")
    }
}

fn menu_label(label: &str, shortcut: &str) -> String {
    format!("{label}    {shortcut}")
}

fn bare_shortcuts_available(focus_taken: bool, modifiers: egui::Modifiers) -> bool {
    !focus_taken && !modifiers.command && !modifiers.ctrl
}

fn cycle_value<T: Copy + PartialEq>(values: &[T], current: T, reverse: bool) -> T {
    let Some(index) = values.iter().position(|value| *value == current) else {
        return values.first().copied().unwrap_or(current);
    };
    if values.is_empty() {
        return current;
    }
    let next = if reverse {
        (index + values.len() - 1) % values.len()
    } else {
        (index + 1) % values.len()
    };
    values[next]
}

fn frame_radius_for_3d_bounds(half: [f32; 3]) -> i32 {
    let extent = half[0].max(half[1]).max(half[2]).max(128.0);
    (extent * 3.2).clamp(512.0, 262_144.0) as i32
}

fn orbit_camera_position_f32(
    yaw_q12: u16,
    pitch_q12: u16,
    radius: i32,
    target: [i32; 3],
) -> [f32; 3] {
    let radius = radius as f32;
    let cos_p = cos_q12_turn_f32(pitch_q12);
    let sin_p = sin_q12_turn_f32(pitch_q12);
    let cos_y = cos_q12_turn_f32(yaw_q12);
    let sin_y = sin_q12_turn_f32(yaw_q12);
    [
        target[0] as f32 + radius * cos_p * sin_y,
        target[1] as f32 - radius * sin_p,
        target[2] as f32 + radius * cos_p * cos_y,
    ]
}

fn orbit_camera_position_i32(
    yaw_q12: u16,
    pitch_q12: u16,
    radius: i32,
    target: [i32; 3],
) -> [i32; 3] {
    orbit_camera_position_f32(yaw_q12, pitch_q12, radius, target).map(round_to_i32)
}

fn camera_forward_from_angles(yaw_q12: u16, pitch_q12: u16) -> [f32; 3] {
    let cos_p = cos_q12_turn_f32(pitch_q12);
    let sin_p = sin_q12_turn_f32(pitch_q12);
    let cos_y = cos_q12_turn_f32(yaw_q12);
    let sin_y = sin_q12_turn_f32(yaw_q12);
    normalize3([-cos_p * sin_y, sin_p, -cos_p * cos_y])
}

fn sin_q12_turn_f32(angle_q12: u16) -> f32 {
    psx_engine::Angle::from_q12(angle_q12).sin().raw() as f32 / 4096.0
}

fn cos_q12_turn_f32(angle_q12: u16) -> f32 {
    psx_engine::Angle::from_q12(angle_q12).cos().raw() as f32 / 4096.0
}

fn distance_i32(a: [i32; 3], b: [i32; 3]) -> i32 {
    let dx = (a[0] - b[0]) as f32;
    let dy = (a[1] - b[1]) as f32;
    let dz = (a[2] - b[2]) as f32;
    (dx.mul_add(dx, dy.mul_add(dy, dz * dz)).sqrt())
        .round()
        .clamp(0.0, i32::MAX as f32) as i32
}

fn camera_angles_to_look_at(position: [i32; 3], target: [i32; 3]) -> Option<(u16, u16)> {
    let dx = (target[0] - position[0]) as f32;
    let dy = (target[1] - position[1]) as f32;
    let dz = (target[2] - position[2]) as f32;
    let len = dx.mul_add(dx, dy.mul_add(dy, dz * dz)).sqrt();
    if !len.is_finite() || len <= f32::EPSILON {
        return None;
    }

    let dir = [dx / len, dy / len, dz / len];
    let yaw = q12_from_radians((-dir[0]).atan2(-dir[2]));
    let pitch =
        signed_to_q12(q12_signed_from_radians(dir[1].clamp(-1.0, 1.0).asin()).clamp(-960, 960));
    Some((yaw, pitch))
}

fn q12_from_radians(radians: f32) -> u16 {
    ((radians * (4096.0 / std::f32::consts::TAU)).round() as i32).rem_euclid(4096) as u16
}

fn q12_signed_from_radians(radians: f32) -> i32 {
    (radians * (4096.0 / std::f32::consts::TAU)).round() as i32
}

fn viewport_3d_pan_delta(
    camera: ViewportCameraState,
    panel_size: Vec2,
    pointer_delta: Vec2,
) -> [f32; 3] {
    let basis = camera.basis();
    let width = panel_size.x.max(1.0);
    let height = panel_size.y.max(1.0);
    let radius = (camera.radius as f32).max(1.0);
    let right = -pointer_delta.x * radius / width;
    let up = pointer_delta.y * radius * 0.75 / height;
    [
        basis.right[0] * right + basis.up[0] * up,
        basis.right[1] * right + basis.up[1] * up,
        basis.right[2] * right + basis.up[2] * up,
    ]
}

fn project_world_to_viewport_screen(
    camera: ViewportCameraState,
    viewport: Rect,
    world: [f32; 3],
) -> Option<Pos2> {
    let basis = camera.basis();
    let rel = sub3(world, basis.position);
    let depth = dot3(rel, basis.forward);
    if !depth.is_finite() || depth <= 1.0 {
        return None;
    }

    let half_fov_x: f32 = 0.5;
    let half_fov_y: f32 = 0.5 * 240.0 / 320.0;
    let nx = dot3(rel, basis.right) / (depth * half_fov_x);
    let ny = -dot3(rel, basis.up) / (depth * half_fov_y);
    if !nx.is_finite() || !ny.is_finite() {
        return None;
    }

    Some(Pos2::new(
        viewport.center().x + nx * viewport.width() * 0.5,
        viewport.center().y + ny * viewport.height() * 0.5,
    ))
}

fn distance_to_segment_2d(point: Pos2, a: Pos2, b: Pos2) -> f32 {
    let ab = b - a;
    let len_sq = ab.length_sq();
    if len_sq <= f32::EPSILON {
        return (point - a).length();
    }
    let t = ((point - a).dot(ab) / len_sq).clamp(0.0, 1.0);
    let closest = a + ab * t;
    (point - closest).length()
}

fn polygon_area_2d(points: &[Pos2]) -> f32 {
    if points.len() < 3 {
        return 0.0;
    }
    let mut area = 0.0;
    for i in 0..points.len() {
        let a = points[i];
        let b = points[(i + 1) % points.len()];
        area += a.x * b.y - b.x * a.y;
    }
    area * 0.5
}

fn point_in_polygon_2d(point: Pos2, polygon: &[Pos2]) -> bool {
    if polygon.len() < 3 {
        return false;
    }
    let mut inside = false;
    let mut j = polygon.len() - 1;
    for i in 0..polygon.len() {
        let a = polygon[i];
        let b = polygon[j];
        if (a.y > point.y) != (b.y > point.y) {
            let x = (b.x - a.x) * (point.y - a.y) / (b.y - a.y) + a.x;
            if point.x < x {
                inside = !inside;
            }
        }
        j = i;
    }
    inside
}

fn vec3_nearly_equal(a: [f32; 3], b: [f32; 3]) -> bool {
    (a[0] - b[0]).abs() < 0.001 && (a[1] - b[1]).abs() < 0.001 && (a[2] - b[2]).abs() < 0.001
}

fn round_to_i32(value: f32) -> i32 {
    value.round().clamp(i32::MIN as f32, i32::MAX as f32) as i32
}

fn add_q12_signed_clamped(value: u16, delta: i32, min: i32, max: i32) -> u16 {
    signed_to_q12((q12_to_signed(value) + delta).clamp(min, max))
}

fn q12_to_signed(value: u16) -> i32 {
    let raw = value as i32;
    if raw >= 2048 {
        raw - 4096
    } else {
        raw
    }
}

fn signed_to_q12(value: i32) -> u16 {
    value.rem_euclid(4096) as u16
}

fn cross3(a: [f32; 3], b: [f32; 3]) -> [f32; 3] {
    [
        a[1] * b[2] - a[2] * b[1],
        a[2] * b[0] - a[0] * b[2],
        a[0] * b[1] - a[1] * b[0],
    ]
}

fn normalize3(v: [f32; 3]) -> [f32; 3] {
    let len_sq = v[0] * v[0] + v[1] * v[1] + v[2] * v[2];
    if len_sq <= f32::EPSILON {
        return [0.0, 0.0, 1.0];
    }
    let inv = len_sq.sqrt().recip();
    [v[0] * inv, v[1] * inv, v[2] * inv]
}

fn sub3(a: [f32; 3], b: [f32; 3]) -> [f32; 3] {
    [a[0] - b[0], a[1] - b[1], a[2] - b[2]]
}

fn dot3(a: [f32; 3], b: [f32; 3]) -> f32 {
    a[0] * b[0] + a[1] * b[1] + a[2] * b[2]
}

/// Outcome of a primitive delete. `Removed` => the face is gone
/// (user selected a face or edge). `Triangulated` => one corner
/// was dropped and the face is still alive as a triangle.
/// `Missing` => the face / sector wasn't where the selection
/// thought it was (stale state) -- caller should leave things
/// alone.
enum DeleteOutcome {
    Removed(&'static str),
    Triangulated(&'static str),
    Missing,
}

/// Short label for a face kind, used in delete status messages.
const fn describe_face_kind(kind: FaceKind) -> &'static str {
    match kind {
        FaceKind::Floor => "floor",
        FaceKind::Ceiling => "ceiling",
        FaceKind::Wall { .. } => "wall",
    }
}

/// One-line human description of a `FaceRef` for status messages
/// and the inspector header. Walls include their cardinal direction
/// + stack index since a single edge can carry several stacked
///   walls (windows / arches).
fn describe_face(face: FaceRef) -> String {
    match face.kind {
        FaceKind::Floor => format!("Floor at {},{}", face.sx, face.sz),
        FaceKind::Ceiling => format!("Ceiling at {},{}", face.sx, face.sz),
        FaceKind::Wall { dir, stack } => {
            format!(
                "{} wall #{stack} at {},{}",
                direction_label(dir),
                face.sx,
                face.sz
            )
        }
    }
}

/// Status-line / breadcrumb text for any `Selection`. Falls
/// through to `describe_face` for face selections so existing
/// face copy stays identical.
pub fn describe_selection(selection: Selection) -> String {
    match selection {
        Selection::Face(face) => describe_face(face),
        Selection::Triangle(triangle) => describe_triangle(triangle),
        Selection::Edge(edge) => describe_edge(edge),
        Selection::Vertex(vertex) => describe_vertex(vertex),
    }
}

fn describe_triangle(triangle: HorizontalTriangleRef) -> String {
    let surface = match triangle.surface {
        HorizontalSurfaceKind::Floor => "Floor",
        HorizontalSurfaceKind::Ceiling => "Ceiling",
    };
    format!(
        "{surface} triangle {} at {},{}",
        triangle.index.label(),
        triangle.sx,
        triangle.sz
    )
}

fn describe_material_target(target: MaterialTarget) -> String {
    match target {
        MaterialTarget::Face(face) => describe_face(face),
        MaterialTarget::Triangle(triangle) => describe_triangle(triangle),
    }
}

fn selection_wall_face(selection: Selection) -> Option<FaceRef> {
    let Selection::Face(face) = selection else {
        return None;
    };
    matches!(face.kind, FaceKind::Wall { .. }).then_some(face)
}

fn selection_horizontal_face(selection: Selection, kind: FaceKind) -> Option<FaceRef> {
    let Selection::Face(face) = selection else {
        return None;
    };
    (face.kind == kind && matches!(face.kind, FaceKind::Floor | FaceKind::Ceiling)).then_some(face)
}

const fn horizontal_face_plural(kind: FaceKind) -> &'static str {
    match kind {
        FaceKind::Floor => "floors",
        FaceKind::Ceiling => "ceilings",
        FaceKind::Wall { .. } => "faces",
    }
}

fn selection_edge(selection: Selection) -> Option<EdgeRef> {
    let Selection::Edge(edge) = selection else {
        return None;
    };
    Some(edge)
}

fn wall_span_bounds(
    anchor: FaceRef,
    current: FaceRef,
    dir: GridDirection,
) -> Option<(u16, u16, u16, u16)> {
    match dir {
        GridDirection::North | GridDirection::South if anchor.sz == current.sz => Some((
            anchor.sx.min(current.sx),
            anchor.sx.max(current.sx),
            anchor.sz,
            anchor.sz,
        )),
        GridDirection::East | GridDirection::West if anchor.sx == current.sx => Some((
            anchor.sx,
            anchor.sx,
            anchor.sz.min(current.sz),
            anchor.sz.max(current.sz),
        )),
        _ => None,
    }
}

fn selection_sector(selection: Selection) -> (NodeId, u16, u16) {
    match selection {
        Selection::Face(face) => (face.room, face.sx, face.sz),
        Selection::Triangle(triangle) => (triangle.room, triangle.sx, triangle.sz),
        Selection::Edge(edge) => match edge.anchor {
            EdgeAnchor::Floor { sx, sz, .. }
            | EdgeAnchor::Ceiling { sx, sz, .. }
            | EdgeAnchor::Wall { sx, sz, .. } => (edge.room, sx, sz),
        },
        Selection::Vertex(vertex) => match vertex.anchor {
            VertexAnchor::Floor { sx, sz, .. }
            | VertexAnchor::Ceiling { sx, sz, .. }
            | VertexAnchor::Wall { sx, sz, .. } => (vertex.room, sx, sz),
        },
    }
}

fn describe_edge(edge: EdgeRef) -> String {
    match edge.anchor {
        EdgeAnchor::Floor { sx, sz, dir } => {
            format!("Floor {} edge at {sx},{sz}", direction_label(dir))
        }
        EdgeAnchor::Ceiling { sx, sz, dir } => {
            format!("Ceiling {} edge at {sx},{sz}", direction_label(dir))
        }
        EdgeAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            edge,
        } => format!(
            "{} wall #{stack} {} edge at {sx},{sz}",
            direction_label(dir),
            wall_edge_label(edge),
        ),
    }
}

fn describe_vertex(vertex: VertexRef) -> String {
    match vertex.anchor {
        VertexAnchor::Floor { sx, sz, corner } => {
            format!("Floor {} vertex at {sx},{sz}", corner_label(corner))
        }
        VertexAnchor::Ceiling { sx, sz, corner } => {
            format!("Ceiling {} vertex at {sx},{sz}", corner_label(corner))
        }
        VertexAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            corner,
        } => format!(
            "{} wall #{stack} {} vertex at {sx},{sz}",
            direction_label(dir),
            wall_corner_label(corner),
        ),
    }
}

fn push_unique_selection(selections: &mut Vec<Selection>, selection: Selection) {
    if !selections.contains(&selection) {
        selections.push(selection);
    }
}

fn push_unique_material_target(targets: &mut Vec<MaterialTarget>, target: MaterialTarget) {
    if !targets.contains(&target) {
        targets.push(target);
    }
}

fn autotile_selection_status(
    selected_tiles: usize,
    visited_walls: usize,
    updated_walls: usize,
    clamped_walls: usize,
) -> String {
    if visited_walls == 0 {
        return "No selected tiles have walls to autotile".to_string();
    }
    if updated_walls == 0 {
        return format!("Selected walls already autotiled across {selected_tiles} tile(s)");
    }
    let mut status =
        format!("Autotiled {updated_walls} wall(s) across {selected_tiles} selected tile(s)");
    if clamped_walls > 0 {
        status.push_str(&format!("; {clamped_walls} V span(s) clamped"));
    }
    status
}

fn face_edges(face: FaceRef) -> Vec<EdgeRef> {
    match face.kind {
        FaceKind::Floor => floor_edges(face.room, face.sx, face.sz, false),
        FaceKind::Ceiling => floor_edges(face.room, face.sx, face.sz, true),
        FaceKind::Wall { dir, stack } => [
            WallEdge::Bottom,
            WallEdge::Right,
            WallEdge::Top,
            WallEdge::Left,
        ]
        .into_iter()
        .map(|edge| EdgeRef {
            room: face.room,
            anchor: EdgeAnchor::Wall {
                sx: face.sx,
                sz: face.sz,
                dir,
                stack,
                edge,
            },
        })
        .collect(),
    }
}

fn triangle_edges(triangle: HorizontalTriangleRef) -> Vec<EdgeRef> {
    let mut edges = Vec::new();
    for idx in 0..3 {
        let a = triangle.corners[idx];
        let b = triangle.corners[(idx + 1) % 3];
        let Some(dir) = horizontal_edge_dir_from_corners(a, b) else {
            continue;
        };
        let anchor = match triangle.surface {
            HorizontalSurfaceKind::Floor => EdgeAnchor::Floor {
                sx: triangle.sx,
                sz: triangle.sz,
                dir,
            },
            HorizontalSurfaceKind::Ceiling => EdgeAnchor::Ceiling {
                sx: triangle.sx,
                sz: triangle.sz,
                dir,
            },
        };
        edges.push(EdgeRef {
            room: triangle.room,
            anchor,
        });
    }
    edges
}

fn floor_edges(room: NodeId, sx: u16, sz: u16, ceiling: bool) -> Vec<EdgeRef> {
    [
        GridDirection::North,
        GridDirection::East,
        GridDirection::South,
        GridDirection::West,
    ]
    .into_iter()
    .map(|dir| EdgeRef {
        room,
        anchor: if ceiling {
            EdgeAnchor::Ceiling { sx, sz, dir }
        } else {
            EdgeAnchor::Floor { sx, sz, dir }
        },
    })
    .collect()
}

fn face_vertices(face: FaceRef) -> Vec<VertexRef> {
    match face.kind {
        FaceKind::Floor => floor_vertices(face.room, face.sx, face.sz, false),
        FaceKind::Ceiling => floor_vertices(face.room, face.sx, face.sz, true),
        FaceKind::Wall { dir, stack } => [
            WallCorner::BL,
            WallCorner::BR,
            WallCorner::TR,
            WallCorner::TL,
        ]
        .into_iter()
        .map(|corner| VertexRef {
            room: face.room,
            anchor: VertexAnchor::Wall {
                sx: face.sx,
                sz: face.sz,
                dir,
                stack,
                corner,
            },
        })
        .collect(),
    }
}

fn triangle_vertices(triangle: HorizontalTriangleRef) -> Vec<VertexRef> {
    triangle
        .corners
        .into_iter()
        .map(|corner| {
            let anchor = match triangle.surface {
                HorizontalSurfaceKind::Floor => VertexAnchor::Floor {
                    sx: triangle.sx,
                    sz: triangle.sz,
                    corner,
                },
                HorizontalSurfaceKind::Ceiling => VertexAnchor::Ceiling {
                    sx: triangle.sx,
                    sz: triangle.sz,
                    corner,
                },
            };
            VertexRef {
                room: triangle.room,
                anchor,
            }
        })
        .collect()
}

fn floor_vertices(room: NodeId, sx: u16, sz: u16, ceiling: bool) -> Vec<VertexRef> {
    [Corner::NW, Corner::NE, Corner::SE, Corner::SW]
        .into_iter()
        .map(|corner| VertexRef {
            room,
            anchor: if ceiling {
                VertexAnchor::Ceiling { sx, sz, corner }
            } else {
                VertexAnchor::Floor { sx, sz, corner }
            },
        })
        .collect()
}

/// Adapter: face → its first edge (north for floor / ceiling,
/// bottom for walls). Used by mode-switch logic so a face
/// selection naturally promotes into one of its edges.
fn face_first_edge(face: FaceRef) -> EdgeRef {
    let anchor = match face.kind {
        FaceKind::Floor => EdgeAnchor::Floor {
            sx: face.sx,
            sz: face.sz,
            dir: GridDirection::North,
        },
        FaceKind::Ceiling => EdgeAnchor::Ceiling {
            sx: face.sx,
            sz: face.sz,
            dir: GridDirection::North,
        },
        FaceKind::Wall { dir, stack } => EdgeAnchor::Wall {
            sx: face.sx,
            sz: face.sz,
            dir,
            stack,
            edge: WallEdge::Bottom,
        },
    };
    EdgeRef {
        room: face.room,
        anchor,
    }
}

fn triangle_first_edge(triangle: HorizontalTriangleRef) -> EdgeRef {
    triangle_edges(triangle)
        .into_iter()
        .next()
        .unwrap_or_else(|| face_first_edge(triangle.parent_face()))
}

/// Adapter: face → its first vertex (NW for floor / ceiling,
/// BL for walls).
fn face_first_vertex(face: FaceRef) -> VertexRef {
    let anchor = match face.kind {
        FaceKind::Floor => VertexAnchor::Floor {
            sx: face.sx,
            sz: face.sz,
            corner: Corner::NW,
        },
        FaceKind::Ceiling => VertexAnchor::Ceiling {
            sx: face.sx,
            sz: face.sz,
            corner: Corner::NW,
        },
        FaceKind::Wall { dir, stack } => VertexAnchor::Wall {
            sx: face.sx,
            sz: face.sz,
            dir,
            stack,
            corner: WallCorner::BL,
        },
    };
    VertexRef {
        room: face.room,
        anchor,
    }
}

fn triangle_first_vertex(triangle: HorizontalTriangleRef) -> VertexRef {
    triangle_vertices(triangle)
        .into_iter()
        .next()
        .unwrap_or_else(|| face_first_vertex(triangle.parent_face()))
}

/// Adapter: edge → the face that owns it. Used when the user
/// switches from Edge mode back to Face mode and we don't want
/// to lose context.
fn edge_owning_face_ref(edge: EdgeRef) -> Option<FaceRef> {
    let kind = match edge.anchor {
        EdgeAnchor::Floor { .. } => FaceKind::Floor,
        EdgeAnchor::Ceiling { .. } => FaceKind::Ceiling,
        EdgeAnchor::Wall { dir, stack, .. } => FaceKind::Wall { dir, stack },
    };
    let (sx, sz) = match edge.anchor {
        EdgeAnchor::Floor { sx, sz, .. }
        | EdgeAnchor::Ceiling { sx, sz, .. }
        | EdgeAnchor::Wall { sx, sz, .. } => (sx, sz),
    };
    Some(FaceRef {
        room: edge.room,
        sx,
        sz,
        kind,
    })
}

/// Adapter: edge → its first endpoint vertex. Edge perimeter
/// convention: floor / ceiling north = NW-NE, east = NE-SE,
/// south = SE-SW, west = SW-NW. Wall bottom = BL-BR, right =
/// BR-TR, top = TR-TL, left = TL-BL. The "first" vertex is
/// the leading corner of that walk.
fn edge_first_vertex(edge: EdgeRef) -> VertexRef {
    let anchor = match edge.anchor {
        EdgeAnchor::Floor { sx, sz, dir } => VertexAnchor::Floor {
            sx,
            sz,
            corner: edge_first_floor_corner(dir),
        },
        EdgeAnchor::Ceiling { sx, sz, dir } => VertexAnchor::Ceiling {
            sx,
            sz,
            corner: edge_first_floor_corner(dir),
        },
        EdgeAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            edge,
        } => VertexAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            corner: edge_first_wall_corner(edge),
        },
    };
    VertexRef {
        room: edge.room,
        anchor,
    }
}

const fn edge_first_floor_corner(dir: GridDirection) -> Corner {
    match dir {
        GridDirection::North => Corner::NW,
        GridDirection::East => Corner::NE,
        GridDirection::South => Corner::SE,
        GridDirection::West => Corner::SW,
        GridDirection::NorthWestSouthEast => Corner::NW,
        GridDirection::NorthEastSouthWest => Corner::NE,
    }
}

const fn edge_first_wall_corner(edge: WallEdge) -> WallCorner {
    match edge {
        WallEdge::Bottom => WallCorner::BL,
        WallEdge::Right => WallCorner::BR,
        WallEdge::Top => WallCorner::TR,
        WallEdge::Left => WallCorner::TL,
    }
}

/// Adapter: vertex → owning face.
fn vertex_owning_face_ref(vertex: VertexRef) -> Option<FaceRef> {
    let kind = match vertex.anchor {
        VertexAnchor::Floor { .. } => FaceKind::Floor,
        VertexAnchor::Ceiling { .. } => FaceKind::Ceiling,
        VertexAnchor::Wall { dir, stack, .. } => FaceKind::Wall { dir, stack },
    };
    let (sx, sz) = match vertex.anchor {
        VertexAnchor::Floor { sx, sz, .. }
        | VertexAnchor::Ceiling { sx, sz, .. }
        | VertexAnchor::Wall { sx, sz, .. } => (sx, sz),
    };
    Some(FaceRef {
        room: vertex.room,
        sx,
        sz,
        kind,
    })
}

/// Adapter: vertex → one of the two edges it sits on. Picks
/// the first walking the perimeter from this corner.
fn vertex_first_edge(vertex: VertexRef) -> EdgeRef {
    let anchor = match vertex.anchor {
        VertexAnchor::Floor { sx, sz, corner } => EdgeAnchor::Floor {
            sx,
            sz,
            dir: floor_corner_first_edge(corner),
        },
        VertexAnchor::Ceiling { sx, sz, corner } => EdgeAnchor::Ceiling {
            sx,
            sz,
            dir: floor_corner_first_edge(corner),
        },
        VertexAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            corner,
        } => EdgeAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            edge: wall_corner_first_edge(corner),
        },
    };
    EdgeRef {
        room: vertex.room,
        anchor,
    }
}

const fn floor_corner_first_edge(corner: Corner) -> GridDirection {
    match corner {
        Corner::NW => GridDirection::North,
        Corner::NE => GridDirection::East,
        Corner::SE => GridDirection::South,
        Corner::SW => GridDirection::West,
    }
}

const fn wall_corner_first_edge(corner: WallCorner) -> WallEdge {
    match corner {
        WallCorner::BL => WallEdge::Bottom,
        WallCorner::BR => WallEdge::Right,
        WallCorner::TR => WallEdge::Top,
        WallCorner::TL => WallEdge::Left,
    }
}

const fn corner_label(corner: Corner) -> &'static str {
    match corner {
        Corner::NW => "NW",
        Corner::NE => "NE",
        Corner::SE => "SE",
        Corner::SW => "SW",
    }
}

const fn wall_corner_label(corner: WallCorner) -> &'static str {
    match corner {
        WallCorner::BL => "bottom-left",
        WallCorner::BR => "bottom-right",
        WallCorner::TR => "top-right",
        WallCorner::TL => "top-left",
    }
}

const fn wall_edge_label(edge: WallEdge) -> &'static str {
    match edge {
        WallEdge::Bottom => "bottom",
        WallEdge::Right => "right",
        WallEdge::Top => "top",
        WallEdge::Left => "left",
    }
}

fn direction_label(dir: GridDirection) -> &'static str {
    match dir {
        GridDirection::North => "North",
        GridDirection::East => "East",
        GridDirection::South => "South",
        GridDirection::West => "West",
        GridDirection::NorthWestSouthEast => "NW-SE",
        GridDirection::NorthEastSouthWest => "NE-SW",
    }
}

const fn next_cardinal_direction(dir: GridDirection) -> GridDirection {
    match dir {
        GridDirection::North => GridDirection::East,
        GridDirection::East => GridDirection::South,
        GridDirection::South => GridDirection::West,
        GridDirection::West
        | GridDirection::NorthWestSouthEast
        | GridDirection::NorthEastSouthWest => GridDirection::North,
    }
}

fn portal_edge_midpoint_editor(grid: &WorldGrid, sx: u16, sz: u16, dir: GridDirection) -> [f32; 2] {
    let wcx = grid.origin[0] + sx as i32;
    let wcz = grid.origin[1] + sz as i32;
    let world = match dir {
        GridDirection::North => [wcx as f32 + 0.5, wcz as f32 + 1.0],
        GridDirection::East => [wcx as f32 + 1.0, wcz as f32 + 0.5],
        GridDirection::South => [wcx as f32 + 0.5, wcz as f32],
        GridDirection::West => [wcx as f32, wcz as f32 + 0.5],
        GridDirection::NorthWestSouthEast | GridDirection::NorthEastSouthWest => {
            [wcx as f32 + 0.5, wcz as f32 + 0.5]
        }
    };
    grid.world_cells_to_editor(world)
}

fn portal_edge_valid_for_world_cell(
    grid: &WorldGrid,
    wcx: i32,
    wcz: i32,
    dir: GridDirection,
) -> bool {
    let Some((sx, sz)) = grid.world_cell_to_array(wcx, wcz) else {
        return false;
    };
    portal_edge_valid_for_array_cell(grid, sx, sz, dir)
}

fn portal_edge_valid_for_array_cell(
    grid: &WorldGrid,
    sx: u16,
    sz: u16,
    dir: GridDirection,
) -> bool {
    let Some((nx, nz)) = portal_edge_neighbour(sx, sz, dir) else {
        return false;
    };
    nx < grid.width
        && nz < grid.depth
        && grid.sector(sx, sz).is_some_and(GridSector::has_geometry)
        && grid.sector(nx, nz).is_some_and(GridSector::has_geometry)
}

fn canonical_portal_edge_for_array_cell(
    sx: u16,
    sz: u16,
    dir: GridDirection,
) -> Option<PortalEdge> {
    match dir {
        GridDirection::North => Some(PortalEdge {
            x: sx,
            z: sz,
            direction: GridDirection::North,
        }),
        GridDirection::East => Some(PortalEdge {
            x: sx,
            z: sz,
            direction: GridDirection::East,
        }),
        GridDirection::South => Some(PortalEdge {
            x: sx,
            z: sz.checked_sub(1)?,
            direction: GridDirection::North,
        }),
        GridDirection::West => Some(PortalEdge {
            x: sx.checked_sub(1)?,
            z: sz,
            direction: GridDirection::East,
        }),
        GridDirection::NorthWestSouthEast | GridDirection::NorthEastSouthWest => None,
    }
}

fn portal_edge_neighbour(sx: u16, sz: u16, dir: GridDirection) -> Option<(u16, u16)> {
    match dir {
        GridDirection::North => Some((sx, sz.checked_add(1)?)),
        GridDirection::East => Some((sx.checked_add(1)?, sz)),
        GridDirection::South => Some((sx, sz.checked_sub(1)?)),
        GridDirection::West => Some((sx.checked_sub(1)?, sz)),
        GridDirection::NorthWestSouthEast | GridDirection::NorthEastSouthWest => None,
    }
}

/// Pick the cardinal `GridDirection` for a wall edge given the
/// click offset from the cell's world-space centre. Mirrors the
/// renderer's `WallEdge` mapping in `editor_preview`:
/// `North = +Z`, `East = +X`, `South = -Z`, `West = -X`. The
/// dominant axis decides; ties favour the X axis.
fn edge_from_world_offset(dx: f32, dz: f32) -> GridDirection {
    psxed_project::spatial::editor_wall_direction_from_offset(dx, dz)
}

/// World-space integer position of `corner` in the room
/// described by `grid`. Returns `None` if the addressed face
/// no longer exists (cell out of bounds, geometry missing).
pub fn face_corner_world(grid: &WorldGrid, corner: FaceCornerRef) -> Option<[i32; 3]> {
    match corner {
        FaceCornerRef::Floor { sx, sz, corner } => {
            if sx >= grid.width || sz >= grid.depth {
                return None;
            }
            let face = grid.sector(sx, sz)?.floor.as_ref()?;
            Some(floor_corner_world(grid, sx, sz, corner, face.heights))
        }
        FaceCornerRef::FloorTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => {
            if sx >= grid.width || sz >= grid.depth {
                return None;
            }
            let face = grid.sector(sx, sz)?.floor.as_ref()?;
            triangle_corner_world(grid, sx, sz, face, triangle, corner)
        }
        FaceCornerRef::Ceiling { sx, sz, corner } => {
            if sx >= grid.width || sz >= grid.depth {
                return None;
            }
            let face = grid.sector(sx, sz)?.ceiling.as_ref()?;
            Some(floor_corner_world(grid, sx, sz, corner, face.heights))
        }
        FaceCornerRef::CeilingTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => {
            if sx >= grid.width || sz >= grid.depth {
                return None;
            }
            let face = grid.sector(sx, sz)?.ceiling.as_ref()?;
            triangle_corner_world(grid, sx, sz, face, triangle, corner)
        }
        FaceCornerRef::Wall {
            sx,
            sz,
            dir,
            stack,
            corner,
        } => {
            if sx >= grid.width || sz >= grid.depth {
                return None;
            }
            let walls = grid.sector(sx, sz)?.walls.get(dir);
            let wall = walls.get(stack as usize)?;
            wall_corner_world(grid, sx, sz, dir, corner, wall.heights)
        }
    }
}

fn triangle_corner_world(
    grid: &WorldGrid,
    sx: u16,
    sz: u16,
    face: &GridHorizontalFace,
    triangle: HorizontalTriangleIndex,
    corner: Corner,
) -> Option<[i32; 3]> {
    let corners = horizontal_triangle_corners(face.split, triangle);
    let slot = corners.iter().position(|candidate| *candidate == corner)?;
    let heights = face.triangle_heights(triangle.idx());
    let [x, z] = grid.cell_bounds_world(sx, sz).horizontal_corner_xz(corner);
    Some([x, heights[slot], z])
}

fn floor_corner_world(
    grid: &WorldGrid,
    sx: u16,
    sz: u16,
    corner: Corner,
    heights: [i32; 4],
) -> [i32; 3] {
    let [x, z] = grid.cell_bounds_world(sx, sz).horizontal_corner_xz(corner);
    [x, heights[corner.idx()], z]
}

fn horizontal_face_world_corners(bounds: GridCellBounds, heights: [i32; 4]) -> [[f32; 3]; 4] {
    let nw = bounds.horizontal_corner_xz(Corner::NW);
    let ne = bounds.horizontal_corner_xz(Corner::NE);
    let se = bounds.horizontal_corner_xz(Corner::SE);
    let sw = bounds.horizontal_corner_xz(Corner::SW);
    [
        [nw[0] as f32, heights[Corner::NW.idx()] as f32, nw[1] as f32],
        [ne[0] as f32, heights[Corner::NE.idx()] as f32, ne[1] as f32],
        [se[0] as f32, heights[Corner::SE.idx()] as f32, se[1] as f32],
        [sw[0] as f32, heights[Corner::SW.idx()] as f32, sw[1] as f32],
    ]
}

fn horizontal_triangle_world_corners(
    bounds: GridCellBounds,
    corners: [Corner; 3],
    heights: [i32; 3],
) -> [[f32; 3]; 3] {
    let point = |corner: Corner, height: i32| {
        let [x, z] = bounds.horizontal_corner_xz(corner);
        [x as f32, height as f32, z as f32]
    };
    [
        point(corners[0], heights[0]),
        point(corners[1], heights[1]),
        point(corners[2], heights[2]),
    ]
}

fn wall_corner_world(
    grid: &WorldGrid,
    sx: u16,
    sz: u16,
    dir: GridDirection,
    corner: WallCorner,
    heights: [i32; 4],
) -> Option<[i32; 3]> {
    let (bl, br) = grid.cell_bounds_world(sx, sz).wall_endpoints_xz(dir)?;
    let [x, z] = match corner {
        // BL / TL share the BL endpoint; BR / TR share BR.
        WallCorner::BL | WallCorner::TL => bl,
        WallCorner::BR | WallCorner::TR => br,
    };
    Some([x, heights[corner.idx()], z])
}

fn wall_face_world_corners(
    bounds: GridCellBounds,
    dir: GridDirection,
    heights: [i32; 4],
) -> Option<[[f32; 3]; 4]> {
    let (bl, br) = bounds.wall_endpoints_xz(dir)?;
    Some([
        [
            bl[0] as f32,
            heights[WallCorner::BL.idx()] as f32,
            bl[1] as f32,
        ],
        [
            br[0] as f32,
            heights[WallCorner::BR.idx()] as f32,
            br[1] as f32,
        ],
        [
            br[0] as f32,
            heights[WallCorner::TR.idx()] as f32,
            br[1] as f32,
        ],
        [
            bl[0] as f32,
            heights[WallCorner::TL.idx()] as f32,
            bl[1] as f32,
        ],
    ])
}

/// Universal coincidence resolver. Returns the physical vertex
/// containing `seed` -- every face-corner whose current world
/// position equals the seed's world position. Walks every
/// floor / ceiling / wall corner in the grid (`O(faces × 4)`,
/// runs in microseconds for 32×32 rooms).
pub fn physical_vertex(grid: &WorldGrid, seed: FaceCornerRef) -> Option<PhysicalVertex> {
    let world = face_corner_world(grid, seed)?;
    let mut members = Vec::new();
    for sx in 0..grid.width {
        for sz in 0..grid.depth {
            let Some(sector) = grid.sector(sx, sz) else {
                continue;
            };
            if sector.floor.is_some() {
                for c in [Corner::NW, Corner::NE, Corner::SE, Corner::SW] {
                    let r = FaceCornerRef::Floor { sx, sz, corner: c };
                    if face_corner_world(grid, r) == Some(world) {
                        members.push(r);
                    }
                }
            }
            if sector.ceiling.is_some() {
                for c in [Corner::NW, Corner::NE, Corner::SE, Corner::SW] {
                    let r = FaceCornerRef::Ceiling { sx, sz, corner: c };
                    if face_corner_world(grid, r) == Some(world) {
                        members.push(r);
                    }
                }
            }
            for dir in GridDirection::ALL {
                for (stack_idx, _) in sector.walls.get(dir).iter().enumerate() {
                    for c in [
                        WallCorner::BL,
                        WallCorner::BR,
                        WallCorner::TR,
                        WallCorner::TL,
                    ] {
                        let r = FaceCornerRef::Wall {
                            sx,
                            sz,
                            dir,
                            stack: stack_idx as u8,
                            corner: c,
                        };
                        if face_corner_world(grid, r) == Some(world) {
                            members.push(r);
                        }
                    }
                }
            }
        }
    }
    Some(PhysicalVertex { world, members })
}

fn detached_vertex(grid: &WorldGrid, seed: FaceCornerRef) -> Option<PhysicalVertex> {
    Some(PhysicalVertex {
        world: face_corner_world(grid, seed)?,
        members: vec![seed],
    })
}

fn vertex_for_seed(
    grid: &WorldGrid,
    seed: FaceCornerRef,
    connectivity: VertexConnectivity,
) -> Option<PhysicalVertex> {
    if matches!(
        seed,
        FaceCornerRef::FloorTriangle { .. } | FaceCornerRef::CeilingTriangle { .. }
    ) {
        return detached_vertex(grid, seed);
    }
    match connectivity {
        VertexConnectivity::Welded => physical_vertex(grid, seed),
        VertexConnectivity::Detached => detached_vertex(grid, seed),
    }
}

/// Face-corner seeds for a drag-translate stroke. The drag
/// engine resolves each seed through the active vertex
/// connectivity mode before applying height edits.
///
/// - Face: 4 corners of the face (preserves slope; same Δ on
///   each).
/// - Edge: 2 endpoint corners.
/// - Vertex: 1 corner.
fn drag_corner_seeds(selection: Selection) -> Option<Vec<FaceCornerRef>> {
    Some(match selection {
        Selection::Face(face) => match face.kind {
            FaceKind::Floor => [Corner::NW, Corner::NE, Corner::SE, Corner::SW]
                .iter()
                .map(|c| FaceCornerRef::Floor {
                    sx: face.sx,
                    sz: face.sz,
                    corner: *c,
                })
                .collect(),
            FaceKind::Ceiling => [Corner::NW, Corner::NE, Corner::SE, Corner::SW]
                .iter()
                .map(|c| FaceCornerRef::Ceiling {
                    sx: face.sx,
                    sz: face.sz,
                    corner: *c,
                })
                .collect(),
            FaceKind::Wall { dir, stack } => [
                WallCorner::BL,
                WallCorner::BR,
                WallCorner::TR,
                WallCorner::TL,
            ]
            .iter()
            .map(|c| FaceCornerRef::Wall {
                sx: face.sx,
                sz: face.sz,
                dir,
                stack,
                corner: *c,
            })
            .collect(),
        },
        Selection::Triangle(triangle) => triangle
            .corners
            .into_iter()
            .map(|corner| match triangle.surface {
                HorizontalSurfaceKind::Floor => FaceCornerRef::FloorTriangle {
                    sx: triangle.sx,
                    sz: triangle.sz,
                    triangle: triangle.index,
                    corner,
                },
                HorizontalSurfaceKind::Ceiling => FaceCornerRef::CeilingTriangle {
                    sx: triangle.sx,
                    sz: triangle.sz,
                    triangle: triangle.index,
                    corner,
                },
            })
            .collect(),
        Selection::Edge(edge) => {
            let (a, b) = edge_endpoint_corners(edge);
            vec![a, b]
        }
        Selection::Vertex(vertex) => vec![vertex.anchor.as_face_corner()],
    })
}

/// Pair of physical vertices that bound `edge`. Returns `None`
/// if either endpoint can't be resolved (face removed, cell
/// out of bounds).
pub fn edge_endpoints(grid: &WorldGrid, edge: EdgeRef) -> Option<(PhysicalVertex, PhysicalVertex)> {
    edge_endpoints_with_connectivity(grid, edge, VertexConnectivity::Welded)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EdgePathKind {
    Floor,
    Ceiling,
    Wall { stack: u8, edge: WallEdge },
}

fn edge_path_kind(edge: EdgeRef) -> EdgePathKind {
    match edge.anchor {
        EdgeAnchor::Floor { .. } => EdgePathKind::Floor,
        EdgeAnchor::Ceiling { .. } => EdgePathKind::Ceiling,
        EdgeAnchor::Wall { stack, edge, .. } => EdgePathKind::Wall { stack, edge },
    }
}

fn edge_world_segment(grid: &WorldGrid, edge: EdgeRef) -> Option<([i32; 3], [i32; 3])> {
    let (a, b) = edge_endpoint_corners(edge);
    Some((face_corner_world(grid, a)?, face_corner_world(grid, b)?))
}

fn edge_segments_touch(a: ([i32; 3], [i32; 3]), b: ([i32; 3], [i32; 3])) -> bool {
    a.0 == b.0 || a.0 == b.1 || a.1 == b.0 || a.1 == b.1
}

fn edge_endpoints_with_connectivity(
    grid: &WorldGrid,
    edge: EdgeRef,
    connectivity: VertexConnectivity,
) -> Option<(PhysicalVertex, PhysicalVertex)> {
    let (a, b) = edge_endpoint_corners(edge);
    let pa = vertex_for_seed(grid, a, connectivity)?;
    let pb = vertex_for_seed(grid, b, connectivity)?;
    Some((pa, pb))
}

/// Endpoint face-corners of `edge` as `(start, end)`. Order
/// matches the perimeter walk used elsewhere -- north = NW→NE,
/// east = NE→SE, etc.
fn edge_endpoint_corners(edge: EdgeRef) -> (FaceCornerRef, FaceCornerRef) {
    match edge.anchor {
        EdgeAnchor::Floor { sx, sz, dir } => {
            let (ca, cb) = floor_edge_endpoints(dir);
            (
                FaceCornerRef::Floor { sx, sz, corner: ca },
                FaceCornerRef::Floor { sx, sz, corner: cb },
            )
        }
        EdgeAnchor::Ceiling { sx, sz, dir } => {
            let (ca, cb) = floor_edge_endpoints(dir);
            (
                FaceCornerRef::Ceiling { sx, sz, corner: ca },
                FaceCornerRef::Ceiling { sx, sz, corner: cb },
            )
        }
        EdgeAnchor::Wall {
            sx,
            sz,
            dir,
            stack,
            edge,
        } => {
            let (ca, cb) = wall_edge_endpoints(edge);
            (
                FaceCornerRef::Wall {
                    sx,
                    sz,
                    dir,
                    stack,
                    corner: ca,
                },
                FaceCornerRef::Wall {
                    sx,
                    sz,
                    dir,
                    stack,
                    corner: cb,
                },
            )
        }
    }
}

const fn floor_edge_endpoints(dir: GridDirection) -> (Corner, Corner) {
    match dir {
        GridDirection::North => (Corner::NW, Corner::NE),
        GridDirection::East => (Corner::NE, Corner::SE),
        GridDirection::South => (Corner::SE, Corner::SW),
        GridDirection::West => (Corner::SW, Corner::NW),
        GridDirection::NorthWestSouthEast => (Corner::NW, Corner::SE),
        GridDirection::NorthEastSouthWest => (Corner::NE, Corner::SW),
    }
}

fn horizontal_edge_dir_from_corners(a: Corner, b: Corner) -> Option<GridDirection> {
    match (a, b) {
        (Corner::NW, Corner::NE) | (Corner::NE, Corner::NW) => Some(GridDirection::North),
        (Corner::NE, Corner::SE) | (Corner::SE, Corner::NE) => Some(GridDirection::East),
        (Corner::SE, Corner::SW) | (Corner::SW, Corner::SE) => Some(GridDirection::South),
        (Corner::SW, Corner::NW) | (Corner::NW, Corner::SW) => Some(GridDirection::West),
        (Corner::NW, Corner::SE) | (Corner::SE, Corner::NW) => {
            Some(GridDirection::NorthWestSouthEast)
        }
        (Corner::NE, Corner::SW) | (Corner::SW, Corner::NE) => {
            Some(GridDirection::NorthEastSouthWest)
        }
        _ => None,
    }
}

const fn wall_edge_endpoints(edge: WallEdge) -> (WallCorner, WallCorner) {
    match edge {
        WallEdge::Bottom => (WallCorner::BL, WallCorner::BR),
        WallEdge::Right => (WallCorner::BR, WallCorner::TR),
        WallEdge::Top => (WallCorner::TR, WallCorner::TL),
        WallEdge::Left => (WallCorner::TL, WallCorner::BL),
    }
}

/// Inspector member-list label.
fn face_corner_label(corner: FaceCornerRef) -> String {
    match corner {
        FaceCornerRef::Floor { sx, sz, corner } => {
            format!("Floor ({sx},{sz}) {}", corner_label(corner))
        }
        FaceCornerRef::FloorTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => format!(
            "Floor triangle {} ({sx},{sz}) {}",
            triangle.label(),
            corner_label(corner)
        ),
        FaceCornerRef::Ceiling { sx, sz, corner } => {
            format!("Ceiling ({sx},{sz}) {}", corner_label(corner))
        }
        FaceCornerRef::CeilingTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => format!(
            "Ceiling triangle {} ({sx},{sz}) {}",
            triangle.label(),
            corner_label(corner)
        ),
        FaceCornerRef::Wall {
            sx,
            sz,
            dir,
            stack,
            corner,
        } => format!(
            "{} wall #{stack} ({sx},{sz}) {}",
            direction_label(dir),
            wall_corner_label(corner)
        ),
    }
}

/// Apply a new Y to every member of `vertex`. X / Z are
/// preserved by construction -- `face_corner_world` returns the
/// current `(X, Y, Z)` and we only ever rewrite the corner's
/// height array entry.
pub fn apply_vertex_height(grid: &mut WorldGrid, vertex: &PhysicalVertex, new_y: i32) {
    let new_y = snap_height(new_y);
    for member in &vertex.members {
        write_face_corner_height(grid, *member, new_y);
    }
}

fn write_face_corner_height(grid: &mut WorldGrid, corner: FaceCornerRef, new_y: i32) {
    match corner {
        FaceCornerRef::Floor { sx, sz, corner } => {
            if let Some(sector) = grid.sector_mut(sx, sz) {
                if let Some(face) = sector.floor.as_mut() {
                    face.heights[corner.idx()] = new_y;
                }
            }
        }
        FaceCornerRef::FloorTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => {
            if let Some(sector) = grid.sector_mut(sx, sz) {
                if let Some(face) = sector.floor.as_mut() {
                    write_triangle_corner_height(face, triangle, corner, new_y);
                }
            }
        }
        FaceCornerRef::Ceiling { sx, sz, corner } => {
            if let Some(sector) = grid.sector_mut(sx, sz) {
                if let Some(face) = sector.ceiling.as_mut() {
                    face.heights[corner.idx()] = new_y;
                }
            }
        }
        FaceCornerRef::CeilingTriangle {
            sx,
            sz,
            triangle,
            corner,
        } => {
            if let Some(sector) = grid.sector_mut(sx, sz) {
                if let Some(face) = sector.ceiling.as_mut() {
                    write_triangle_corner_height(face, triangle, corner, new_y);
                }
            }
        }
        FaceCornerRef::Wall {
            sx,
            sz,
            dir,
            stack,
            corner,
        } => {
            if let Some(sector) = grid.sector_mut(sx, sz) {
                if let Some(wall) = sector.walls.get_mut(dir).get_mut(stack as usize) {
                    wall.heights[corner.idx()] = new_y;
                }
            }
        }
    }
}

fn write_triangle_corner_height(
    face: &mut GridHorizontalFace,
    triangle: HorizontalTriangleIndex,
    corner: Corner,
    new_y: i32,
) {
    let corners = horizontal_triangle_corners(face.split, triangle);
    let Some(slot) = corners.iter().position(|candidate| *candidate == corner) else {
        return;
    };
    face.triangle_heights_mut(triangle.idx())[slot] = new_y;
}

fn selection_copy_face(selection: Selection) -> Option<FaceRef> {
    selection.as_face().or_else(|| match selection {
        Selection::Edge(edge) => edge_owning_face_ref(edge),
        Selection::Vertex(vertex) => vertex_owning_face_ref(vertex),
        Selection::Face(_) | Selection::Triangle(_) => None,
    })
}

fn sector_fragment_for_selection(grid: &WorldGrid, selection: Selection) -> Option<GridSector> {
    let face = selection_copy_face(selection)?;
    let sector = grid.sector(face.sx, face.sz)?;
    let mut fragment = GridSector::empty();
    match face.kind {
        FaceKind::Floor => {
            fragment.floor = sector.floor.clone();
        }
        FaceKind::Ceiling => {
            fragment.ceiling = sector.ceiling.clone();
        }
        FaceKind::Wall { dir, stack } => {
            let wall = sector.walls.get(dir).get(stack as usize)?;
            fragment.walls.get_mut(dir).push(wall.clone());
        }
    }
    fragment.has_geometry().then_some(fragment)
}

fn merge_clipboard_fragment(target: &mut GridSector, fragment: GridSector) {
    if fragment.floor.is_some() {
        target.floor = fragment.floor;
    }
    if fragment.ceiling.is_some() {
        target.ceiling = fragment.ceiling;
    }
    for direction in GridDirection::ALL {
        for wall in fragment.walls.get(direction) {
            target.walls.get_mut(direction).push(wall.clone());
        }
    }
}

fn merge_primitive_fragment(
    target: &mut GridSector,
    fragment: GridSector,
    room: NodeId,
    sx: u16,
    sz: u16,
    selected: &mut Vec<Selection>,
) {
    if let Some(floor) = fragment.floor {
        target.floor = Some(floor);
        push_unique_selection(
            selected,
            Selection::Face(FaceRef {
                room,
                sx,
                sz,
                kind: FaceKind::Floor,
            }),
        );
    }
    if let Some(ceiling) = fragment.ceiling {
        target.ceiling = Some(ceiling);
        push_unique_selection(
            selected,
            Selection::Face(FaceRef {
                room,
                sx,
                sz,
                kind: FaceKind::Ceiling,
            }),
        );
    }
    for direction in GridDirection::ALL {
        for wall in fragment.walls.get(direction) {
            let Ok(stack) = u8::try_from(target.walls.get(direction).len()) else {
                continue;
            };
            target.walls.get_mut(direction).push(wall.clone());
            push_unique_selection(
                selected,
                Selection::Face(FaceRef {
                    room,
                    sx,
                    sz,
                    kind: FaceKind::Wall {
                        dir: direction,
                        stack,
                    },
                }),
            );
        }
    }
}

fn remove_primitive_faces_from_project(project: &mut ProjectDocument, targets: &[Selection]) {
    let mut faces = Vec::new();
    for &target in targets {
        let Some(face) = selection_copy_face(target) else {
            continue;
        };
        if !faces.contains(&face) {
            faces.push(face);
        }
    }
    faces.sort_by_key(primitive_remove_sort_key);
    for face in faces {
        let Some(node) = project.active_scene_mut().node_mut(face.room) else {
            continue;
        };
        let NodeKind::Room { grid } = &mut node.kind else {
            continue;
        };
        remove_face_from_grid(grid, face);
    }
}

fn primitive_remove_sort_key(face: &FaceRef) -> (u64, u16, u16, u8, u8, u8) {
    let (kind, direction, stack) = match face.kind {
        FaceKind::Floor => (0, 0, 0),
        FaceKind::Ceiling => (1, 0, 0),
        FaceKind::Wall { dir, stack } => (2, direction_sort_index(dir), u8::MAX - stack),
    };
    (face.room.raw(), face.sx, face.sz, kind, direction, stack)
}

const fn direction_sort_index(direction: GridDirection) -> u8 {
    match direction {
        GridDirection::North => 0,
        GridDirection::East => 1,
        GridDirection::South => 2,
        GridDirection::West => 3,
        GridDirection::NorthWestSouthEast => 4,
        GridDirection::NorthEastSouthWest => 5,
    }
}

fn remove_face_from_grid(grid: &mut WorldGrid, face: FaceRef) {
    let Some(sector) = grid.sector_mut(face.sx, face.sz) else {
        return;
    };
    match face.kind {
        FaceKind::Floor => {
            sector.floor = None;
        }
        FaceKind::Ceiling => {
            sector.ceiling = None;
        }
        FaceKind::Wall { dir, stack } => {
            let walls = sector.walls.get_mut(dir);
            let index = stack as usize;
            if index < walls.len() {
                walls.remove(index);
            }
        }
    }
}

fn transformed_geometry_cells(
    cells: &[GeometryClipboardCell],
    width: i32,
    height: i32,
    rotation_quarters: u8,
    flip_x: bool,
    flip_z: bool,
) -> Vec<([i32; 2], Option<GridSector>)> {
    let (rotated_width, rotated_height) =
        rotated_geometry_dimensions(width, height, rotation_quarters);
    cells
        .iter()
        .map(|cell| {
            let mut offset = rotate_cell_offset_cw(cell.offset, width, height, rotation_quarters);
            let mut sector = cell.sector.clone();
            if let Some(sector) = sector.as_mut() {
                for _ in 0..rotation_quarters % 4 {
                    *sector = rotate_sector_cw(sector);
                }
                if flip_x {
                    *sector = flip_sector_x(sector);
                }
                if flip_z {
                    *sector = flip_sector_z(sector);
                }
            }
            if flip_x {
                offset[0] = rotated_width - 1 - offset[0];
            }
            if flip_z {
                offset[1] = rotated_height - 1 - offset[1];
            }
            (offset, sector)
        })
        .collect()
}

fn rotated_geometry_dimensions(
    mut width: i32,
    mut height: i32,
    rotation_quarters: u8,
) -> (i32, i32) {
    if rotation_quarters % 2 == 1 {
        std::mem::swap(&mut width, &mut height);
    }
    (width, height)
}

fn rotate_cell_offset_cw(
    mut offset: [i32; 2],
    mut width: i32,
    mut height: i32,
    rotation_quarters: u8,
) -> [i32; 2] {
    for _ in 0..rotation_quarters % 4 {
        offset = [offset[1], width - 1 - offset[0]];
        std::mem::swap(&mut width, &mut height);
    }
    offset
}

fn rotate_sector_cw(sector: &GridSector) -> GridSector {
    let mut rotated = GridSector::empty();
    rotated.floor = sector.floor.clone().map(rotate_horizontal_face_cw);
    rotated.ceiling = sector.ceiling.clone().map(rotate_horizontal_face_cw);
    for direction in GridDirection::ALL {
        let rotated_direction = rotate_direction_cw(direction);
        for wall in sector.walls.get(direction) {
            rotated
                .walls
                .get_mut(rotated_direction)
                .push(rotate_vertical_face_cw(direction, wall.clone()));
        }
    }
    rotated
}

fn flip_sector_x(sector: &GridSector) -> GridSector {
    let mut flipped = GridSector::empty();
    flipped.floor = sector.floor.clone().map(flip_horizontal_face_x);
    flipped.ceiling = sector.ceiling.clone().map(flip_horizontal_face_x);
    for direction in GridDirection::ALL {
        let flipped_direction = flip_direction_x(direction);
        for wall in sector.walls.get(direction) {
            flipped
                .walls
                .get_mut(flipped_direction)
                .push(flip_vertical_face_x(direction, wall.clone()));
        }
    }
    flipped
}

fn flip_sector_z(sector: &GridSector) -> GridSector {
    let mut flipped = GridSector::empty();
    flipped.floor = sector.floor.clone().map(flip_horizontal_face_z);
    flipped.ceiling = sector.ceiling.clone().map(flip_horizontal_face_z);
    for direction in GridDirection::ALL {
        let flipped_direction = flip_direction_z(direction);
        for wall in sector.walls.get(direction) {
            flipped
                .walls
                .get_mut(flipped_direction)
                .push(flip_vertical_face_z(direction, wall.clone()));
        }
    }
    flipped
}

fn rotate_horizontal_face_cw(mut face: GridHorizontalFace) -> GridHorizontalFace {
    let old_heights = face.heights;
    let old_split = face.split;
    let old_overrides = face.triangle_overrides;
    face.heights = [
        old_heights[Corner::SW.idx()],
        old_heights[Corner::NW.idx()],
        old_heights[Corner::NE.idx()],
        old_heights[Corner::SE.idx()],
    ];
    face.split = rotate_split_cw(old_split);
    face.dropped_corner = face.dropped_corner.map(rotate_corner_cw);
    face.uv = rotate_uv_transform_cw(face.uv);

    for new_index in 0..2 {
        let old_index = rotated_horizontal_triangle_source_index(old_split, face.split, new_index);
        let mut triangle_override = *old_overrides.get(old_index);
        if let Some(uv) = triangle_override.uv.as_mut() {
            *uv = rotate_uv_transform_cw(*uv);
        }
        if let Some(heights) = triangle_override.heights {
            triangle_override.heights = Some(rotate_triangle_heights_cw(
                old_split, old_index, face.split, new_index, heights,
            ));
        }
        *face.triangle_override_mut(new_index) = triangle_override;
    }
    face
}

fn flip_horizontal_face_x(mut face: GridHorizontalFace) -> GridHorizontalFace {
    let old_heights = face.heights;
    face.heights = [
        old_heights[Corner::NE.idx()],
        old_heights[Corner::NW.idx()],
        old_heights[Corner::SW.idx()],
        old_heights[Corner::SE.idx()],
    ];
    flip_horizontal_face(face, flip_corner_x, flip_uv_transform_u)
}

fn flip_horizontal_face_z(mut face: GridHorizontalFace) -> GridHorizontalFace {
    let old_heights = face.heights;
    face.heights = [
        old_heights[Corner::SW.idx()],
        old_heights[Corner::SE.idx()],
        old_heights[Corner::NE.idx()],
        old_heights[Corner::NW.idx()],
    ];
    flip_horizontal_face(face, flip_corner_z, flip_uv_transform_v)
}

fn flip_horizontal_face(
    mut face: GridHorizontalFace,
    flip_corner: fn(Corner) -> Corner,
    flip_uv: fn(GridUvTransform) -> GridUvTransform,
) -> GridHorizontalFace {
    let old_split = face.split;
    let old_overrides = face.triangle_overrides;
    face.split = flip_split(old_split);
    face.dropped_corner = face.dropped_corner.map(flip_corner);
    face.uv = flip_uv(face.uv);

    for new_index in 0..2 {
        let old_index = transformed_horizontal_triangle_source_index(
            old_split,
            face.split,
            new_index,
            flip_corner,
        );
        let mut triangle_override = *old_overrides.get(old_index);
        if let Some(uv) = triangle_override.uv.as_mut() {
            *uv = flip_uv(*uv);
        }
        if let Some(heights) = triangle_override.heights {
            triangle_override.heights = Some(transform_triangle_heights(
                old_split,
                old_index,
                face.split,
                new_index,
                heights,
                flip_corner,
            ));
        }
        *face.triangle_override_mut(new_index) = triangle_override;
    }
    face
}

fn rotated_horizontal_triangle_source_index(
    old_split: GridSplit,
    new_split: GridSplit,
    new_index: usize,
) -> usize {
    transformed_horizontal_triangle_source_index(old_split, new_split, new_index, rotate_corner_cw)
}

fn transformed_horizontal_triangle_source_index(
    old_split: GridSplit,
    new_split: GridSplit,
    new_index: usize,
    transform_corner: fn(Corner) -> Corner,
) -> usize {
    let new_corners = psxed_project::horizontal_triangle_corners(new_split, new_index);
    for old_index in 0..2 {
        let old_corners =
            psxed_project::horizontal_triangle_corners(old_split, old_index).map(transform_corner);
        if same_corner_set(old_corners, new_corners) {
            return old_index;
        }
    }
    new_index
}

fn same_corner_set(a: [Corner; 3], b: [Corner; 3]) -> bool {
    a.iter().all(|corner| b.contains(corner))
}

fn rotate_triangle_heights_cw(
    old_split: GridSplit,
    old_index: usize,
    new_split: GridSplit,
    new_index: usize,
    old_heights: [i32; 3],
) -> [i32; 3] {
    transform_triangle_heights(
        old_split,
        old_index,
        new_split,
        new_index,
        old_heights,
        rotate_corner_cw,
    )
}

fn transform_triangle_heights(
    old_split: GridSplit,
    old_index: usize,
    new_split: GridSplit,
    new_index: usize,
    old_heights: [i32; 3],
    transform_corner: fn(Corner) -> Corner,
) -> [i32; 3] {
    let old_corners = psxed_project::horizontal_triangle_corners(old_split, old_index);
    let new_corners = psxed_project::horizontal_triangle_corners(new_split, new_index);
    let mut new_heights = old_heights;
    for (old_corner, height) in old_corners.into_iter().zip(old_heights) {
        let rotated_corner = transform_corner(old_corner);
        if let Some(slot) = new_corners
            .iter()
            .position(|corner| *corner == rotated_corner)
        {
            new_heights[slot] = height;
        }
    }
    new_heights
}

fn rotate_vertical_face_cw(
    direction: GridDirection,
    mut wall: GridVerticalFace,
) -> GridVerticalFace {
    let old_heights = wall.heights;
    let mut heights = [0; 4];
    for corner in [
        WallCorner::BL,
        WallCorner::BR,
        WallCorner::TR,
        WallCorner::TL,
    ] {
        let rotated_corner = rotate_wall_corner_cw(direction, corner);
        heights[rotated_corner.idx()] = old_heights[corner.idx()];
    }
    wall.heights = heights;
    wall.dropped_corner = wall
        .dropped_corner
        .map(|corner| rotate_wall_corner_cw(direction, corner));
    wall.uv = rotate_uv_transform_cw(wall.uv);
    wall
}

fn flip_vertical_face_x(direction: GridDirection, wall: GridVerticalFace) -> GridVerticalFace {
    flip_vertical_face(direction, wall, flip_wall_corner_x)
}

fn flip_vertical_face_z(direction: GridDirection, wall: GridVerticalFace) -> GridVerticalFace {
    flip_vertical_face(direction, wall, flip_wall_corner_z)
}

fn flip_vertical_face(
    direction: GridDirection,
    mut wall: GridVerticalFace,
    flip_corner: fn(GridDirection, WallCorner) -> WallCorner,
) -> GridVerticalFace {
    let old_heights = wall.heights;
    let mut heights = [0; 4];
    for corner in [
        WallCorner::BL,
        WallCorner::BR,
        WallCorner::TR,
        WallCorner::TL,
    ] {
        let flipped_corner = flip_corner(direction, corner);
        heights[flipped_corner.idx()] = old_heights[corner.idx()];
    }
    wall.heights = heights;
    wall.dropped_corner = wall
        .dropped_corner
        .map(|corner| flip_corner(direction, corner));
    wall.uv = flip_uv_transform_u(wall.uv);
    wall
}

const fn rotate_direction_cw(direction: GridDirection) -> GridDirection {
    match direction {
        GridDirection::North => GridDirection::East,
        GridDirection::East => GridDirection::South,
        GridDirection::South => GridDirection::West,
        GridDirection::West => GridDirection::North,
        GridDirection::NorthWestSouthEast => GridDirection::NorthEastSouthWest,
        GridDirection::NorthEastSouthWest => GridDirection::NorthWestSouthEast,
    }
}

const fn flip_direction_x(direction: GridDirection) -> GridDirection {
    match direction {
        GridDirection::North => GridDirection::North,
        GridDirection::East => GridDirection::West,
        GridDirection::South => GridDirection::South,
        GridDirection::West => GridDirection::East,
        GridDirection::NorthWestSouthEast => GridDirection::NorthEastSouthWest,
        GridDirection::NorthEastSouthWest => GridDirection::NorthWestSouthEast,
    }
}

const fn flip_direction_z(direction: GridDirection) -> GridDirection {
    match direction {
        GridDirection::North => GridDirection::South,
        GridDirection::East => GridDirection::East,
        GridDirection::South => GridDirection::North,
        GridDirection::West => GridDirection::West,
        GridDirection::NorthWestSouthEast => GridDirection::NorthEastSouthWest,
        GridDirection::NorthEastSouthWest => GridDirection::NorthWestSouthEast,
    }
}

const fn rotate_split_cw(split: GridSplit) -> GridSplit {
    flip_split(split)
}

const fn flip_split(split: GridSplit) -> GridSplit {
    match split {
        GridSplit::NorthWestSouthEast => GridSplit::NorthEastSouthWest,
        GridSplit::NorthEastSouthWest => GridSplit::NorthWestSouthEast,
    }
}

const fn rotate_corner_cw(corner: Corner) -> Corner {
    match corner {
        Corner::NW => Corner::NE,
        Corner::NE => Corner::SE,
        Corner::SE => Corner::SW,
        Corner::SW => Corner::NW,
    }
}

const fn flip_corner_x(corner: Corner) -> Corner {
    match corner {
        Corner::NW => Corner::NE,
        Corner::NE => Corner::NW,
        Corner::SE => Corner::SW,
        Corner::SW => Corner::SE,
    }
}

const fn flip_corner_z(corner: Corner) -> Corner {
    match corner {
        Corner::NW => Corner::SW,
        Corner::NE => Corner::SE,
        Corner::SE => Corner::NE,
        Corner::SW => Corner::NW,
    }
}

fn rotate_wall_corner_cw(direction: GridDirection, corner: WallCorner) -> WallCorner {
    let rotated_direction = rotate_direction_cw(direction);
    let (horizontal_corner, top) = wall_corner_horizontal_endpoint(direction, corner);
    let rotated_corner = rotate_corner_cw(horizontal_corner);
    wall_corner_from_horizontal_endpoint(rotated_direction, rotated_corner, top).unwrap_or(corner)
}

fn flip_wall_corner_x(direction: GridDirection, corner: WallCorner) -> WallCorner {
    let flipped_direction = flip_direction_x(direction);
    let (horizontal_corner, top) = wall_corner_horizontal_endpoint(direction, corner);
    let flipped_corner = flip_corner_x(horizontal_corner);
    wall_corner_from_horizontal_endpoint(flipped_direction, flipped_corner, top).unwrap_or(corner)
}

fn flip_wall_corner_z(direction: GridDirection, corner: WallCorner) -> WallCorner {
    let flipped_direction = flip_direction_z(direction);
    let (horizontal_corner, top) = wall_corner_horizontal_endpoint(direction, corner);
    let flipped_corner = flip_corner_z(horizontal_corner);
    wall_corner_from_horizontal_endpoint(flipped_direction, flipped_corner, top).unwrap_or(corner)
}

const fn wall_corner_horizontal_endpoint(
    direction: GridDirection,
    corner: WallCorner,
) -> (Corner, bool) {
    let (bl, br) = wall_direction_endpoint_corners(direction);
    match corner {
        WallCorner::BL => (bl, false),
        WallCorner::BR => (br, false),
        WallCorner::TR => (br, true),
        WallCorner::TL => (bl, true),
    }
}

const fn wall_direction_endpoint_corners(direction: GridDirection) -> (Corner, Corner) {
    match direction {
        GridDirection::North => (Corner::NW, Corner::NE),
        GridDirection::East => (Corner::NE, Corner::SE),
        GridDirection::South => (Corner::SE, Corner::SW),
        GridDirection::West => (Corner::SW, Corner::NW),
        GridDirection::NorthWestSouthEast => (Corner::NW, Corner::SE),
        GridDirection::NorthEastSouthWest => (Corner::NE, Corner::SW),
    }
}

fn wall_corner_from_horizontal_endpoint(
    direction: GridDirection,
    corner: Corner,
    top: bool,
) -> Option<WallCorner> {
    let (bl, br) = wall_direction_endpoint_corners(direction);
    if corner == bl {
        Some(if top { WallCorner::TL } else { WallCorner::BL })
    } else if corner == br {
        Some(if top { WallCorner::TR } else { WallCorner::BR })
    } else {
        None
    }
}

fn rotate_uv_transform_cw(mut uv: GridUvTransform) -> GridUvTransform {
    uv.rotation = rotate_uv_rotation_cw(uv.rotation);
    uv
}

fn flip_uv_transform_u(mut uv: GridUvTransform) -> GridUvTransform {
    uv.flip_u = !uv.flip_u;
    uv
}

fn flip_uv_transform_v(mut uv: GridUvTransform) -> GridUvTransform {
    uv.flip_v = !uv.flip_v;
    uv
}

const fn rotate_uv_rotation_cw(rotation: GridUvRotation) -> GridUvRotation {
    match rotation {
        GridUvRotation::Deg0 => GridUvRotation::Deg90,
        GridUvRotation::Deg90 => GridUvRotation::Deg180,
        GridUvRotation::Deg180 => GridUvRotation::Deg270,
        GridUvRotation::Deg270 => GridUvRotation::Deg0,
    }
}

fn horizontal_triangle_index_at_local(
    local_x: f32,
    local_z: f32,
    sector_size: i32,
    split: GridSplit,
) -> HorizontalTriangleIndex {
    let size = sector_size.max(1) as f32;
    match split {
        GridSplit::NorthWestSouthEast => {
            if local_x + local_z >= size {
                HorizontalTriangleIndex::A
            } else {
                HorizontalTriangleIndex::B
            }
        }
        GridSplit::NorthEastSouthWest => {
            if local_z >= local_x {
                HorizontalTriangleIndex::A
            } else {
                HorizontalTriangleIndex::B
            }
        }
    }
}

const fn horizontal_triangle_other(index: HorizontalTriangleIndex) -> HorizontalTriangleIndex {
    match index {
        HorizontalTriangleIndex::A => HorizontalTriangleIndex::B,
        HorizontalTriangleIndex::B => HorizontalTriangleIndex::A,
    }
}

const fn horizontal_triangle_corners(
    split: GridSplit,
    index: HorizontalTriangleIndex,
) -> [Corner; 3] {
    psxed_project::horizontal_triangle_corners(split, horizontal_triangle_index_usize(index))
}

const fn horizontal_triangle_index_usize(index: HorizontalTriangleIndex) -> usize {
    match index {
        HorizontalTriangleIndex::A => 0,
        HorizontalTriangleIndex::B => 1,
    }
}

const fn horizontal_triangle_delete_corner(
    split: GridSplit,
    index: HorizontalTriangleIndex,
) -> Corner {
    match (split, index) {
        (GridSplit::NorthWestSouthEast, HorizontalTriangleIndex::A) => Corner::NE,
        (GridSplit::NorthWestSouthEast, HorizontalTriangleIndex::B) => Corner::SW,
        (GridSplit::NorthEastSouthWest, HorizontalTriangleIndex::A) => Corner::NW,
        (GridSplit::NorthEastSouthWest, HorizontalTriangleIndex::B) => Corner::SE,
    }
}

/// Wall-quad triangle decomposition. The diagonal flips when
/// the dropped corner sits on the BL-TR line -- `BL` / `TR`
/// trigger the BR-TL diagonal.
type WallTri = ([f32; 3], [f32; 3], [f32; 3], [WallCorner; 3]);
fn wall_triangles(
    bl: [f32; 3],
    br: [f32; 3],
    tr: [f32; 3],
    tl: [f32; 3],
    dropped: Option<WallCorner>,
) -> [WallTri; 2] {
    let use_br_tl = matches!(dropped, Some(WallCorner::BL) | Some(WallCorner::TR));
    if use_br_tl {
        [
            (bl, br, tl, [WallCorner::BL, WallCorner::BR, WallCorner::TL]),
            (br, tr, tl, [WallCorner::BR, WallCorner::TR, WallCorner::TL]),
        ]
    } else {
        [
            (bl, br, tr, [WallCorner::BL, WallCorner::BR, WallCorner::TR]),
            (bl, tr, tl, [WallCorner::BL, WallCorner::TR, WallCorner::TL]),
        ]
    }
}

fn material_sidedness(
    project: &ProjectDocument,
    material: Option<ResourceId>,
) -> MaterialFaceSidedness {
    material
        .and_then(|id| project.resource(id))
        .and_then(|resource| match &resource.data {
            ResourceData::Material(material) => Some(material.sidedness()),
            _ => None,
        })
        .unwrap_or_default()
}

fn wall_material_sidedness(sidedness: MaterialFaceSidedness) -> MaterialFaceSidedness {
    match sidedness {
        MaterialFaceSidedness::Front => MaterialFaceSidedness::Back,
        MaterialFaceSidedness::Back => MaterialFaceSidedness::Front,
        MaterialFaceSidedness::Both => MaterialFaceSidedness::Both,
    }
}

fn wall_side_visible_from_camera(
    sidedness: MaterialFaceSidedness,
    bounds: GridCellBounds,
    direction: GridDirection,
    camera_position: [f32; 3],
) -> bool {
    let sidedness = wall_material_sidedness(sidedness);
    let cam_x = camera_position[0];
    let cam_z = camera_position[2];
    let inside_distance = match direction {
        GridDirection::North => bounds.z1 as f32 - cam_z,
        GridDirection::East => bounds.x1 as f32 - cam_x,
        GridDirection::South => cam_z - bounds.z0 as f32,
        GridDirection::West => cam_x - bounds.x0 as f32,
        GridDirection::NorthWestSouthEast | GridDirection::NorthEastSouthWest => return true,
    };
    match sidedness {
        MaterialFaceSidedness::Both => true,
        MaterialFaceSidedness::Back => inside_distance >= 0.0,
        MaterialFaceSidedness::Front => inside_distance <= 0.0,
    }
}

/// Index of the corner closest (3D distance) to `hit` among
/// `corners`. Caller is responsible for the corner ordering
/// convention -- `[NW, NE, SE, SW]` for floors / ceilings,
/// `[BL, BR, TR, TL]` for walls, or triangle perimeter order.
fn closest_corner_idx<const N: usize>(corners: &[[f32; 3]; N], hit: [f32; 3]) -> usize {
    let mut best = 0usize;
    let mut best_d2 = f32::INFINITY;
    for (i, c) in corners.iter().enumerate() {
        let d2 = dist2_3d(*c, hit);
        if d2 < best_d2 {
            best = i;
            best_d2 = d2;
        }
    }
    best
}

/// Index of the edge closest to `hit`. Edge `i` runs
/// `corners[i] → corners[(i+1) % N]`.
fn closest_edge_idx<const N: usize>(corners: &[[f32; 3]; N], hit: [f32; 3]) -> usize {
    let mut best = 0usize;
    let mut best_d2 = f32::INFINITY;
    for i in 0..N {
        let a = corners[i];
        let b = corners[(i + 1) % N];
        let d2 = point_segment_dist2(hit, a, b);
        if d2 < best_d2 {
            best = i;
            best_d2 = d2;
        }
    }
    best
}

fn dist2_3d(a: [f32; 3], b: [f32; 3]) -> f32 {
    let dx = a[0] - b[0];
    let dy = a[1] - b[1];
    let dz = a[2] - b[2];
    dx * dx + dy * dy + dz * dz
}

/// Squared distance from point `p` to the segment `a-b`.
fn point_segment_dist2(p: [f32; 3], a: [f32; 3], b: [f32; 3]) -> f32 {
    let ab = [b[0] - a[0], b[1] - a[1], b[2] - a[2]];
    let ap = [p[0] - a[0], p[1] - a[1], p[2] - a[2]];
    let len2 = ab[0] * ab[0] + ab[1] * ab[1] + ab[2] * ab[2];
    let t = if len2 > 0.0 {
        ((ap[0] * ab[0] + ap[1] * ab[1] + ap[2] * ab[2]) / len2).clamp(0.0, 1.0)
    } else {
        0.0
    };
    let q = [a[0] + ab[0] * t, a[1] + ab[1] * t, a[2] + ab[2] * t];
    dist2_3d(q, p)
}

/// Floor / ceiling corner index `0..3` → `Corner` (NW, NE,
/// SE, SW in perimeter order).
const fn floor_corner_idx(idx: usize) -> Corner {
    match idx {
        0 => Corner::NW,
        1 => Corner::NE,
        2 => Corner::SE,
        _ => Corner::SW,
    }
}

const fn wall_corner_idx(idx: usize) -> WallCorner {
    match idx {
        0 => WallCorner::BL,
        1 => WallCorner::BR,
        2 => WallCorner::TR,
        _ => WallCorner::TL,
    }
}

/// Floor / ceiling edge index `0..3` → cardinal `GridDirection`.
const fn floor_edge_dir(idx: usize) -> GridDirection {
    match idx {
        0 => GridDirection::North,
        1 => GridDirection::East,
        2 => GridDirection::South,
        _ => GridDirection::West,
    }
}

const fn wall_edge_idx(idx: usize) -> WallEdge {
    match idx {
        0 => WallEdge::Bottom,
        1 => WallEdge::Right,
        2 => WallEdge::Top,
        _ => WallEdge::Left,
    }
}

/// Möller-Trumbore ray-triangle intersection. Returns the ray
/// parameter `t`, or `None` for misses / degenerate triangles.
fn ray_triangle(
    orig: [f32; 3],
    dir: [f32; 3],
    v0: [f32; 3],
    v1: [f32; 3],
    v2: [f32; 3],
) -> Option<f32> {
    let edge1 = sub3(v1, v0);
    let edge2 = sub3(v2, v0);
    let h = cross3(dir, edge2);
    let a = dot3(edge1, h);
    if a.abs() < 1e-6 {
        return None;
    }
    let f = 1.0 / a;
    let s = sub3(orig, v0);
    let u = f * dot3(s, h);
    if !(0.0..=1.0).contains(&u) {
        return None;
    }
    let q = cross3(s, edge1);
    let v = f * dot3(dir, q);
    if v < 0.0 || u + v > 1.0 {
        return None;
    }
    let t = f * dot3(edge2, q);
    if t > 1e-3 {
        Some(t)
    } else {
        None
    }
}

/// Same ray test, but applying the material side rule before the
/// expensive barycentric checks. Horizontal grid faces use this so
/// the Select tool passes through a face whose rendered side is
/// currently culled.
fn ray_triangle_sided(
    orig: [f32; 3],
    dir: [f32; 3],
    v0: [f32; 3],
    v1: [f32; 3],
    v2: [f32; 3],
    sidedness: MaterialFaceSidedness,
) -> Option<f32> {
    let edge1 = sub3(v1, v0);
    let edge2 = sub3(v2, v0);
    let h = cross3(dir, edge2);
    let a = dot3(edge1, h);
    if !ray_triangle_side_visible(sidedness, a) {
        return None;
    }
    let f = 1.0 / a;
    let s = sub3(orig, v0);
    let u = f * dot3(s, h);
    if !(0.0..=1.0).contains(&u) {
        return None;
    }
    let q = cross3(s, edge1);
    let v = f * dot3(dir, q);
    if v < 0.0 || u + v > 1.0 {
        return None;
    }
    let t = f * dot3(edge2, q);
    if t > 1e-3 {
        Some(t)
    } else {
        None
    }
}

fn ray_triangle_side_visible(sidedness: MaterialFaceSidedness, signed_area: f32) -> bool {
    const EPS: f32 = 1e-6;
    match sidedness {
        MaterialFaceSidedness::Front => signed_area < -EPS,
        MaterialFaceSidedness::Back => signed_area > EPS,
        MaterialFaceSidedness::Both => signed_area.abs() >= EPS,
    }
}

/// Lowercase + non-alphanumeric → `_`, matching the cooker's clip
/// naming convention so room files line up with the asset cooker.
fn sanitise_room_filename(name: &str) -> String {
    let mut out = String::with_capacity(name.len());
    for ch in name.chars() {
        if ch.is_ascii_alphanumeric() {
            out.push(ch.to_ascii_lowercase());
        } else if !out.ends_with('_') {
            out.push('_');
        }
    }
    let trimmed = out.trim_matches('_').to_string();
    if trimmed.is_empty() {
        "room".to_string()
    } else {
        trimmed
    }
}

/// Walk the active scene and collect every Room node as an
/// `(id, display name)` pair, used by Portal pickers.
/// Walk parent links until a `NodeKind::Room` is found.
/// Returns its `NodeId` or `None` if `node_id` lives outside
/// any Room.
fn enclosing_room_id(scene: &psxed_project::Scene, node_id: NodeId) -> Option<NodeId> {
    let mut current = scene.node(node_id)?.parent;
    while let Some(parent_id) = current {
        let parent = scene.node(parent_id)?;
        if matches!(parent.kind, NodeKind::Room { .. }) {
            return Some(parent_id);
        }
        current = parent.parent;
    }
    None
}

fn node_enclosing_sector_size(scene: &psxed_project::Scene, node_id: NodeId) -> i32 {
    enclosing_room_id(scene, node_id)
        .and_then(|room_id| scene.node(room_id))
        .and_then(|room| match &room.kind {
            NodeKind::Room { grid } => Some(grid.sector_size.max(1)),
            _ => None,
        })
        .unwrap_or(DEFAULT_WORLD_SECTOR_SIZE)
}

/// Per-kind half-extents in world units. Picked so:
/// - bounds are big enough to click reliably at typical
///   editor zoom levels,
/// - small enough that a Light or AudioSource doesn't block
///   selection of nearby grid faces,
/// - distinct enough to read at a glance.
///
/// `None` for node kinds that don't get a 3D bound (Room,
/// World, Node, Node3D -- the structural / non-spatial ones).
fn entity_bound_kind_and_size(
    workspace: &EditorWorkspace,
    node: &psxed_project::SceneNode,
) -> Option<(EntityBoundKind, [f32; 3])> {
    match &node.kind {
        NodeKind::Room { .. } | NodeKind::World { .. } | NodeKind::Node | NodeKind::Node3D => None,
        NodeKind::ModelRenderer { .. }
        | NodeKind::Animator { .. }
        | NodeKind::Collider { .. }
        | NodeKind::Interactable { .. }
        | NodeKind::CharacterController { .. }
        | NodeKind::AiController { .. }
        | NodeKind::Combat { .. }
        | NodeKind::Equipment { .. } => None,
        NodeKind::Entity => {
            if let Some(model) = entity_model_resource(workspace, node) {
                let h = (model.world_height as f32).max(256.0);
                let half_h = h * 0.5;
                let half_xz = (h / 3.0).max(192.0);
                return Some((EntityBoundKind::Model, [half_xz, half_h, half_xz]));
            }
            Some((EntityBoundKind::MeshFallback, [256.0, 256.0, 256.0]))
        }
        NodeKind::MeshInstance { mesh, .. } => {
            // Model-backed instance: scale the bound to the
            // model's `world_height` so a Wraith reads as a
            // standing humanoid box, not a marker cube. Falls
            // back to a fixed mesh box for unbound instances.
            if let Some(id) = mesh {
                if let Some(resource) = workspace.project.resource(*id) {
                    if let psxed_project::ResourceData::Model(model) = &resource.data {
                        let h = (model.world_height as f32).max(256.0);
                        let half_h = h * 0.5;
                        // Square footprint sized as roughly
                        // a third of the model height -- wide
                        // enough to click, tight enough that
                        // adjacent models don't overlap.
                        let half_xz = (h / 3.0).max(192.0);
                        return Some((EntityBoundKind::Model, [half_xz, half_h, half_xz]));
                    }
                }
            }
            Some((EntityBoundKind::MeshFallback, [256.0, 256.0, 256.0]))
        }
        NodeKind::ImageProp { width, height, .. } => Some((
            EntityBoundKind::ImageProp,
            [
                (*width as f32 * 0.5).max(32.0),
                (*height as f32 * 0.5).max(32.0),
                32.0,
            ],
        )),
        NodeKind::SpawnPoint { .. } => Some((EntityBoundKind::SpawnPoint, [128.0, 256.0, 128.0])),
        NodeKind::PointLight { .. } => Some((EntityBoundKind::PointLight, [128.0, 128.0, 128.0])),
        NodeKind::Trigger { .. } => Some((EntityBoundKind::Trigger, [256.0, 256.0, 256.0])),
        NodeKind::Portal { .. } => Some((EntityBoundKind::Portal, [256.0, 256.0, 64.0])),
        NodeKind::AudioSource { .. } => Some((EntityBoundKind::AudioSource, [128.0, 128.0, 128.0])),
    }
}

fn node_is_floor_anchored(kind: &NodeKind) -> bool {
    matches!(
        kind,
        NodeKind::Entity | NodeKind::MeshInstance { .. } | NodeKind::SpawnPoint { .. }
    )
}

fn entity_model_resource<'a>(
    workspace: &'a EditorWorkspace,
    node: &psxed_project::SceneNode,
) -> Option<&'a psxed_project::ModelResource> {
    let scene = workspace.project.active_scene();
    node.children
        .iter()
        .filter_map(|id| scene.node(*id))
        .find_map(|child| match &child.kind {
            NodeKind::ModelRenderer {
                model: Some(id), ..
            } => workspace
                .project
                .resource(*id)
                .and_then(|resource| match &resource.data {
                    ResourceData::Model(model) => Some(model),
                    _ => None,
                }),
            NodeKind::CharacterController {
                character: Some(id),
                ..
            } => workspace
                .project
                .resource(*id)
                .and_then(|resource| match &resource.data {
                    ResourceData::Character(character) => character.model.and_then(|model_id| {
                        workspace
                            .project
                            .resource(model_id)
                            .and_then(|model_resource| match &model_resource.data {
                                ResourceData::Model(model) => Some(model),
                                _ => None,
                            })
                    }),
                    _ => None,
                }),
            _ => None,
        })
}

fn entity_character_resource_id(
    workspace: &EditorWorkspace,
    node: &psxed_project::SceneNode,
) -> Option<ResourceId> {
    if let NodeKind::CharacterController {
        character: Some(id),
        ..
    } = node.kind
    {
        return Some(id);
    }
    let scene = workspace.project.active_scene();
    node.children
        .iter()
        .filter_map(|id| scene.node(*id))
        .find_map(|child| match child.kind {
            NodeKind::CharacterController {
                character: Some(id),
                ..
            } => Some(id),
            _ => None,
        })
}

fn collect_room_options(project: &ProjectDocument) -> Vec<(NodeId, String)> {
    project
        .active_scene()
        .nodes()
        .iter()
        .filter(|node| matches!(node.kind, NodeKind::Room { .. }))
        .map(|node| (node.id, node.name.clone()))
        .collect()
}

/// Collect every Model resource as a `(resource id, display
/// name, clip names)` row. The MeshInstance inspector uses
/// this to render its clip-name combo box.
fn collect_model_options(project: &ProjectDocument) -> Vec<(ResourceId, String, Vec<String>)> {
    project
        .resources
        .iter()
        .filter_map(|r| match &r.data {
            ResourceData::Model(_) => Some((
                r.id,
                r.name.clone(),
                project
                    .resolved_model_animation_clips(r.id)
                    .iter()
                    .map(|c| c.name.clone())
                    .collect(),
            )),
            _ => None,
        })
        .collect()
}

fn collect_skeleton_options(project: &ProjectDocument) -> Vec<(ResourceId, String)> {
    project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::Skeleton(_) => Some((resource.id, resource.name.clone())),
            _ => None,
        })
        .collect()
}

fn collect_animation_clip_options(project: &ProjectDocument) -> Vec<AnimationClipOption> {
    project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::AnimationClip(clip) => Some(AnimationClipOption {
                id: resource.id,
                name: resource.name.clone(),
                skeleton: clip.skeleton,
                role: clip.role,
            }),
            _ => None,
        })
        .collect()
}

fn collect_animation_source_options(project: &ProjectDocument) -> Vec<(ResourceId, String)> {
    project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::AnimationSource(_) => Some((resource.id, resource.name.clone())),
            _ => None,
        })
        .collect()
}

fn collect_animation_set_options(project: &ProjectDocument) -> Vec<AnimationSetOption> {
    project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::AnimationSet(set) => {
                let mut action_clips = [None; psxed_project::CHARACTER_ANIMATION_ACTION_COUNT];
                for action in psxed_project::CharacterAnimationAction::ALL {
                    action_clips[action.to_index()] = set.action_clip(action);
                }
                Some(AnimationSetOption {
                    id: resource.id,
                    name: resource.name.clone(),
                    skeleton: set.skeleton,
                    action_clips,
                })
            }
            _ => None,
        })
        .collect()
}

#[derive(Default)]
struct AnimationCatalogueReport {
    skeletons_added: usize,
    source_candidates: usize,
    sources_added: usize,
    sources_updated: usize,
    clips_added: usize,
    sets_added: usize,
    sets_updated: usize,
    models_updated: usize,
    characters_updated: usize,
}

impl AnimationCatalogueReport {
    const fn changed(&self) -> bool {
        self.skeletons_added > 0
            || self.sources_added > 0
            || self.sources_updated > 0
            || self.clips_added > 0
            || self.sets_added > 0
            || self.sets_updated > 0
            || self.models_updated > 0
            || self.characters_updated > 0
    }
}

#[derive(Clone)]
struct ModelCatalogueInput {
    id: ResourceId,
    name: String,
    model_path: String,
    clips: Vec<psxed_project::ModelAnimationClip>,
}

#[derive(Debug, Clone)]
struct AnimationSourceCandidate {
    resource_name: String,
    source_path: String,
    clip_name: String,
    provider: psxed_project::AnimationSourceProvider,
    role: psxed_project::AnimationRole,
    looping: bool,
    tags: Vec<String>,
}

fn catalogue_animation_library(
    project: &mut ProjectDocument,
    project_root: &Path,
) -> Result<AnimationCatalogueReport, String> {
    let models: Vec<ModelCatalogueInput> = project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::Model(model) if !model.clips.is_empty() => Some(ModelCatalogueInput {
                id: resource.id,
                name: resource.name.clone(),
                model_path: model.model_path.clone(),
                clips: model.clips.clone(),
            }),
            _ => None,
        })
        .collect();

    let mut report = AnimationCatalogueReport::default();
    for model in models {
        let abs = psxed_project::model_import::resolve_path(&model.model_path, Some(project_root));
        let bytes = std::fs::read(&abs).map_err(|error| format!("{}: {error}", abs.display()))?;
        let parsed = psx_asset::Model::from_bytes(&bytes)
            .map_err(|error| format!("{}: {error:?}", abs.display()))?;
        let skeleton = psxed_project::SkeletonResource::from_model(&parsed);
        let skeleton_id = match find_skeleton_by_signature(project, &skeleton.signature) {
            Some(id) => id,
            None => {
                let id = project.add_resource(
                    format!("{} Skeleton", model.name),
                    ResourceData::Skeleton(psxed_project::SkeletonResource {
                        note: format!("Catalogued from {}", model.name),
                        ..skeleton
                    }),
                );
                report.skeletons_added += 1;
                id
            }
        };

        if let Some(resource) = project.resource_mut(model.id) {
            if let ResourceData::Model(model_resource) = &mut resource.data {
                if model_resource.skeleton != Some(skeleton_id) {
                    model_resource.skeleton = Some(skeleton_id);
                    report.models_updated += 1;
                }
            }
        }

        let mut animation_ids = Vec::new();
        for clip in &model.clips {
            let role = psxed_project::AnimationRole::guess_from_name(&clip.name);
            let source_id =
                match find_animation_source_by_path(project, Some(model.id), &clip.psxanim_path) {
                    Some(id) => id,
                    None => {
                        let mut source = psxed_project::AnimationSourceResource::from_path(
                            clip.psxanim_path.clone(),
                            clip.name.clone(),
                        );
                        source.skeleton = Some(skeleton_id);
                        source.target_model = Some(model.id);
                        source.role = role;
                        source.looping = !matches!(
                            role,
                            psxed_project::AnimationRole::Roll
                                | psxed_project::AnimationRole::Backstep
                                | psxed_project::AnimationRole::Attack
                                | psxed_project::AnimationRole::Hit
                                | psxed_project::AnimationRole::Death
                        );
                        let id = project.add_resource(
                            format!("{} Source", clip.name),
                            ResourceData::AnimationSource(source),
                        );
                        report.sources_added += 1;
                        id
                    }
                };
            let clip_id =
                match find_animation_clip_by_path(project, skeleton_id, &clip.psxanim_path) {
                    Some(id) => id,
                    None => {
                        let id = project.add_resource(
                            clip.name.clone(),
                            ResourceData::AnimationClip(psxed_project::AnimationClipResource {
                                psxanim_path: clip.psxanim_path.clone(),
                                skeleton: Some(skeleton_id),
                                source: Some(source_id),
                                target_model: Some(model.id),
                                bake: psxed_project::AnimationClipBakeKind::ModelNative,
                                role,
                                looping: !matches!(
                                    role,
                                    psxed_project::AnimationRole::Roll
                                        | psxed_project::AnimationRole::Backstep
                                        | psxed_project::AnimationRole::Attack
                                        | psxed_project::AnimationRole::Hit
                                        | psxed_project::AnimationRole::Death
                                ),
                                tags: if matches!(role, psxed_project::AnimationRole::Generic) {
                                    Vec::new()
                                } else {
                                    vec![role.label().to_ascii_lowercase()]
                                },
                                calibration: clip.calibration,
                            }),
                        );
                        report.clips_added += 1;
                        id
                    }
                };
            animation_ids.push(clip_id);
        }

        let set_name = format!("{} Clip Role Map", model.name);
        let catalogued_set = build_animation_set_from_clips(project, skeleton_id, &animation_ids);
        let set_id = match find_animation_set_by_name(project, skeleton_id, &set_name) {
            Some(id) => {
                if let Some(resource) = project.resource_mut(id) {
                    if let ResourceData::AnimationSet(existing) = &mut resource.data {
                        if merge_animation_set(existing, &catalogued_set) {
                            report.sets_updated += 1;
                        }
                    }
                }
                id
            }
            None => {
                let id = project.add_resource(set_name, ResourceData::AnimationSet(catalogued_set));
                report.sets_added += 1;
                id
            }
        };

        for resource in &mut project.resources {
            let ResourceData::Character(character) = &mut resource.data else {
                continue;
            };
            if character.model == Some(model.id) && character.animation_set.is_none() {
                character.animation_set = Some(set_id);
                report.characters_updated += 1;
            }
        }
    }
    Ok(report)
}

fn catalogue_animation_sources_from_path(
    project: &mut ProjectDocument,
    project_root: &Path,
    source_root: &Path,
) -> Result<AnimationCatalogueReport, String> {
    let mut candidates = Vec::new();
    if source_root.is_dir() {
        collect_animation_source_candidates_from_dir(source_root, project_root, &mut candidates)?;
    } else if is_zip_path(source_root) {
        collect_animation_source_candidates_from_zip(source_root, project_root, &mut candidates)?;
    } else if is_animation_source_file_path(source_root) {
        candidates.push(animation_source_candidate_for_file(
            &EditorWorkspace::display_project_path(source_root, project_root),
            source_root
                .file_stem()
                .and_then(|stem| stem.to_str())
                .unwrap_or("animation"),
        ));
    } else {
        return Err(format!(
            "{} is not an animation source folder, zip, FBX, GLB, or glTF file",
            source_root.display()
        ));
    }

    candidates.sort_by_key(|candidate| {
        (
            candidate.provider.label(),
            candidate.source_path.to_ascii_lowercase(),
        )
    });
    candidates.dedup_by(|a, b| {
        a.source_path.eq_ignore_ascii_case(&b.source_path)
            && a.clip_name.eq_ignore_ascii_case(&b.clip_name)
    });

    let mut report = AnimationCatalogueReport {
        source_candidates: candidates.len(),
        ..AnimationCatalogueReport::default()
    };
    for candidate in candidates {
        match upsert_animation_source_candidate(project, candidate) {
            AnimationSourceUpsert::Added => report.sources_added += 1,
            AnimationSourceUpsert::Updated => report.sources_updated += 1,
            AnimationSourceUpsert::Unchanged => {}
        }
    }
    Ok(report)
}

fn collect_animation_source_candidates_from_dir(
    root: &Path,
    project_root: &Path,
    out: &mut Vec<AnimationSourceCandidate>,
) -> Result<(), String> {
    let mut pending = vec![root.to_path_buf()];
    while let Some(dir) = pending.pop() {
        let entries =
            std::fs::read_dir(&dir).map_err(|error| format!("{}: {error}", dir.display()))?;
        let mut entries: Vec<_> = entries
            .collect::<Result<Vec<_>, _>>()
            .map_err(|error| format!("{}: {error}", dir.display()))?;
        entries.sort_by_key(|entry| entry.path());
        for entry in entries.into_iter().rev() {
            let path = entry.path();
            let Some(name) = path.file_name().and_then(|name| name.to_str()) else {
                continue;
            };
            if name.starts_with('.') {
                continue;
            }
            if path.is_dir() {
                if !should_skip_animation_source_dir(&path) {
                    pending.push(path);
                }
                continue;
            }
            if !is_animation_source_file_path(&path) {
                continue;
            }
            let stored = EditorWorkspace::display_project_path(&path, project_root);
            if should_skip_animation_source_path(&stored) {
                continue;
            }
            let clip_name = path
                .file_stem()
                .and_then(|stem| stem.to_str())
                .unwrap_or("animation");
            out.push(animation_source_candidate_for_file(&stored, clip_name));
        }
    }
    Ok(())
}

fn collect_animation_source_candidates_from_zip(
    zip_path: &Path,
    project_root: &Path,
    out: &mut Vec<AnimationSourceCandidate>,
) -> Result<(), String> {
    let file = std::fs::File::open(zip_path)
        .map_err(|error| format!("{}: {error}", zip_path.display()))?;
    let mut archive =
        zip::ZipArchive::new(file).map_err(|error| format!("{}: {error}", zip_path.display()))?;
    let stored_zip = EditorWorkspace::display_project_path(zip_path, project_root);
    for index in 0..archive.len() {
        let file = archive
            .by_index(index)
            .map_err(|error| format!("{} entry #{index}: {error}", zip_path.display()))?;
        if file.is_dir() {
            continue;
        }
        let entry_name = file.name().replace('\\', "/");
        if !is_animation_source_entry_name(&entry_name)
            || should_skip_animation_source_path(&entry_name)
        {
            continue;
        }
        let clip_name = Path::new(&entry_name)
            .file_stem()
            .and_then(|stem| stem.to_str())
            .unwrap_or("animation");
        let stored = format!("{stored_zip}::{entry_name}");
        out.push(animation_source_candidate_for_file(&stored, clip_name));
    }
    Ok(())
}

enum AnimationSourceUpsert {
    Added,
    Updated,
    Unchanged,
}

fn upsert_animation_source_candidate(
    project: &mut ProjectDocument,
    candidate: AnimationSourceCandidate,
) -> AnimationSourceUpsert {
    if let Some(resource) = project
        .resources
        .iter_mut()
        .find(|resource| match &resource.data {
            ResourceData::AnimationSource(source) => {
                source.target_model.is_none()
                    && source
                        .source_path
                        .eq_ignore_ascii_case(&candidate.source_path)
                    && source.clip_name.eq_ignore_ascii_case(&candidate.clip_name)
            }
            _ => false,
        })
    {
        let ResourceData::AnimationSource(source) = &mut resource.data else {
            return AnimationSourceUpsert::Unchanged;
        };
        let mut changed = false;
        if source.provider != candidate.provider {
            source.provider = candidate.provider;
            changed = true;
        }
        if source.role != candidate.role {
            source.role = candidate.role;
            changed = true;
        }
        if source.looping != candidate.looping {
            source.looping = candidate.looping;
            changed = true;
        }
        if source.tags != candidate.tags {
            source.tags = candidate.tags;
            changed = true;
        }
        if changed {
            AnimationSourceUpsert::Updated
        } else {
            AnimationSourceUpsert::Unchanged
        }
    } else {
        project.add_resource(
            candidate.resource_name,
            ResourceData::AnimationSource(psxed_project::AnimationSourceResource {
                source_path: candidate.source_path,
                clip_name: candidate.clip_name,
                provider: candidate.provider,
                skeleton: None,
                target_model: None,
                role: candidate.role,
                looping: candidate.looping,
                tags: candidate.tags,
            }),
        );
        AnimationSourceUpsert::Added
    }
}

fn animation_source_candidate_for_file(
    stored_path: &str,
    clip_name: &str,
) -> AnimationSourceCandidate {
    let provider = psxed_project::AnimationSourceProvider::guess_from_path(stored_path);
    let role = psxed_project::AnimationRole::guess_from_name(clip_name);
    AnimationSourceCandidate {
        resource_name: animation_source_resource_name(clip_name),
        source_path: stored_path.to_string(),
        clip_name: clip_name.to_string(),
        provider,
        role,
        looping: animation_source_default_looping(role, clip_name, stored_path),
        tags: animation_source_tags(provider, role, clip_name, stored_path),
    }
}

fn animation_source_resource_name(clip_name: &str) -> String {
    let mut name = clip_name
        .strip_prefix("A_MOD_SWD_")
        .or_else(|| clip_name.strip_prefix("A_"))
        .unwrap_or(clip_name)
        .trim_end_matches("_Sword")
        .trim_end_matches("_Neut")
        .replace('_', " ");
    name = name.split_whitespace().collect::<Vec<_>>().join(" ");
    if name.is_empty() {
        "Animation Source".to_string()
    } else {
        name
    }
}

fn animation_source_default_looping(
    role: psxed_project::AnimationRole,
    clip_name: &str,
    source_path: &str,
) -> bool {
    let lowered = format!("{clip_name} {source_path}").to_ascii_lowercase();
    if lowered.contains("loop") {
        return true;
    }
    if lowered.contains("begin")
        || lowered.contains("enter")
        || lowered.contains("end")
        || lowered.contains("exit")
        || lowered.contains("returntoidle")
        || lowered.contains("draw")
        || lowered.contains("sheathe")
        || lowered.contains("parry")
        || lowered.contains("backstep")
        || lowered.contains("back_step")
        || lowered.contains("back step")
        || lowered.contains("step_back")
        || lowered.contains("dodge")
        || lowered.contains("roll")
        || lowered.contains("knockdown")
        || lowered.contains("stagger")
        || lowered.contains("stun")
    {
        return false;
    }
    matches!(
        role,
        psxed_project::AnimationRole::Idle
            | psxed_project::AnimationRole::Walk
            | psxed_project::AnimationRole::Run
            | psxed_project::AnimationRole::Turn
            | psxed_project::AnimationRole::Generic
    )
}

fn animation_source_tags(
    provider: psxed_project::AnimationSourceProvider,
    role: psxed_project::AnimationRole,
    clip_name: &str,
    source_path: &str,
) -> Vec<String> {
    let lowered = format!("{clip_name} {source_path}").to_ascii_lowercase();
    let mut tags = Vec::new();
    if !matches!(provider, psxed_project::AnimationSourceProvider::Unknown) {
        tags.push(provider.label().to_ascii_lowercase());
    }
    if !matches!(role, psxed_project::AnimationRole::Generic) {
        tags.push(role.label().to_ascii_lowercase());
    }
    for (needle, tag) in [
        ("polygon", "polygon"),
        ("sidekick", "sidekick"),
        ("rootmotion", "root_motion"),
        ("_rm_", "root_motion"),
        ("rmh", "root_motion_horizontal"),
        ("rmv", "root_motion_vertical"),
        ("returntoidle", "return_to_idle"),
        ("dodge", "dodge"),
        ("roll", "roll"),
        ("block", "block"),
        ("parry", "parry"),
        ("stagger", "stagger"),
        ("knockdown", "knockdown"),
        ("stun", "stun"),
        ("draw", "draw"),
        ("sheathe", "sheathe"),
        ("sheathed", "sheathed"),
        ("femn", "feminine"),
        ("masc", "masculine"),
        ("sword", "sword"),
    ] {
        if lowered.contains(needle) {
            tags.push(tag.to_string());
        }
    }
    tags.sort();
    tags.dedup();
    tags
}

fn should_skip_animation_source_dir(path: &Path) -> bool {
    let lowered = path.to_string_lossy().to_ascii_lowercase();
    lowered.contains("/target/")
        || lowered.ends_with("/target")
        || lowered.contains("/.git/")
        || lowered.ends_with("/.git")
        || lowered.contains("/models/")
        || lowered.ends_with("/models")
        || lowered.contains("/textures/")
        || lowered.ends_with("/textures")
}

fn should_skip_animation_source_path(path: &str) -> bool {
    let lowered = path.replace('\\', "/").to_ascii_lowercase();
    lowered.contains("/models/")
        || lowered.starts_with("models/")
        || lowered.contains("/textures/")
        || lowered.starts_with("textures/")
        || lowered.contains("/__macosx/")
        || lowered.starts_with("__macosx/")
}

fn is_animation_source_entry_name(name: &str) -> bool {
    let lowered = name.to_ascii_lowercase();
    lowered.ends_with(".fbx") || lowered.ends_with(".glb") || lowered.ends_with(".gltf")
}

fn is_animation_source_file_path(path: &Path) -> bool {
    path.extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| matches!(ext.to_ascii_lowercase().as_str(), "fbx" | "glb" | "gltf"))
        .unwrap_or(false)
}

fn is_zip_path(path: &Path) -> bool {
    path.extension()
        .and_then(|ext| ext.to_str())
        .map(|ext| ext.eq_ignore_ascii_case("zip"))
        .unwrap_or(false)
}

fn find_skeleton_by_signature(project: &ProjectDocument, signature: &str) -> Option<ResourceId> {
    project
        .resources
        .iter()
        .find_map(|resource| match &resource.data {
            ResourceData::Skeleton(skeleton) if skeleton.signature == signature => {
                Some(resource.id)
            }
            _ => None,
        })
}

fn find_animation_clip_by_path(
    project: &ProjectDocument,
    skeleton: ResourceId,
    path: &str,
) -> Option<ResourceId> {
    project
        .resources
        .iter()
        .find_map(|resource| match &resource.data {
            ResourceData::AnimationClip(clip)
                if clip.skeleton == Some(skeleton) && clip.psxanim_path == path =>
            {
                Some(resource.id)
            }
            _ => None,
        })
}

fn find_animation_source_by_path(
    project: &ProjectDocument,
    target_model: Option<ResourceId>,
    path: &str,
) -> Option<ResourceId> {
    project
        .resources
        .iter()
        .find_map(|resource| match &resource.data {
            ResourceData::AnimationSource(source)
                if source.source_path == path && source.target_model == target_model =>
            {
                Some(resource.id)
            }
            _ => None,
        })
}

fn find_animation_set_by_name(
    project: &ProjectDocument,
    skeleton: ResourceId,
    name: &str,
) -> Option<ResourceId> {
    project
        .resources
        .iter()
        .find_map(|resource| match &resource.data {
            ResourceData::AnimationSet(set)
                if set.skeleton == Some(skeleton) && resource.name == name =>
            {
                Some(resource.id)
            }
            _ => None,
        })
}

fn build_animation_set_from_clips(
    project: &ProjectDocument,
    skeleton: ResourceId,
    animation_ids: &[ResourceId],
) -> psxed_project::AnimationSetResource {
    let mut set = psxed_project::AnimationSetResource {
        skeleton: Some(skeleton),
        ..psxed_project::AnimationSetResource::default()
    };
    for id in animation_ids {
        let Some(resource) = project.resource(*id) else {
            continue;
        };
        let ResourceData::AnimationClip(clip) = &resource.data else {
            continue;
        };
        match clip.role {
            psxed_project::AnimationRole::Idle if set.idle_clip.is_none() => {
                set.idle_clip = Some(*id)
            }
            psxed_project::AnimationRole::Walk if set.walk_clip.is_none() => {
                set.walk_clip = Some(*id)
            }
            psxed_project::AnimationRole::Run if set.run_clip.is_none() => set.run_clip = Some(*id),
            psxed_project::AnimationRole::Turn if set.turn_clip.is_none() => {
                set.turn_clip = Some(*id)
            }
            psxed_project::AnimationRole::Roll if set.roll_clip.is_none() => {
                set.roll_clip = Some(*id)
            }
            psxed_project::AnimationRole::Backstep if set.backstep_clip.is_none() => {
                set.backstep_clip = Some(*id)
            }
            _ => {
                if !set.clips.contains(id) {
                    set.clips.push(*id);
                }
            }
        }
    }
    set
}

fn merge_animation_set(
    target: &mut psxed_project::AnimationSetResource,
    source: &psxed_project::AnimationSetResource,
) -> bool {
    let mut changed = false;
    if target.skeleton.is_none() && source.skeleton.is_some() {
        target.skeleton = source.skeleton;
        changed = true;
    }
    for role in [
        psxed_project::AnimationRole::Idle,
        psxed_project::AnimationRole::Walk,
        psxed_project::AnimationRole::Run,
        psxed_project::AnimationRole::Turn,
        psxed_project::AnimationRole::Roll,
        psxed_project::AnimationRole::Backstep,
    ] {
        let source_clip = source.role_clip(role);
        if source_clip.is_some() {
            if let Some(target_slot) = target.role_clip_mut(role) {
                if target_slot.is_none() {
                    *target_slot = source_clip;
                    changed = true;
                }
            }
        }
    }
    for clip in &source.clips {
        if !target.clips.contains(clip) {
            target.clips.push(*clip);
            changed = true;
        }
    }
    changed
}

fn collect_attachment_socket_names(project: &ProjectDocument) -> Vec<String> {
    let mut names: Vec<String> = project
        .resources
        .iter()
        .filter_map(|resource| match &resource.data {
            ResourceData::Model(model) => Some(model),
            _ => None,
        })
        .flat_map(|model| model.attachments.iter().map(|socket| socket.name.trim()))
        .filter(|name| !name.is_empty())
        .map(|name| name.to_string())
        .collect();
    names.sort_by_key(|name| name.to_ascii_lowercase());
    names.dedup_by(|a, b| a.eq_ignore_ascii_case(b));
    names
}

/// Collect every Character Profile resource as `(id, name)`. The
/// controller/spawn inspectors use this to populate their pickers.
fn collect_character_options(project: &ProjectDocument) -> Vec<(ResourceId, String)> {
    project
        .resources
        .iter()
        .filter_map(|r| match &r.data {
            ResourceData::Character(_) => Some((r.id, r.name.clone())),
            _ => None,
        })
        .collect()
}

/// Collect every Weapon resource as `(id, name)`.
fn collect_weapon_options(project: &ProjectDocument) -> Vec<(ResourceId, String)> {
    project
        .resources
        .iter()
        .filter_map(|r| match &r.data {
            ResourceData::Weapon(_) => Some((r.id, r.name.clone())),
            _ => None,
        })
        .collect()
}

fn world_streaming_for_room(project: &ProjectDocument, room_id: NodeId) -> WorldStreamingSettings {
    project
        .active_scene()
        .world_streaming_for_node(room_id)
        .unwrap_or_default()
}

fn draw_portal_room_budget(
    ui: &mut egui::Ui,
    project: &ProjectDocument,
    project_root: &Path,
    room_id: NodeId,
    grid: &WorldGrid,
) {
    let streaming = world_streaming_for_room(project, room_id);
    let plan = plan_portal_rooms(
        project.active_scene(),
        room_id,
        grid,
        PortalRoomConfig::default(),
    );
    let resource_use = collect_scene_resource_use(project);
    let file_budget = resource_file_budget(project, project_root, &resource_use);
    let vram_budget = runtime_vram_budget(project, project_root, &resource_use);
    let model_budget = runtime_model_budget(project, project_root, &resource_use);
    let over = plan.over_budget_count() > 0;
    let header = if over {
        icons::label(icons::TRASH, "Manual Portal Rooms — over limit")
    } else {
        icons::label(icons::SCAN, "Manual Portal Rooms")
    };

    egui::CollapsingHeader::new(header)
        .default_open(true)
        .show(ui, |ui| {
            draw_budget_row(ui, "Manual rooms", format!("{}", plan.room_count()), over);
            draw_budget_row(
                ui,
                "Hard cap",
                format!(
                    "{}×{} sectors",
                    plan.config.max_width, plan.config.max_depth
                ),
                false,
            );
            draw_budget_row(
                ui,
                "Resident rooms",
                format!("{}", streaming.resident_chunk_limit),
                false,
            );
            draw_budget_row(
                ui,
                "Visible rooms",
                format!("{}", streaming.visible_chunk_limit),
                false,
            );
            draw_budget_row(
                ui,
                "Portal markers",
                format!("{}", plan.portal_count),
                false,
            );
            draw_budget_row(
                ui,
                "Authored footprint",
                format!("{}×{} sectors", plan.source_size[0], plan.source_size[1]),
                false,
            );
            ui.weak("Embedded Play cooks this world into manual portal-delimited runtime rooms.");
            if let Some(room) = plan.largest_room_asset() {
                draw_budget_row(
                    ui,
                    "Largest room asset",
                    format!(
                        "#{} {}×{}, {} total",
                        room.index,
                        room.size[0],
                        room.size[1],
                        human_bytes_u64(room.budget.psxw_static_lit_bytes as u64)
                    ),
                    room.over_budget,
                );
            }
            if let Some(room) = plan.largest_geometry() {
                draw_budget_row(
                    ui,
                    "Largest geometry",
                    format!(
                        "#{} {}",
                        room.index,
                        human_bytes_u64(room.budget.psxw_bytes as u64)
                    ),
                    room.budget.psxw_bytes > MAX_ROOM_BYTES,
                );
            }
            if let Some(room) = plan.largest_triangle_room() {
                draw_budget_row(
                    ui,
                    "Most triangles",
                    format!(
                        "#{} {} / {}",
                        room.index, room.budget.triangles, MAX_ROOM_TRIANGLES
                    ),
                    room.budget.triangles > MAX_ROOM_TRIANGLES,
                );
            }

            ui.add_space(4.0);
            draw_room_budget_rows(ui, grid.authored_budget());

            ui.add_space(4.0);
            ui.separator();
            draw_budget_row(
                ui,
                "Scene resources",
                resource_count_summary(&resource_use),
                false,
            );
            draw_budget_row(
                ui,
                "Scene components",
                component_count_summary(&resource_use),
                false,
            );
            draw_budget_row(
                ui,
                "Referenced files",
                format!(
                    "{} across {} files",
                    human_bytes_u64(file_budget.bytes),
                    file_budget.files
                ),
                false,
            );
            draw_budget_row(
                ui,
                "Texture VRAM",
                format!(
                    "{} across {} textures",
                    human_bytes_u64(vram_budget.bytes),
                    vram_budget.textures
                ),
                false,
            );
            draw_budget_row(
                ui,
                "Room texture VRAM",
                format!(
                    "{} across {} textures",
                    human_bytes_u64(vram_budget.room_bytes),
                    vram_budget.room_textures
                ),
                false,
            );
            draw_budget_row(
                ui,
                "Model texture VRAM",
                format!(
                    "{} across {} atlases",
                    human_bytes_u64(vram_budget.model_bytes),
                    vram_budget.model_textures
                ),
                false,
            );
            draw_budget_row(
                ui,
                "Model RAM",
                format!(
                    "{} across {} models, {} clips",
                    human_bytes_u64(model_budget.ram_bytes),
                    model_budget.models,
                    model_budget.clips
                ),
                false,
            );
            if file_budget.missing > 0 {
                draw_budget_row(
                    ui,
                    "Missing files",
                    format!("{}", file_budget.missing),
                    true,
                );
            }
            if vram_budget.missing > 0 {
                draw_budget_row(
                    ui,
                    "Unresolved VRAM textures",
                    format!("{}", vram_budget.missing),
                    true,
                );
            }
            if model_budget.missing > 0 {
                draw_budget_row(
                    ui,
                    "Unresolved model assets",
                    format!("{}", model_budget.missing),
                    true,
                );
            }

            ui.add_space(4.0);
            egui::Grid::new(format!("portal_rooms_{}", room_id.raw()))
                .num_columns(7)
                .striped(true)
                .show(ui, |ui| {
                    ui.label(RichText::new("#").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Origin").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Size").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Tris").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Geom").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Light").color(STUDIO_TEXT_WEAK));
                    ui.label(RichText::new("Total").color(STUDIO_TEXT_WEAK));
                    ui.end_row();

                    for room in plan.rooms.iter().take(8) {
                        let color = room
                            .over_budget
                            .then_some(Color32::from_rgb(0xE0, 0x60, 0x60));
                        let text = |value: String| {
                            let text = RichText::new(value).monospace();
                            if let Some(color) = color {
                                text.color(color)
                            } else {
                                text
                            }
                        };
                        ui.label(text(format!("{}", room.index)));
                        ui.label(text(format!(
                            "{},{}",
                            room.world_origin[0], room.world_origin[1]
                        )));
                        ui.label(text(format!("{}×{}", room.size[0], room.size[1])));
                        ui.label(text(format!("{}", room.budget.triangles)));
                        ui.label(text(human_bytes_u64(room.budget.psxw_bytes as u64)));
                        ui.label(text(human_bytes_u64(
                            room.budget.static_light_table_bytes as u64,
                        )));
                        ui.label(text(human_bytes_u64(
                            room.budget.psxw_static_lit_bytes as u64,
                        )));
                        ui.end_row();
                    }
                });
            if plan.rooms.len() > 8 {
                ui.weak(format!("{} more rooms", plan.rooms.len() - 8));
            }
        });
}

#[derive(Default)]
struct ResourceFileBudget {
    files: usize,
    bytes: u64,
    missing: usize,
}

#[derive(Default)]
struct RuntimeVramBudget {
    textures: usize,
    bytes: u64,
    room_textures: usize,
    room_bytes: u64,
    model_textures: usize,
    model_bytes: u64,
    missing: usize,
}

#[derive(Default)]
struct RuntimeModelBudget {
    models: usize,
    clips: usize,
    ram_bytes: u64,
    missing: usize,
}

fn resource_file_budget(
    project: &ProjectDocument,
    project_root: &Path,
    resource_use: &SceneResourceUse,
) -> ResourceFileBudget {
    let mut budget = ResourceFileBudget::default();
    let mut seen = HashSet::new();
    for id in resource_use
        .textures
        .iter()
        .chain(resource_use.models.iter())
        .chain(resource_use.meshes.iter())
        .chain(resource_use.audio.iter())
    {
        let Some(resource) = project.resource(*id) else {
            continue;
        };
        match &resource.data {
            ResourceData::Texture { psxt_path } => {
                add_resource_file(project_root, psxt_path, &mut budget, &mut seen);
            }
            ResourceData::Model(model) => {
                add_resource_file(project_root, &model.model_path, &mut budget, &mut seen);
                if let Some(texture_path) = &model.texture_path {
                    add_resource_file(project_root, texture_path, &mut budget, &mut seen);
                }
                for clip in &model.clips {
                    add_resource_file(project_root, &clip.psxanim_path, &mut budget, &mut seen);
                }
            }
            ResourceData::Mesh { source_path }
            | ResourceData::Scene { source_path }
            | ResourceData::Script { source_path }
            | ResourceData::Audio { source_path } => {
                add_resource_file(project_root, source_path, &mut budget, &mut seen);
            }
            ResourceData::AnimationClip(clip) => {
                add_resource_file(project_root, &clip.psxanim_path, &mut budget, &mut seen);
            }
            ResourceData::Material(_)
            | ResourceData::Skeleton(_)
            | ResourceData::AnimationSource(_)
            | ResourceData::AnimationSet(_)
            | ResourceData::Character(_)
            | ResourceData::Weapon(_) => {}
        }
    }
    budget
}

fn runtime_vram_budget(
    project: &ProjectDocument,
    project_root: &Path,
    resource_use: &SceneResourceUse,
) -> RuntimeVramBudget {
    let mut budget = RuntimeVramBudget::default();

    for id in &resource_use.textures {
        let Some(resource) = project.resource(*id) else {
            continue;
        };
        if let ResourceData::Texture { psxt_path } = &resource.data {
            add_runtime_texture_vram(project_root, psxt_path, true, &mut budget);
        }
    }

    for id in &resource_use.models {
        let Some(resource) = project.resource(*id) else {
            continue;
        };
        let ResourceData::Model(model) = &resource.data else {
            continue;
        };
        if let Some(texture_path) = &model.texture_path {
            add_runtime_texture_vram(project_root, texture_path, false, &mut budget);
        }
    }

    budget
}

fn runtime_model_budget(
    project: &ProjectDocument,
    project_root: &Path,
    resource_use: &SceneResourceUse,
) -> RuntimeModelBudget {
    let mut budget = RuntimeModelBudget::default();

    for id in &resource_use.models {
        let Some(resource) = project.resource(*id) else {
            continue;
        };
        let ResourceData::Model(model) = &resource.data else {
            continue;
        };
        budget.models += 1;
        add_runtime_model_asset_bytes(project_root, &model.model_path, &mut budget);
        for clip in project.resolved_model_animation_clips(*id) {
            budget.clips += 1;
            add_runtime_model_asset_bytes(project_root, &clip.psxanim_path, &mut budget);
        }
    }

    budget
}

fn add_runtime_texture_vram(
    project_root: &Path,
    stored: &str,
    room_material: bool,
    budget: &mut RuntimeVramBudget,
) {
    if stored.trim().is_empty() {
        return;
    }
    let abs = psxed_project::model_import::resolve_path(stored, Some(project_root));
    let Ok(bytes) = std::fs::read(&abs) else {
        budget.missing += 1;
        return;
    };
    let Ok(texture) = psx_asset::Texture::from_bytes(&bytes) else {
        budget.missing += 1;
        return;
    };

    budget.textures += 1;
    let bytes = texture.pixel_bytes().len() as u64 + texture.clut_bytes().len() as u64;
    budget.bytes = budget.bytes.saturating_add(bytes);
    if room_material {
        budget.room_textures += 1;
        budget.room_bytes = budget.room_bytes.saturating_add(bytes);
    } else {
        budget.model_textures += 1;
        budget.model_bytes = budget.model_bytes.saturating_add(bytes);
    }
}

fn add_runtime_model_asset_bytes(
    project_root: &Path,
    stored: &str,
    budget: &mut RuntimeModelBudget,
) {
    if stored.trim().is_empty() {
        budget.missing += 1;
        return;
    }
    let abs = psxed_project::model_import::resolve_path(stored, Some(project_root));
    match std::fs::metadata(&abs) {
        Ok(metadata) if metadata.is_file() => {
            budget.ram_bytes = budget.ram_bytes.saturating_add(metadata.len());
        }
        _ => budget.missing += 1,
    }
}

fn add_resource_file(
    project_root: &Path,
    stored: &str,
    budget: &mut ResourceFileBudget,
    seen: &mut HashSet<PathBuf>,
) {
    if stored.trim().is_empty() {
        return;
    }
    let abs = psxed_project::model_import::resolve_path(stored, Some(project_root));
    if !seen.insert(abs.clone()) {
        return;
    }
    match std::fs::metadata(&abs) {
        Ok(metadata) if metadata.is_file() => {
            budget.files += 1;
            budget.bytes = budget.bytes.saturating_add(metadata.len());
        }
        _ => budget.missing += 1,
    }
}

fn resource_count_summary(resource_use: &SceneResourceUse) -> String {
    format!(
        "{} model, {} character profile, {} material, {} texture, {} audio",
        resource_use.models.len(),
        resource_use.characters.len(),
        resource_use.materials.len(),
        resource_use.textures.len(),
        resource_use.audio.len()
    )
}

fn component_count_summary(resource_use: &SceneResourceUse) -> String {
    format!(
        "{} renderer, {} controller, {} collider, {} light, {} interactable",
        resource_use.model_instances,
        resource_use.character_controllers,
        resource_use.colliders,
        resource_use.lights,
        resource_use.interactables
    )
}

fn draw_budget_row(ui: &mut egui::Ui, key: &str, val: String, hot: bool) {
    ui.horizontal(|ui| {
        ui.label(RichText::new(key).color(STUDIO_TEXT_WEAK));
        let txt = RichText::new(val).monospace();
        ui.label(if hot {
            txt.color(Color32::from_rgb(0xE0, 0x60, 0x60))
        } else {
            txt
        });
    });
}

fn draw_room_budget_rows(ui: &mut egui::Ui, budget: WorldGridBudget) {
    draw_budget_row(
        ui,
        "Cells",
        format!(
            "{} populated / {} total",
            budget.populated_cells, budget.total_cells
        ),
        budget.total_cells > (MAX_ROOM_WIDTH as usize) * (MAX_ROOM_DEPTH as usize),
    );
    draw_budget_row(ui, "Floors", format!("{}", budget.floors), false);
    draw_budget_row(ui, "Ceilings", format!("{}", budget.ceilings), false);
    draw_budget_row(ui, "Walls", format!("{}", budget.walls), false);
    draw_budget_row(
        ui,
        "Triangles",
        format!("{} / {}", budget.triangles, MAX_ROOM_TRIANGLES),
        budget.triangles > MAX_ROOM_TRIANGLES,
    );
    draw_budget_row(
        ui,
        ".psxw geometry",
        format!(
            "{} / {}",
            human_bytes_u64(budget.psxw_bytes as u64),
            human_bytes_u64(MAX_ROOM_BYTES as u64)
        ),
        budget.psxw_bytes > MAX_ROOM_BYTES,
    );
    draw_budget_row(
        ui,
        "Static-light table",
        human_bytes_u64(budget.static_light_table_bytes as u64),
        false,
    );
    draw_budget_row(
        ui,
        "Room asset total",
        format!(
            "{} / {}",
            human_bytes_u64(budget.psxw_static_lit_bytes as u64),
            human_bytes_u64(MAX_ROOM_BYTES as u64)
        ),
        budget.static_lit_over_budget(),
    );
    draw_budget_row(
        ui,
        ".psxw compact est.",
        human_bytes_u64(budget.future_compact_estimated_bytes as u64).to_string(),
        budget.future_compact_estimated_bytes > MAX_ROOM_BYTES,
    );
}

/// Per-cell inspector for one sector inside the active Room.
///
/// Renders a CollapsingHeader with floor/ceiling toggles, a single
/// flat height per face (corner authoring lands later), a material

/// dropdown for each face, and a row of toggles for the four
/// cardinal walls. Returns `true` if any field changed so the
/// workspace can mark the project dirty in one place.
fn draw_sector_inspector(
    ui: &mut egui::Ui,
    project: &mut ProjectDocument,
    room_id: NodeId,
    sx: u16,
    sz: u16,
    material_options: &[(ResourceId, String)],
    nav_target: &mut Option<ResourceId>,
) -> bool {
    let scene = project.active_scene_mut();
    let Some(room) = scene.node_mut(room_id) else {
        return false;
    };
    let NodeKind::Room { grid } = &mut room.kind else {
        return false;
    };
    if sx >= grid.width || sz >= grid.depth {
        return false;
    }
    let sector_size = grid.sector_size;
    let mut changed = false;

    egui::CollapsingHeader::new(icons::label(icons::GRID, "Sector"))
        .default_open(true)
        .show(ui, |ui| {
            ui.horizontal(|ui| {
                ui.label("Cell");
                ui.monospace(format!("{sx}, {sz}"));
            });

            let sector = grid.ensure_sector(sx, sz);
            let Some(sector) = sector else {
                ui.weak("Cell out of grid bounds");
                return;
            };

            // Floor row: enabled toggle + height + material picker.
            ui.horizontal(|ui| {
                let mut has_floor = sector.floor.is_some();
                if ui.checkbox(&mut has_floor, "Floor").changed() {
                    sector.floor = if has_floor {
                        Some(GridHorizontalFace::flat(0, None))
                    } else {
                        None
                    };
                    changed = true;
                }
            });
            if let Some(floor) = sector.floor.as_mut() {
                changed |= height_row("    Height", &mut floor.heights, ui);
                changed |= split_row("    Split", &mut floor.split, ui);
                changed |= material_picker(
                    ui,
                    "    Material",
                    &mut floor.material,
                    material_options,
                    nav_target,
                );
            }

            ui.separator();

            // Ceiling row.
            ui.horizontal(|ui| {
                let mut has_ceiling = sector.ceiling.is_some();
                if ui.checkbox(&mut has_ceiling, "Ceiling").changed() {
                    sector.ceiling = if has_ceiling {
                        Some(GridHorizontalFace::flat(sector_size, None))
                    } else {
                        None
                    };
                    changed = true;
                }
            });
            if let Some(ceiling) = sector.ceiling.as_mut() {
                changed |= height_row("    Height", &mut ceiling.heights, ui);
                changed |= split_row("    Split", &mut ceiling.split, ui);
                changed |= material_picker(
                    ui,
                    "    Material",
                    &mut ceiling.material,
                    material_options,
                    nav_target,
                );
            }

            ui.separator();
            ui.label(icons::label(icons::BRICK_WALL, "Walls"));
            for (label, dir) in [
                ("North", GridDirection::North),
                ("East", GridDirection::East),
                ("South", GridDirection::South),
                ("West", GridDirection::West),
                ("NW-SE", GridDirection::NorthWestSouthEast),
                ("NE-SW", GridDirection::NorthEastSouthWest),
            ] {
                changed |= wall_stack_row(
                    label,
                    sector.walls.get_mut(dir),
                    sector_size,
                    material_options,
                    nav_target,
                    ui,
                );
            }
        });

    changed
}

/// Stack-of-walls editor for a single sector edge (N/E/S/W).
///
/// PSX rooms commonly stack walls to model windows / arches: one
/// wall from `0..window_bottom`, another from `window_top..ceiling`.
/// The data model already allows N walls per edge -- this UI surfaces
/// it. Each wall row carries its own `[bottom, top]` and material;
/// `+` adds a new wall on top of the previous one (or `0..ceil` for
/// the first), `×` removes that row.
fn wall_stack_row(
    edge_label: &str,
    walls: &mut Vec<GridVerticalFace>,
    sector_size: i32,
    material_options: &[(ResourceId, String)],
    nav_target: &mut Option<ResourceId>,
    ui: &mut egui::Ui,
) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(edge_label);
        if ui
            .small_button("+")
            .on_hover_text("Add wall stack")
            .clicked()
        {
            // New wall sits above the highest existing wall, or
            // spans the full sector when this edge is empty.
            let bottom = walls
                .iter()
                .map(|w| w.heights[2].max(w.heights[3]))
                .max()
                .unwrap_or(0);
            let top = (bottom + sector_size).max(bottom + 1);
            walls.push(GridVerticalFace::flat(bottom, top, None));
            changed = true;
        }
    });
    let mut remove_at: Option<usize> = None;
    for (i, wall) in walls.iter_mut().enumerate() {
        ui.horizontal(|ui| {
            ui.label(format!("    #{i}"));
            ui.label("bot");
            // bottom height = heights[0] = heights[1]; top = heights[2] = heights[3].
            let mut bot = wall.heights[0];
            let mut top = wall.heights[2];
            if ui
                .add(egui::DragValue::new(&mut bot).speed(HEIGHT_QUANTUM as f32))
                .changed()
            {
                let bot = snap_height(bot);
                wall.heights[0] = bot;
                wall.heights[1] = bot;
                changed = true;
            }
            ui.label("top");
            if ui
                .add(egui::DragValue::new(&mut top).speed(HEIGHT_QUANTUM as f32))
                .changed()
            {
                let top = snap_height(top);
                wall.heights[2] = top;
                wall.heights[3] = top;
                changed = true;
            }
            if ui.small_button("×").on_hover_text("Remove wall").clicked() {
                remove_at = Some(i);
            }
        });
        let pick_label = format!("    #{i} mat");
        changed |= material_picker(
            ui,
            &pick_label,
            &mut wall.material,
            material_options,
            nav_target,
        );
    }
    if let Some(i) = remove_at {
        walls.remove(i);
        changed = true;
    }
    changed
}

fn uv_transform_controls(uv: &mut GridUvTransform, ui: &mut egui::Ui) -> bool {
    let before = *uv;

    ui.horizontal(|ui| {
        ui.label("Offset");
        ui.label("U");
        ui.add(egui::DragValue::new(&mut uv.offset[0]).speed(1.0));
        ui.label("V");
        ui.add(egui::DragValue::new(&mut uv.offset[1]).speed(1.0));
    });

    ui.horizontal(|ui| {
        ui.label("Span");
        ui.label("U");
        ui.add(
            egui::DragValue::new(&mut uv.span[0])
                .speed(1.0)
                .range(0..=255),
        )
        .on_hover_text("0 uses the material's native U span.");
        ui.label("V");
        ui.add(
            egui::DragValue::new(&mut uv.span[1])
                .speed(1.0)
                .range(0..=255),
        )
        .on_hover_text("0 uses the material's native V span.");
    });

    ui.horizontal(|ui| {
        ui.label("Rotate");
        ui.selectable_value(&mut uv.rotation, GridUvRotation::Deg0, "0");
        ui.selectable_value(&mut uv.rotation, GridUvRotation::Deg90, "90");
        ui.selectable_value(&mut uv.rotation, GridUvRotation::Deg180, "180");
        ui.selectable_value(&mut uv.rotation, GridUvRotation::Deg270, "270");
    });

    ui.horizontal(|ui| {
        ui.checkbox(&mut uv.flip_u, "Flip U");
        ui.checkbox(&mut uv.flip_v, "Flip V");
        if ui
            .small_button("Reset")
            .on_hover_text("Reset this face's UV offset, span, rotation, and flips.")
            .clicked()
        {
            *uv = GridUvTransform::IDENTITY;
        }
    });

    *uv != before
}

/// Editable row for a `[NW, NE, SE, SW]` corner-height array.
///
/// Renders one DragValue when the four corners agree (the common
/// "flat floor" case) and switches to a 2×2 grid of independent
/// DragValues -- laid out NW-NE / SW-SE so the on-screen position
/// matches the world-space corner -- once the heights diverge or
/// the user clicks the "Slope" toggle. Returns `true` whenever any
/// corner changed so the caller can mark the project dirty.
fn height_row(label: &str, heights: &mut [i32; 4], ui: &mut egui::Ui) -> bool {
    let mut changed = false;
    let mut sloped =
        !(heights[0] == heights[1] && heights[1] == heights[2] && heights[2] == heights[3]);

    ui.horizontal(|ui| {
        ui.label(label);
        if ui
            .toggle_value(&mut sloped, "Slope")
            .on_hover_text("Edit each corner height independently.")
            .changed()
            && !sloped
        {
            // Collapse back to the NW value so the floor is flat
            // again -- predictable, matches how `flat()` builds.
            heights[1] = heights[0];
            heights[2] = heights[0];
            heights[3] = heights[0];
            changed = true;
        }
    });

    // DragValue speed must equal HEIGHT_QUANTUM so each "tick" of
    // mouse drag advances by one snap step. Combined with the
    // `snap_height` post-clamp, the value visibly walks
    // 0 → 64 → 128 → … without intermediate noise.
    if sloped {
        // 2×2 grid: NW NE on top row (z+), SW SE on bottom (z−).
        // The order in `heights` is [NW, NE, SE, SW] -- index map:
        //   top row: [0]=NW, [1]=NE
        //   bottom:  [3]=SW, [2]=SE
        egui::Grid::new(format!("{label}-corners"))
            .num_columns(2)
            .spacing([8.0, 4.0])
            .show(ui, |ui| {
                for &idx in &[0usize, 1, 3, 2] {
                    if ui
                        .add(egui::DragValue::new(&mut heights[idx]).speed(HEIGHT_QUANTUM as f32))
                        .changed()
                    {
                        heights[idx] = snap_height(heights[idx]);
                        changed = true;
                    }
                    if idx == 1 {
                        ui.end_row();
                    }
                }
                ui.end_row();
            });
    } else {
        ui.horizontal(|ui| {
            // Indent so the field aligns with the per-corner grid above.
            ui.label("    ");
            let mut h = heights[0];
            if ui
                .add(egui::DragValue::new(&mut h).speed(HEIGHT_QUANTUM as f32))
                .changed()
            {
                let snapped = snap_height(h);
                *heights = [snapped; 4];
                changed = true;
            }
        });
    }

    changed
}

fn split_row(label: &str, split: &mut GridSplit, ui: &mut egui::Ui) -> bool {
    let before = *split;
    ui.horizontal(|ui| {
        ui.label(label);
        ui.selectable_value(split, GridSplit::NorthWestSouthEast, "NW-SE");
        ui.selectable_value(split, GridSplit::NorthEastSouthWest, "NE-SW");
    });
    *split != before
}

/// Material picker used by the sector / face inspector.
///
/// `jump_to` is an out-param: clicking the `→` button writes
/// the selected material's resource id into it. The caller
/// applies the navigation after its borrows release. Returns
/// `true` if the picker changed `current`.
fn material_picker(
    ui: &mut egui::Ui,
    label: &str,
    current: &mut Option<ResourceId>,
    options: &[(ResourceId, String)],
    jump_to: &mut Option<ResourceId>,
) -> bool {
    let mut changed = false;
    ui.horizontal(|ui| {
        ui.label(label);
        let preview = current
            .and_then(|id| {
                options
                    .iter()
                    .find(|(rid, _)| *rid == id)
                    .map(|(_, n)| n.as_str())
            })
            .unwrap_or("(none)");
        egui::ComboBox::from_id_salt(label.to_string())
            .selected_text(preview)
            .show_ui(ui, |ui| {
                if ui.selectable_label(current.is_none(), "(none)").clicked() {
                    *current = None;
                    changed = true;
                }
                for (id, name) in options {
                    if ui.selectable_label(*current == Some(*id), name).clicked() {
                        *current = Some(*id);
                        changed = true;
                    }
                }
            });
        if let Some(id) = *current {
            if ui
                .small_button("→")
                .on_hover_text("Open this material in the inspector")
                .clicked()
            {
                *jump_to = Some(id);
            }
        }
    });
    changed
}

fn material_option_label(material: Option<ResourceId>, options: &[(ResourceId, String)]) -> String {
    material
        .and_then(|id| {
            options
                .iter()
                .find(|(rid, _)| *rid == id)
                .map(|(_, name)| name.clone())
        })
        .unwrap_or_else(|| "(none)".to_string())
}

